interface ImageObj {
  base64: string,
  widthPx: number,
  heightPx: number
}

async function urlToBase64(url: string): Promise<string> {
  const res = await fetch(url, { mode: 'cors' });
  if (!res.ok) throw new Error(`Failed to fetch image: ${res.status} ${res.statusText}`);

  const blob = await res.blob();

  return await new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const dataUrl = reader.result as string;
      resolve(dataUrl);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
}

async function loadLogo(company_logo: any) {
  if (company_logo.png_data) {
    return loadImageBase64(company_logo.png_data);
  }
  return fetchImageDimensionsAndBase64(company_logo.thumbnailUrl);
}

async function loadImageBase64(base64Str:string) {
  const base64Data = `data:image/png;base64,${base64Str}`;
  const img = new Image();
  await new Promise((resolve) => {
    img.onload = resolve;
    img.src = base64Data;
  });

  return {
    base64: base64Data,
    widthPx: img.width,
    heightPx: img.height,
  };
}

async function fetchImageDimensionsAndBase64(url: string) {
  if (!url) {
    return null;
  }

  const response = await fetch(url);
  if (!response.ok) {
    throw new Error(`Failed to fetch image: ${response.statusText}`);
  }

  const blob = await response.blob();
  const base64Data = await new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      if (typeof reader.result === 'string') {
        resolve(reader.result);
      } else {
        reject(new Error('Failed to read blob as data URL'));
      }
    };
    reader.onerror = () => reject(reader.error);
    reader.readAsDataURL(blob);
  });

  const img = new Image();
  await new Promise((resolve) => {
    img.onload = resolve;
    img.src = base64Data;
  });

  return {
    base64: base64Data,
    widthPx: img.width,
    heightPx: img.height,
  };
}

async function html2Img(eleId:string) {
  const node = document.getElementById(eleId);
  if (!node) return;
  const base64Data = await toPng(node, {
    pixelRatio: 2,
    cacheBust: true,
  });

  const img = new Image();
  await new Promise((resolve) => {
    img.onload = resolve;
    // img.onerror = () => reject(new Error("Image failed to load"));
    img.onerror = resolve;
    img.src = base64Data;
  });

  return {
    base64: base64Data,
    widthPx: img.width,
    heightPx: img.height,
  };
}

async function genPage(pptx: PptxGenJS, reportData: PotentialDetailResponse, type: number, settingContext: any, idx?: number) {
  function showText(title: string,text: string, references: Reference[]){
    if (typeof text === 'string' && text.includes("【") && text.includes("】")) {
      let cList: string[] = [];
      let textList = text.split(/【/);
      let result = textList.map((item, index) => {
        if (index > 0 && item.includes("】")) {
          let itemList = item.split(/】/);
          let citation = itemList[0];
          let shiftedItem = itemList.slice(1);
          let otherText = shiftedItem ? shiftedItem.join("】") : "";
          cList.push(citation);
          return otherText;
        } else if (index > 0) {
          return "【" + item;
        } else{
          return item;
        }
      });
      references.push({title: title, list: cList});
      return result.join('');
    }
    return text;
  }

