  async function addPhotoPage(pData: PotentialDetailResponse) {
    const slide5 = pptx.addSlide();

    slide5.addShape(pptx.ShapeType.rect, { x:4.6601, y:5.0065, w:8.2451, h:2.0777, fill: { color: '404040' } });
    slide5.addText([{ text: 'Store Photos', options: { fontSize: 40.0, color: 'FFFFFF', align: 'left', fontFace: '+mj-lt' } }], { x:5.0344, y:5.1859, w:7.4689, h:0.9427, shape: pptx.ShapeType.rect, fill: { color: 'FFFFFF', transparency: 100 } });

    const company_images = pData.company_profile?.company_images || [];

    // Helper to add an image while preserving aspect ratio inside a fixed box
    const addImageInBox = async (imgObj: { data: string; thumbnailUrl: string; webSearchUrl: string; }, x: number, y: number, boxW: number, boxH: number) => {
      if (!imgObj.thumbnailUrl) return;
      try {
        const imgData = imgObj.data? await loadImageBase64(imgObj.data) : await fetchImageDimensionsAndBase64(imgObj.thumbnailUrl);
        if (!imgData) return;

        const AR = imgData.widthPx / imgData.heightPx;
        let w = boxW;
        let h = w / AR;
        if (h > boxH) {
          h = boxH;
          w = h * AR;
        }

        const offsetX = x + (boxW - w) / 2;
        const offsetY = y + (boxH - h) / 2;

        slide5.addImage({ data: imgData.base64, x: offsetX, y: offsetY, w, h });
      } catch (error) {
        console.error('Error fetching or processing image:', error);
      }
    };

    if (company_images.length > 0) {
      if (settingContext.appEnv == "uat") {
        await addImageInBox(company_images[0], 0.3474, 0.3519, 4.1531, 2.1988);
      } else {
        let image1 = await urlToBase64(pData.company_profile?.company_images[0].thumbnailUrl);
        slide5.addImage({ data: image1, x: 0.3474, y: 0.3519, w: 4.1531, h: 2.1988, sizing: { type: 'crop', w: 4.1531, h: 2.1988 } });
      }
