DropdownInput = ({ options, value, style = "", editStyle = "", onSelected }: {
  options: string[],
  value: string,
  style?: string,
  editStyle?: string,
  onSelected: (value: string) => void
}) => {
  const [isOpened, setIsOpened] = useState(false);
  const [seletedValue, setSelectedValue] = useState(value);

  let items: MenuProps['items'] = [];
  options.map((item) => {
    if (items) {
      items.push({
        key: item,
        label: item,
      });
    }
  });

  return (
    <>
      <Dropdown menu={{
        items,
        selectable: true,
        defaultSelectedKeys: [seletedValue],
        onSelect: ({ key }) => {
          setSelectedValue(key);
          onSelected(key);
        },
      }} trigger={['click']} onOpenChange={(open) => setIsOpened(open)}>
        <div className={"px-2 " + (isOpened ? style : editStyle)} onClick={(e) => { e.preventDefault() }}>
          <p className="w-[calc(100%-24px)] inline-block text-center">{seletedValue}</p>
          <img src={icon_arrowdown} alt="arrowdown icon" className={"h-[24px] inline-block" + (isOpened ? " rotate-180" : "")} />
        </div>
      </Dropdown>
    </>
  );
}

