interface Props extends React.HTMLAttributes<HTMLInputElement> {
  placeholder: string;
  prefix: "user" | "lock";
  name: string;
  containerClassName?: string;
  rules?: RegisterOptions;
}

CommonInput = ({
  placeholder,
  prefix,
  name,
  containerClassName,
  className,
  rules,
  ...inputProps
}: PropsWithChildren<Props>) => {
  const { control } = useFormContext();
  const {
    field: { onChange, value },
    fieldState: { error },
  } = useController({ name, control, rules });

  const InputPrefix = useMemo(() => {
    switch (prefix) {
      case "user": {
        return <IconProfile width={24} height={24} />;
      }
      case "lock": {
        return <IconPassword width={24} height={24} />;
      }
      default:
        return null;
    }
  }, [prefix]);

  const onChangeValue = (e: ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    onChange(value);
  };

  return (
    <div className={cn("w-full h-12", containerClassName)}>
      <Input
        placeholder={placeholder}
        prefix={InputPrefix}
        onChange={onChangeValue}
        value={value}
        className={cn("common-input border-b", className)}
        {...inputProps}
      />
      {error && <Text type={"danger"}>{error.message}</Text>}
    </div>
  );
}

