frontend/src/components/progress-bar/ind.source_code:
interface Props {
  className?: string;
  defaultWidth?: number;
  isFinished: boolean;
  maxDuration?: number;
}

ProgressBar = ({
  className,
  defaultWidth = 360,
  isFinished,
  maxDuration = 120,
}: Props) => {
  const barRef = useRef<HTMLDivElement | null>(null);

  const step = Math.floor((defaultWidth * 0.8) / maxDuration);
  const endProgressingStep = defaultWidth * 0.8;
  const [progressingWidth, setProgressingWidth] = useState(0);

  useEffect(() => {
    let timer: ReturnType<typeof setTimeout>;
    if (isFinished) {
      setProgressingWidth(progressingWidth + (defaultWidth - progressingWidth));
    } else if (progressingWidth < endProgressingStep) {
      const randomStep = Math.floor(Math.random() * (step * 2 - step) + step);
      const defaultDelay = Math.floor(Math.random() * 2);

      timer = setTimeout(() => {
        setProgressingWidth(progressingWidth + randomStep);
      }, defaultDelay * 1000);
    }

    return () => {
      clearTimeout(timer);
    };
  }, [defaultWidth, endProgressingStep, isFinished, progressingWidth, step]);

  return (
    <div
      ref={barRef}
      className={cn("h-2 relative overflow-hidden", className)}
      style={{ width: defaultWidth }}
    >
      <div
        className="absolute top-0 left-0 bg-accent-blue h-full transition-all delay-300"
        style={{ width: progressingWidth }}
      />
    </div>
  );
}

frontend/src/components/provider/Setting.source_code:
interface SettingContextType {
  userProfile: UserInfo | null;
  userData: any;
  appEnv: string;
  loading: boolean;
  allowPage: (pageName: string) => boolean;
  hasPermission: (pageName: string, permissionName: string) => boolean;
  hasEditPermission: (pageName: string) => boolean;
  getFilter: (pageName: string) => any;
  updateFilter: (pageName: string, filterData: any) => void;
}

SettingProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [userProfile, setUserProfile] = useState<UserInfo | null>(null);
  const [userData, setUserData] = useState<PermissionResponse>();
  const [filterData, setFilterData] = useState<filterRecord[]>([]);
  const [appEnv, setAppEnv] = useState<string>("prd");

  const initialized = useRef(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!initialized.current) {
      const loadUserProfile = async () => {
        const response = await axiosInstance(ENDPOINT.getAuthorized);
        const accessToken = response.data[0].id_token;
        const userProfile: JwtPayload & UserInfo = jwtDecode(accessToken);
        setUserProfile({
          name: userProfile.name,
          email: userProfile.email,
        });
      }
      const fetchPermissions = async () => {
        try {
          const response = await CreditService.getPermission();
          setUserData(response.data.data);
          setFilterData(response.data.data?.filters || []);
          setAppEnv(response.data.data?.app_env || "prd");
        } catch (error) {
          console.error('Error fetching permissions:', error);
        }
      };
      loadUserProfile();
      fetchPermissions();
      initialized.current = true;
    }
  }, []);

  useEffect(() => {
    if(loading && userData != undefined){
      setLoading(false);
    }
  }, [userData]);

  const allowPage = (pageName: string) => {
    if (!userData) return true;
    return userData?.permissions?.allowed_pages.includes(pageName) || false;
  };

  const hasPermission = (pageName: string, permissionName: string) => {
    if (!userData || userData?.permissions?.actions_map[pageName] == undefined) return true;
    return userData?.permissions?.actions_map[pageName].includes(permissionName) || false;
  };

  const hasEditPermission = (pageName: string) => {
    if (userData && userData.permissions.actions_map[pageName]) {
      if (pageName === "existing_detail") {
        let editPermissions = ["edit_final_memo", "edit_factsheet", "edit_risk_category", "edit_cm_page", "edit_company_profile"];
        return editPermissions.some(permission => userData.permissions.actions_map[pageName].includes(permission));
      } else if (pageName === "potential_detail") {
        let editPermissions = ["edit_final_memo", "edit_factsheet", "edit_risk_category", "edit_cm_page", "edit_company_profile"];
        return editPermissions.some(permission => userData.permissions.actions_map[pageName].includes(permission));
      }
    }
    return false;
  };

  const getFilter = (pageName: string) => {
    if (userData) {
      let filterItem = filterData?.filter(i => i.name == pageName);
      return filterItem.length > 0 ? filterItem[0].params : {};
    }
    return {};
  };

  const updateFilter = (pageName: string, newFilterData: any) => {
    let updated = false;
    let newData = filterData?.map(item => {
      if (item.name == pageName) {
        updated = true;
        return { ...item, params: newFilterData };
      }
      return item;
    });
    if (!updated) {
      newData = [...(newData || []), { name: pageName, params: newFilterData }];
    }
    setFilterData(newData || []);
  };

  return (
    <SettingContext.Provider value={{ userProfile, userData, appEnv, loading, allowPage, hasPermission, hasEditPermission, getFilter, updateFilter }}>
      {children}
    </SettingContext.Provider>
  );
}

