interface TagNameProps {
  classname?: string;
  date: string;
}

TagName = ({ classname, date }: TagNameProps) => {
  const nextDate = moment(new Date(date)).startOf('day');
  const nextDate2 = moment(new Date(date)).startOf('day');
  const now = moment(new Date()).startOf('day');
  const timeDiff = now.diff(nextDate);

  const years = now.diff(nextDate2, 'year');
  nextDate2.add(years, 'years');

  const months = now.diff(nextDate2, 'months');
  nextDate2.add(months, 'months');

  const days = now.diff(nextDate2, 'days');

  let style = "";
  let text = "";
  if (timeDiff > 0) {
    style = classStyles["overdue"];
    text = "Overdue ";
    if (years != 0) {
      text += years + " years";
    }
    if (months != 0) {
      text += (years != 0 ? " and " : "") + months + " months";
    }
    if (days != 0) {
      text += (years != 0 || months != 0 ? " and " : "") + days + " days";
    }
  } else if (now.diff(nextDate, 'days') >= -61) {
    style = classStyles["expiring"];
    if (now.diff(nextDate, 'days') == 0) {
      text = "Due today";
    } else {
      text = "Expiring in ";
      if (months != 0) {
        text += (months * -1) + " months";
      }
      if (days != 0) {
        text += (months != 0 ? " and " : "") + (days * -1) + " days";
      }
    }
  } else {
    style = classStyles["valid"];
    text = "Valid";
  }

  return (
    <div
      className={cn(
        "w-fit px-3 py-1 text-sm",
        style,
        classname
      )}
    >
      {text}
    </div>
  );
}

