function useDisclosure({
  isOpen,
  onOpen: handleOpen,
  onClose: handleClose,
}: Props) {
  const [isVisible, setIsVisible] = useState(isOpen || false);

  return useMemo(
    () => ({
      isOpen: isVisible,
      onClose: () => {
        setIsVisible(false);
        handleClose?.();
      },
      onOpen: () => {
        setIsVisible(true);
        handleOpen?.();
      },
    }),
    [handleClose, handleOpen, isVisible]
  );
}

