frontend/src/templates/privateTemplate.t.source_code:
interface Props {
  showNavbar?: boolean;
  className?: string;
  childClassName?: string;
}

PrivateTemplate = ({
  className,
  childClassName,
  showNavbar = true,
  children,
}: PropsWithChildren<Props>) => {
  const settingContext = useContext(SettingContext);

  const onLogout = () => {
    Promise.all([
      axiosInstance(ENDPOINT.msLogout),
      axiosInstance(ENDPOINT.appLogout),
    ]);
    window.location.reload();
  };

  return (
    <div
      className={cn("relative w-full h-auto min-h-[100vh] table", className)}
      style={{ backgroundImage: `url(${Background})` }}
    >
      {/* navbar */}
      {showNavbar && <Navbar userProfile={settingContext?.userProfile || null} onLogout={onLogout} />}
      {/* body */}
      <div className={cn("max-w-full h-full", childClassName)}>{children}</div>
    </div>
  );
}

