class ChatModel:
    def __init__(self, config: LLMConfig):
        #self.llm = self.init_gemini(model="gemini-1.5-flash-001", temperature=0, max_tokens=8192, max_retries=0)
        self.config = config
        self.llm = self.init_llm()

    def init_llm(self):
        model = self.config.model

        if "gemini" in model:
            temperature = self.config.temperature
            max_tokens = self.config.max_tokens
            max_retries = self.config.max_retries
            response_mime_type = self.config.response_mime_type
            llm = self.init_gemini(model, temperature, max_tokens, max_retries, response_mime_type)

        return llm

    def init_gemini(self, model="gemini-2.0-flash-exp", temperature=0, max_tokens=8192, max_retries=5, response_mime_type=None):

        safety_settings = {
            HarmCategory.HARM_CATEGORY_HARASSMENT: HarmBlockThreshold.BLOCK_NONE,
            HarmCategory.HARM_CATEGORY_HATE_SPEECH: HarmBlockThreshold.BLOCK_NONE,
            HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT: HarmBlockThreshold.BLOCK_NONE,
            HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT: HarmBlockThreshold.BLOCK_NONE,
        }

        llm = ChatGoogleGenerativeAI(
            model=model,
            temperature=temperature,
            max_tokens=max_tokens,
            max_retries=max_retries,
            stop=None,
            location='global',
            safety_settings=safety_settings,
            response_mime_type=response_mime_type,
            vertexai=True,
            # other params...
        )

        return llm

    def create_media_message(self, file_path):
        filetype = ''
        file_ext =  file_path.split('.')[-1].lower()

        if file_ext=='pdf':
            filetype = 'pdf'
        elif file_ext=='jpg' or file_ext=='jpeg':
            filetype = 'jpeg'

        if not filetype:
            raise ValueError(f'unsupported file extension: {file_ext}')

        with open(file_path, "rb") as f:
            media_bytes = f.read()

        media_message = {
            "type": "image_url",  # Assuming the LLM accepts PDF under this key, you might need to verify this
            "image_url": {
                "url": f"data:application/{filetype};base64,{base64.b64encode(media_bytes).decode('utf-8')}"
            },
        }

        return media_message

