def google_image_search(input_text, result_num=20):
    result = []

    def search_function():
        nonlocal result
        try:
            result_num_capped = min((result_num, 20))

            search_url = f"https://www.google.com/search?q={input_text}&client=firefox-b-1-d&sxsrf=AOaemvLwoKYN8RyvBYe-XTRPazSsDAiQuQ:1641698866084&source=lnms&tbm=isch&sa=X&ved=2ahUKEwiLp_bt3KP1AhWHdt8KHZR9C-UQ_AUoAXoECAIQAw&biw=1536&bih=711&dpr=1.25"
            r = requests.get(search_url, timeout=10)
            soup = BeautifulSoup(r.text, 'html.parser')
            image_tags = soup.findAll('img')[1:1+result_num_capped]

            tables = soup.findAll('table')[3:3+result_num_capped]
            website_urls = []
            for table in tables:
                url = ''
                a = table.find('a')
                if a :
                    url = a.get('href', '')
                url = url.split('/url?q=')[-1]
                url = url.split('&')[0]
                website_urls.append(url)

            images = []
            for n, img in enumerate(image_tags):
                if img.has_attr('src'):
                    image_url = img['src']
                    if image_url.startswith('http'):
                        images.append({
                            'thumbnailUrl': image_url,
                            'webSearchUrl': website_urls[n],
                        })
            result = images
        except Exception as e:
            print(f"google_image_search error: {e}")
            result = []

    thread = threading.Thread(target=search_function)
    thread.start()
    thread.join(timeout=10)  # Wait for 10 seconds

    if thread.is_alive():
        print("google_image_search timed out after 10 seconds.")
        # In this scenario, we can't directly "kill" the thread,
        # but we can effectively abandon its result.
        return []
    else:
        return result

