class BDAI(CreditAI):
    def __init__(self, prompt_directory):
        self.prompt_directory = Path(prompt_directory)
        self.bd_prompts = load_json(self.prompt_directory/'bd_prompts.json')

        if not self.prompt_directory.exists():
            raise Exception("prompt_directory does not exist")

    def _format_dashboard_data(self, factsheet)->list:
        def sort_fy(date_list, n_last_year=None):
            datetime_objects = [datetime.strptime(date_str, '%d-%b-%y') for date_str in date_list]
            datetime_objects.sort(reverse=False)
            sorted_date_strings = [date_obj.strftime('%d-%b-%y') for date_obj in datetime_objects]

            if n_last_year:
                return sorted_date_strings[-n_last_year:]
            else:
                return sorted_date_strings

        def parse_field_value(field_value):
            if isinstance(field_value, (int, float)):
                return float(field_value)

            if not isinstance(field_value, str):
                return None

            field_value = field_value.strip()

            if field_value == '-' or field_value.lower() == 'na':
                return None

            if field_value.endswith('%'):
                try:
                    return float(field_value[:-1])
                except ValueError:
                    return None
            elif field_value.startswith('(') and field_value.endswith(')'):
                try:
                    return -float(field_value[1:-1])
                except ValueError:
                    return None
            else:
                try:
                    return float(field_value)
                except ValueError:
                    return None


        annual = factsheet.get('annual', {})
        annual_data = annual.get('data', {})
        fy_list = annual.get('period', [])

        if not fy_list or not annual_data:
            return []

        try:
            fy_list = sort_fy(fy_list, n_last_year=3)
        except:
            print("error during sorting fy list")
            return []

        dashboard_data = []

        for fy in fy_list:
            year = datetime.strptime(fy, "%d-%b-%y").year
            year = f"FY{year}"

            d = annual_data.get(fy, {})

            formatted_data = {"Year": year}
            formatted_data['Cash'] = parse_field_value(d.get('Cash', None))
            formatted_data['FCF'] = parse_field_value(d.get('Free cash flow', None))
            formatted_data['Revenue'] = parse_field_value(d.get('Turnover', None))
            formatted_data['GP %'] = parse_field_value(d.get('Gross Profit %', None))
            formatted_data['EBITDA %'] = parse_field_value(d.get('EBITDA Margin %', None))
            formatted_data['Net Profit %'] = parse_field_value(d.get('PAT Margin', None))
            formatted_data['Equity'] = parse_field_value(d.get('Net Worth', None))
            formatted_data['Inventory Days'] = parse_field_value(d.get('Inventories Days', None))
            formatted_data['Payable Days'] = parse_field_value(d.get('Trade Payables Days', None))
            formatted_data['Receivables Days'] = parse_field_value(d.get('Trade Receivables days', None))

            dashboard_data.append(formatted_data)

        return dashboard_data

    def _initialize_company_profile(self, report_id)->CompanyProfile:

        with get_db() as session:
            query = text("""SELECT 
                        -- xdata,
                        factsheet,
                        risk_rating,
                        company_name, 
                        parent_customer_id
                    FROM public.credit_report 
                    where id = :report_id;
        """)
            result_proxy = session.execute(query, {'report_id': report_id})

            Report = namedtuple('Report', result_proxy.keys())
            reports = [Report(*row) for row in result_proxy.fetchall()]

        risk_rating = reports[0].risk_rating
        factsheet = reports[0].factsheet
        company_profile = {}
        snp_rating='N/A'
        snp_outlook=''
        revenue='N/A'
        dashboard_data = []
        with_financials = False

        if risk_rating:
            snp_rating = risk_rating.get('external_ratings', {}).get('s&p', '')
            snp_outlook = risk_rating.get('outlook', {}).get('s&p', '')
            if snp_rating and snp_outlook:
                snp_rating+='/'+snp_outlook

            revenue = risk_rating.get('financial_scores', {}).get('revenue_size', {}).get('value', '')
            try:
                float(revenue)
            except:
                revenue = "N/A"

            if revenue != '0' and revenue != "N/A":
                revenue += ' M'
            else:
                revenue = "N/A"

            with_financials = has_financial_scores(risk_rating)

        if type(factsheet)==dict and with_financials:
            dashboard_data = self._format_dashboard_data(factsheet)

        company_profile['snp_rating'] = snp_rating
        company_profile['revenue'] = revenue
        company_profile['company_name'] = reports[0].company_name
        company_profile['dashboard_data'] = dashboard_data

        return CompanyProfile(**company_profile)

    def _search_company_information(self, company_name, executor=None)->dict:
        info_str = ''
        info_futures = []
        info_list = []

        own_executor = False
        if executor is None:
            executor = ThreadPoolExecutor(max_workers=7)
            own_executor = True

        try:
            info_futures.append(executor.submit(self.user_query_rag_gemini_2_5, self.bd_prompts['website_mission'], company_name, None, None, None, True))
            info_futures.append(executor.submit(self.user_query_rag_gemini_2_5, self.bd_prompts['established_owner_ceo_head_office_buying_office'], company_name, None, None, None, True))
            info_futures.append(executor.submit(self.user_query_rag_gemini_2_5, self.bd_prompts['market_cap_company_type_no_of_employee'], company_name, None, None, None, True))
            info_futures.append(executor.submit(self.user_query_rag_gemini_2_5, self.bd_prompts['categories_private_brands_competitor'], company_name, None, None, None, True))
            info_futures.append(executor.submit(self.user_query_rag_gemini_2_5, self.bd_prompts['store_locations_no_of_store_size_of_store'], company_name, None, None, None, True))
            info_futures.append(executor.submit(self.user_query_rag_gemini_2_5, self.bd_prompts['no_of_distribution_center_products_suppliers_factories_annual_quantity'], company_name, None, None, None, True))

            for info_future in as_completed(info_futures):
                info_list.append(info_future.result())

        finally:
            if own_executor:
                executor.shutdown()

        for info in info_list:
            if info and type(info)==str:
                info_str += info 
            else:
                print(f"info type {type(info)}")

        #shorten the citation urls for better AI result
        modified_text, extracted_urls = replace_and_extract_brackets(info_str)

        other_information = {"Company Information": modified_text}
        info_json_str = self.user_query_rag_json_gemini_2_5(self.bd_prompts['company_info_formatting'], company_name, other_information=other_information, enable_search=False)
        short_info_json_str = self.user_query_rag_json_gemini_2_5(self.bd_prompts['company_info_formatting_short'], company_name, other_information=other_information, enable_search=False)

        #revert back the citation urls
        info_json_str = revert_text_from_brackets(info_json_str, extracted_urls)
        info_json = parse_llm_json_output(info_json_str)

        short_info_json_str = revert_text_from_brackets(short_info_json_str, extracted_urls)
        short_info_json = parse_llm_json_output(short_info_json_str)

        output = {"info":info_json, "short_info":short_info_json}

        return output

    def _generate_crm(self, company_name, executor=None):
        crm_str = ''
        crm_title  ={"crm_finance": "#Revenue and Merchandise Mix:\n",
                     "crm_management": "\n\n#Management:\n", 
                     "crm_competitive": "\n\n#Competitive Advantage:\n",
                     "crm_sourcing": "\n\n#Sourcing:\n"}
        crm_results = {}
        times = {}

        own_executor = False
        if executor is None:
            executor = ThreadPoolExecutor(max_workers=6)
            own_executor = True

        try:
            task_names = ["crm_finance", "crm_management", "crm_competitive", "crm_sourcing"]
            futures = {}

            # Record start times before submitting tasks
            for task in task_names:
                times[f"{task}_start"] = time.time()
                futures[executor.submit(self.user_query_rag_gemini_2_5, self.bd_prompts[task], company_name, None, None, None, True)] = task

            for future in as_completed(futures):
                task_name = futures[future]
                crm_results[task_name] = future.result()
                times[f"{task_name}_end"] = time.time() # Record end time after result is retrieved

        finally:
            if own_executor:
                executor.shutdown()

        durations = {}
        for key in crm_results.keys(): # Iterate through crm_results to ensure consistent keys
            start_key = key + "_start"
            end_key = key + "_end"
            if start_key in times and end_key in times:
                durations[key] = times[end_key] - times[start_key]

        for key, duration in durations.items():
            print(f"_generate_crm {key} took {duration:.4f} seconds")

        for k, ret in crm_results.items():
            if type(ret)==str:
                crm_str += crm_title[k] + ret
            else:
                print(f"crm type {type(ret)}")

        crm_str += "\n\n"
        #shorten the citation urls for better AI result
        modified_text, extracted_urls = replace_and_extract_brackets(crm_str)

        other_information = {"Company Information": modified_text}
        crm_json_str = self.user_query_rag_json_gemini_2_5(self.bd_prompts['crm_formatting'], company_name, other_information=other_information, enable_search=False)

        #revert back the citation urls
        crm_json_str = revert_text_from_brackets(crm_json_str, extracted_urls)
        crm_json = parse_llm_json_output(crm_json_str)

        crm = ''
        for k, v in crm_json.items():
            if v:
                crm += f"• {k}\n{v}\n\n"

        return crm

    def generate_company_profile(self, report_id, subsidiary_search=True, management_search=True):
        company_profile = self._initialize_company_profile(report_id)
        #entity_id = self._query_entity_id(report_id)

        search_options = {
            "subsidiary": subsidiary_search,
            "management": management_search
        }

        futures = {}
        # results = {} # No longer needed
        times = {}

        with ThreadPoolExecutor(max_workers=4) as executor:
            print("Start generate_company_profile")
            start = time.time()
            all_futures = []

            future_info = executor.submit(self._search_company_information, company_profile.company_name, executor)
            all_futures.append((future_info, "info"))
            times["info_start"] = time.time()

            future_crm = executor.submit(self._generate_crm, company_profile.company_name, executor)
            all_futures.append((future_crm, "crm"))
            times["crm_start"] = time.time()

            future_company_images = executor.submit(self._search_company_images, company_profile.company_name)
            all_futures.append((future_company_images, "company_images"))
            times["company_images_start"] = time.time()

            future_company_logo = executor.submit(self._search_company_logo, company_profile.company_name)
            all_futures.append((future_company_logo, "company_logo"))
            times["company_logoy_start"] = time.time()

            future_company_logo = executor.submit(self._search_company_logo_v2, company_profile.company_name)
            all_futures.append((future_company_logo, "company_logo_v2"))
            times["company_logo_v2_start"] = time.time()

            future_revenue_breakdown = executor.submit(self._search_revenue_breakdown, company_profile.company_name)
            all_futures.append((future_revenue_breakdown, "revenue_breakdown"))
            times["revenue_breakdown_start"] = time.time()

            future_social_media = executor.submit(self._search_social_media, company_profile.company_name)
            all_futures.append((future_social_media, "social_media"))
            times["social_media_start"] = time.time()

            future_info = executor.submit(self._generate_bankruptcy_history, company_profile.company_name)
            all_futures.append((future_info, "bankruptcy_history"))
            times["bankruptcy_history_start"] = time.time()

            if search_options["subsidiary"]:
                future_subsidiary = executor.submit(self._search_company_hierarchy, company_profile.company_name)
                all_futures.append((future_subsidiary, "subsidiary"))
                times["subsidiary_start"] = time.time()

            if search_options["management"]:
                future_management = executor.submit(self._search_company_management, company_profile.company_name)
                all_futures.append((future_management, "management"))
                times["management_start"] = time.time()

                future_contact = executor.submit(self._search_company_contact, company_profile.company_name)
                all_futures.append((future_contact, "contact"))
                times["contact_start"] = time.time()

            # Process results as they complete
            for future, key in all_futures:
                futures[key] = future

            results = {} # Initialize results dictionary before processing
            for future in as_completed([f for f, _ in all_futures]):
                for key, f in futures.items():
                    if f == future:
                        results[key] = future.result()
                        times[key + "_end"] = time.time()
                        break

        durations = {}
        for key in futures.keys():
            start_key = key + "_start"
            end_key = key + "_end"
            if start_key in times and end_key in times:
                durations[key] = times[end_key] - times[start_key]

        info_dict = results.get("info", {}).get("info", {})
        short_info_dict = results.get("info", {}).get("short_info", {})
        subsidiaries = results.get("subsidiary", {})
        management = results.get("management", {})
        linkedin = {}
        contact = results.get("contact", {})
        company_images = results.get("company_images", [])
        company_logo = results.get("company_logo", {})
        company_logo_v2 = results.get("company_logo_v2", {})
        crm = results.get("crm", {})
        revenue_breakdown = results.get("revenue_breakdown", {})
        social_media = results.get("social_media", {})
        bankruptcy_history = results.get("bankruptcy_history", {})

        # if management:
        #     official_list = list(management.keys())
        #     times["linkedin_profile_start"] = time.time()
        #     linkedin = self._search_linkedin_profile(company_profile.company_name, official_list)
        #     times["linkedin_profile_end"] = time.time()
        #     durations['linkedin'] = times['linkedin_profile_end'] - times['linkedin_profile_start']

        for key, duration in durations.items():
            print(f"{key} took {duration:.4f} seconds")

        for key, value in info_dict.items():
            if getattr(company_profile, key, None) is not None:
                setattr(company_profile, key, value)

        company_profile.crm = crm
        company_profile.subsidiaries = subsidiaries
        company_profile.management = management
        company_profile.contact = contact
        company_profile.linkedin = linkedin
        company_profile.company_images = company_images
        if company_logo_v2:
            company_profile.company_logo = company_logo_v2
        else:
            company_profile.company_logo = company_logo
        company_profile.revenue_breakdown = revenue_breakdown
        company_profile.social_media = social_media
        company_profile.shortened_info = short_info_dict
        company_profile.bankruptcy_history_list = bankruptcy_history

        return company_profile.model_dump()

