    def _generate_adjacency_list(self, company_id, company_name):
        adjacency_list = {}

        if not company_id:
            adjacency_list = self._search_company_hierarchy(company_name)
            return adjacency_list

        entities = self._query_company_hierarchy(company_id)
        entities = list(set(entities))

        if (entities):
            company_ids = set()

            for e in entities:
                company_ids.add(e.entity_id)
                company_ids.add(e.parent_company_id)
            company_ids = list(company_ids)
            if None in company_ids:
                company_ids.remove(None)

            company_id_name = self._query_company_name(company_ids)

            adjacency_list = defaultdict(list)
            all_companies = set()

            for entity in entities:
                parent_id = entity.parent_company_id
                entity_id = entity.entity_id

                if parent_id in company_id_name and entity_id in company_id_name:
                    parent_name = company_id_name[parent_id]
                    entity_name = company_id_name[entity_id]
                    adjacency_list[parent_name].append(entity_name)

                all_companies.add(parent_id)
                all_companies.add(entity_id)

            for company_id in all_companies:
                if company_id in company_id_name:
                    company_name = company_id_name[company_id]
                    if company_name not in adjacency_list:
                        adjacency_list[company_name] = []

            adjacency_list = dict(adjacency_list)
        else:
            company_id_name = self._query_company_name([company_id])
            adjacency_list = {company_id_name[company_id]: []}

        return adjacency_list

    def _query_entity_id(self, report_id):
        with get_db() as session:
            query = text("""
                Select entity_id 
                FROM public.credit_report
                WHERE id=:report_id
            """)

            result_proxy = session.execute(query, {'report_id': report_id})
            ret = [x for x in result_proxy.fetchall()]

            entity_id = ret[0][0] if ret else None

        return entity_id

    def _query_company_name(self, company_ids):
        with get_db() as session:
            query = text("""
                Select entity_id, entity_name
                FROM public.credit_entities
                WHERE entity_id IN ({})
            """.format(','.join([str(x) for x in company_ids])))

            result_proxy = session.execute(query)
            company_id_name = {x[0]:x[1] for x in result_proxy.fetchall()}

        return company_id_name

    def _query_company_hierarchy(self, company_id):
        with get_db() as session:
            query = text("""
                        WITH RECURSIVE

                        children AS (
                            SELECT entity_id, parent_company_id
                            FROM public.credit_entity_hierarchy
                            WHERE parent_company_id = :target_entity_id

                            UNION ALL

                            SELECT h.entity_id, h.parent_company_id
                            FROM public.credit_entity_hierarchy h
                            INNER JOIN children c ON h.parent_company_id = c.entity_id
                        ),

                        parents AS (
                            SELECT entity_id, parent_company_id
                            FROM public.credit_entity_hierarchy
                            WHERE entity_id = :target_entity_id

                            UNION ALL

                            SELECT h.entity_id, h.parent_company_id
                            FROM public.credit_entity_hierarchy h
                            INNER JOIN parents p ON h.entity_id = p.parent_company_id
                            WHERE h.parent_company_id IS NOT NULL
                        )

                        SELECT *
                        FROM children
                        UNION
                        SELECT *
                        FROM parents
            """)
            result_proxy = session.execute(query, {'target_entity_id': company_id})

            Entity = namedtuple('Entity', result_proxy.keys())
            entities = [Entity(*row) for row in result_proxy.fetchall()]

        return entities

