            future_revenue_3 = executor.submit(self.user_query_rag_gemini_2_5, self.bd_prompts['revenue_breakdown_3'], company_name, None, None, None, True)
            future_revenue_4 = executor.submit(self.user_query_rag_gemini_2_5, self.bd_prompts['revenue_breakdown_4'], company_name, None, None, None, True)
            future_revenue_5 = executor.submit(self.user_query_rag_gemini_2_5, self.bd_prompts['revenue_breakdown_5'], company_name, None, None, None, True)


            revenue_1 = future_revenue_1.result()
            revenue_2 = future_revenue_2.result()
            revenue_3 = future_revenue_3.result()
            revenue_4 = future_revenue_4.result()
            revenue_5 = future_revenue_5.result()

        #ret = self.user_query_rag(self.bd_prompts['revenue_breakdown'], company_name, enable_search=True)
        revenue_str = f"#Breakdown by Brands:\n{revenue_1}\n\n"
        revenue_str += f"#Breakdown by Geographic Location:\n{revenue_2}\n\n"
        revenue_str += f"#Breakdown by Product Segments:\n{revenue_3}\n\n"
        revenue_str += f"#Breakdown by Sales Channel:\n{revenue_4}\n\n"
        revenue_str += f"#Total Revenue:\n{revenue_5}\n\n"

        modified_text, extracted_urls = replace_and_extract_brackets(revenue_str)

        other_information = {"Revenue BreakDown": modified_text}
        json_str = self.user_query_rag_json_gemini_2_5(self.bd_prompts['revenue_breakdown_formatting'], company_name, other_information=other_information, enable_search=False)

        json_str = revert_text_from_brackets(json_str, extracted_urls)
        output_json = parse_llm_json_output(json_str)

        return output_json


    def _search_social_media(self, company_name):
        ret = self.user_query_rag_gemini_2_5(self.bd_prompts['social_media'], company_name, enable_search=True)
        ret = remove_citations(ret)
        output_json = parse_llm_json_output(ret)

        return output_json

    def _generate_bankruptcy_history(self, company_name):
        output = []

        ret = self.user_query_rag_gemini_2_5(self.bd_prompts['bankruptcy_search'], company_name, enable_search=True)

