class CreditChat:
    def __init__(self):
        self.models = {}
        self.models_with_search = {}

        self.models['gemini-2.5-flash'] = ChatModel(LLMConfig(model="gemini-2.5-flash", temperature=0.7, max_tokens=8192, max_retries=2)).llm
        self.models['gemini-2.5-pro'] = ChatModel(LLMConfig(model="gemini-2.5-pro", temperature=0.7, max_tokens=8192, max_retries=2)).llm

        self.models_with_search['gemini-2.5-flash'] = self.models['gemini-2.5-flash'].bind_tools([{"google_search": {}}])
        self.models_with_search['gemini-2.5-pro'] = self.models['gemini-2.5-pro'].bind_tools([{"google_search": {}}])

        self.trimmer = trim_messages(max_tokens=800000, strategy="last", token_counter=self.models['gemini-2.5-pro'], include_system=True, allow_partial=False, start_on="human")

        self.postgres_conn_str = f"postgresql://{os.environ['DB_USER']}:{os.environ['DB_PASSWORD']}@{os.environ['DB_HOST']}:{os.environ['DB_PORT']}/{os.environ['DB_NAME']}"

        with PostgresSaver.from_conn_string(self.postgres_conn_str) as checkpointer:
            checkpointer.setup()

        self.chat_workflow = StateGraph(state_schema=State)
        self.chat_workflow.add_edge(START, "model")
        self.chat_workflow.add_node("model", self._call_model)

    def get_chat_response(self, user_query, report_id, model='gemini-2.5-pro', thread_id=None, enable_search=False, attachments=None, role_id=3)->ChatResponse :  
        if not thread_id:
            thread_id = str(uuid.uuid4())

        config = {"configurable": {"thread_id": thread_id}}
        messages = []
        system_prompt = None

        with PostgresSaver.from_conn_string(self.postgres_conn_str) as checkpointer:
            thread_metadata = checkpointer.get(config=config)
            if thread_metadata:
                system_prompt = thread_metadata['channel_values']['system_prompt']
            if not system_prompt:
                system_prompt = self._create_system_prompt(report_id, role_id)

        messages.append({
            "role": "user",
            "content": user_query,
        })

        if(attachments):
            for file_path in attachments:
                msg = self._create_media_message(file_path)
                if msg:
                    messages.append(msg)


        state={"messages": messages, "enable_search":enable_search, "system_prompt":system_prompt, "model":model}
        ret = self._compile_run_chat_app(self.chat_workflow, state, config)

        ai_message=ret['messages'][-1]
        response = ai_message.content

        chat_response = ChatResponse(thread_id=thread_id, response=response, ai_message=ai_message)

        if(enable_search):
            chat_response.response = map_google_grounding_citations(chat_response.ai_message)

        return chat_response

    def get_chat_history(self, thread_id):
        with PostgresSaver.from_conn_string(self.postgres_conn_str) as checkpointer:
            ret = checkpointer.get(config =  {"configurable": {"thread_id": thread_id}})

        if ret:
            messages = ret.get('channel_values', {}).get('messages', [])
        else:
            return []
        message_list = []

        for msg in messages:
            if type(msg) == HumanMessage:
                role = 'user'
            elif type(msg) == SystemMessage:
                role = 'system'
            elif type(msg) == AIMessage:
                role = 'assistant'
            elif type(msg) == ToolMessage:
                role = 'tool'

            content = msg.content
            if type(content) == list:
                message_list.append({'role': role, 'content': content[-1]['text']})
            elif type(content) == str and content:
                message_list.append({'role': role, 'content': content})

        return message_list

    def delete_thread(self, thread_id):
        with PostgresSaver.from_conn_string(self.postgres_conn_str) as checkpointer:
            checkpointer.delete_thread(thread_id)

    def _create_system_prompt(self, report_id, role_id):    
        def replace_curly_braces(text):
            return text.replace("{", "{{").replace("}", "}}")

        with get_db() as session:
            query = text("""SELECT 
                    xdata->'credit_limit' as credit_limit, 
                    xdata->'customer_background' as customer_background,
                    xdata,
                    cm_page,
                    company_profile,
                    company_name, 
                    parent_customer_id
                FROM public.credit_report 
                where id = :report_id;
            """)
            result_proxy = session.execute(query, {'report_id': report_id})

            Report = namedtuple('Report', result_proxy.keys())
            reports = [Report(*row) for row in result_proxy.fetchall()]

            try:
                #print(reports[0])
                credit_rating = parse_credit_limit(reports[0])
                cm = reports[0].xdata
                credit_turnover = reports[0].cm_page
                company_profile =  reports[0].company_profile
                #print(credit_rating)
            except:
                print("Error in parse_credit_limit")
                credit_rating = None
                cm = None

            company_name = reports[0].company_name
            parent_customer_id = reports[0].parent_customer_id

        system_prompt = f"""
###Context
You are a helpful assistant of Credit Analysis Platform of a supply chain company. The platform provide credit and financial information of potential customer companies.

###Task
Search for online resources and make use of the provided data to answer user query accurately. You should not make up any information or data. 

###Output Criteria
If no output format is specified in the user query, you should answer in a concise and clear manner while providing relevant facts, numbers and statistics. The data should be formatted in professional and human-readable way, avoid directly quoting the field and variable names of internal data. 
If the user asks for a specific format, you should follow the user reqirements. 
If you do not know the answer, politely say you don't know the answer.

###Potential Customer Company Name:{company_name}"""

        if company_profile:
            system_prompt += f"\n\n###Company Profile Data:\n{replace_curly_braces(str(company_profile))}"

        #allow BD access of all data, BD will be allowed to see potential, controlled by report_id.
        #may change this part if restriction is imposed on potential customer data
        if role_id == 1 or role_id ==2 or role_id ==3: 
            if cm:
                system_prompt += f"\n\n###Credit Memo Data:\n{replace_curly_braces(str(cm))}"
            if credit_rating:
                system_prompt += f"\n\n###Financial Data:\n{replace_curly_braces(str(json.loads(credit_rating.model_dump_json())))}"
            if credit_turnover:
                system_prompt += f"\n\n###Credit & Turnover Summary:\n{replace_curly_braces(str(credit_turnover))}"

        system_prompt = remove_citations(system_prompt)

        #print(system_prompt)

        return system_prompt

    def _call_model(self, state: State):
        prompt_template = ChatPromptTemplate.from_messages(
            [
                (
                    "system",
                    state['system_prompt'],
                ),
                MessagesPlaceholder(variable_name="messages"),
            ]
        )

        trimmed_messages = self.trimmer.invoke(state["messages"])
        prompt = prompt_template.invoke(
            {"messages": trimmed_messages},

        )

        if state['enable_search']:
            response = self.models_with_search[state['model']].invoke(prompt)
        else:
            response = self.models[state['model']].invoke(prompt)
        return {"messages": [response]}

    def _compile_run_chat_app(self, workflow, state: State, config):
        with PostgresSaver.from_conn_string(self.postgres_conn_str) as checkpointer:
            compiled_app = workflow.compile(checkpointer=checkpointer)
            output = compiled_app.invoke(state, config=config) 

        return output

    def _create_media_message(self, file_path):
        file_ext =  file_path.split('.')[-1].lower()

        loader_map = {
            'pdf': self._load_pdf_content,
            'jpg': self._load_jpg_content,
            'jpeg': self._load_jpg_content,
            'png': self._load_jpg_content,
            'txt': self._load_txt_content,
            'docx': self._load_docx_content,
            'csv': self._load_csv_content,
            'xlsx': self._load_xlxs_content,
