class CreditAgent:
    def __init__(self):
        self.openai_client = AzureOpenAI(
            api_version=os.environ['OPENAI_LFTEG_API_VERSION'],
            azure_endpoint=os.environ['OPENAI_LFTEG_ENDPOINT'],
            api_key=os.environ['OPENAI_LFTEG_API_KEY']
        )
        self.embedding_model = 'text-embedding-3-small'

        tools = [
            Tool(
                name="query_credit_report",
                description="Query for internal sources of credit & financial report data given a report id.",
                func=self._query_credit_report,
                args_schema=QueryCreditReportInput
            ),
            Tool(
                name="query_similar_company_report_id",
                description="Given an input name, query for similar company names and their latest credit report IDs.",
                func=self._query_similar_comapny_report_id,
                args_schema=QuerySimilarCompanyInput
            ),
            Tool(
                name="query_google",
                description="Answer a query using Google Search for up-to-date information or external context.",
                func=self._query_google,
                args_schema=GoogleSearchInput
            )
        ]

        self.tools_by_name = {tool.name: tool for tool in tools}

        self.models = {}
        self.models_with_tools = {}

        self.models['gemini-2.5-flash'] = ChatModel(LLMConfig(model="gemini-2.5-flash", temperature=0.7, max_tokens=8192, max_retries=2)).llm
        self.models['gemini-2.5-pro'] = ChatModel(LLMConfig(model="gemini-2.5-pro", temperature=0.7, max_tokens=8192, max_retries=2)).llm

        self.models_with_tools['gemini-2.5-flash'] = self.models['gemini-2.5-flash'].bind_tools(tools)
        self.models_with_tools['gemini-2.5-pro'] = self.models['gemini-2.5-pro'].bind_tools(tools)

        self.trimmer = trim_messages(max_tokens=800000, strategy="last", token_counter=self.models['gemini-2.5-pro'], include_system=True, allow_partial=False, start_on="human")

        self.postgres_conn_str = f"postgresql://{os.environ['DB_USER']}:{os.environ['DB_PASSWORD']}@{os.environ['DB_HOST']}:{os.environ['DB_PORT']}/{os.environ['DB_NAME']}"

        with PostgresSaver.from_conn_string(self.postgres_conn_str) as checkpointer:
            checkpointer.setup()

        self.agent_builder = StateGraph(state_schema=State)
        self.agent_builder.add_node("llm_call", self._call_model)
        self.agent_builder.add_node("tool_node", self._tool_node)
        self.agent_builder.add_edge(START, "llm_call")
        self.agent_builder.add_conditional_edges(
            "llm_call",
            self._should_continue,
            ["tool_node", END]
        )
        self.agent_builder.add_edge("tool_node", "llm_call")

    def _query_credit_report(self, report_id:int)->str:
        def replace_curly_braces(text):
            return text.replace("{", "{{").replace("}", "}}")

        with get_db() as session:
            query = text("""SELECT 
                    xdata->'credit_limit' as credit_limit, 
                    xdata->'customer_background' as customer_background,
                    xdata,
                    cm_page,
                    company_profile,
                    company_name, 
                    parent_customer_id
                FROM public.credit_report 
                where id = :report_id;
            """)
            result_proxy = session.execute(query, {'report_id': report_id})

            Report = namedtuple('Report', result_proxy.keys())
            reports = [Report(*row) for row in result_proxy.fetchall()]

            try:
                #print(reports[0])
                credit_rating = parse_credit_limit(reports[0])
                cm = reports[0].xdata
                credit_turnover = reports[0].cm_page
                company_profile =  reports[0].company_profile
                #print(credit_rating)
            except:
                print("Error in parse_credit_limit")
                credit_rating = None
                cm = None

            company_name = reports[0].company_name
            parent_customer_id = reports[0].parent_customer_id

        output = f"""###Company Name:{company_name}"""

        if company_profile:
            output += f"\n\n###Company Profile Data:\n{replace_curly_braces(str(company_profile))}"
        if cm:
            output += f"\n\n###Credit Memo Data:\n{replace_curly_braces(str(cm))}"
        if credit_rating:
            output += f"\n\n###Financial Data:\n{replace_curly_braces(str(json.loads(credit_rating.model_dump_json())))}"
        if credit_turnover:
            output += f"\n\n###Credit & Turnover Summary:\n{replace_curly_braces(str(credit_turnover))}"

        output = remove_citations(output)

        return output

    def _query_similar_comapny_report_id(self, input_name:str, n_items:int=5) -> str:
        embedding = self._get_embedding(input_name)
        embedding_str = "[" + ",".join(str(x) for x in embedding) + "]"

        with get_db() as session:
            query = text("""
                SELECT
                    company_name,
                    latest_report_id
                FROM
                    credit_company_embeddings
                ORDER BY
                    embedding <=> :embedding
                LIMIT :n_items
            """)
            result_proxy = session.execute(query, {"embedding": embedding_str, "n_items": n_items})
            results = result_proxy.fetchall()

        output_str = "Company Name, Report ID:\n"
        for ret in results:
            output_str+=f"{ret[0], ret[1]}\n"
        return output_str

    def _query_google(self, query:str) -> str:
        model_with_grounding = self.models['gemini-2.5-pro'].bind_tools([{"google_search": {}}])
        ret = model_with_grounding.invoke(query)
        return ret.content

    def _get_embedding(self, input_text):
        response = self.openai_client.embeddings.create(
            input=input_text,
            model=self.embedding_model
        )

        return response.data[0].embedding

    def get_chat_response(self, user_query, model='gemini-2.5-pro', thread_id=None, attachments=None)->ChatResponse :  
        if not thread_id:
            thread_id = str(uuid.uuid4())

        config = {"configurable": {"thread_id": thread_id}}
        messages = []
        system_prompt = None

        with PostgresSaver.from_conn_string(self.postgres_conn_str) as checkpointer:
            thread_metadata = checkpointer.get(config=config)
            if thread_metadata:
                system_prompt = thread_metadata['channel_values']['system_prompt']
            if not system_prompt:
                system_prompt = self._create_system_prompt()

        messages.append({
            "role": "user",
            "content": user_query,
        })

        if(attachments):
            for file_path in attachments:
                msg = self._create_media_message(file_path)
                if msg:
                    messages.append(msg)


        state={"messages": messages, "system_prompt":system_prompt, "model":model}
        ret = self._compile_run_chat_app(self.agent_builder, state, config)

        ai_message = ret['messages'][-1]

        response = ai_message.content
        if type(response) == str:
            pass 
        elif type(response[-1]) == dict:
            response = response[-1]['text']

        chat_response = ChatResponse(thread_id=thread_id, response=response, ai_message=ai_message)

        return chat_response

    def _create_system_prompt(self):    
        system_prompt = f"""
You are a helpful assistant answering questions related to credit risk of a company.

If no company name is provided by user, you should clarify with the user.

Whenever possible, use internal data to answer user.

Your answer should be concise and clear for top management and credit risk analyst.
"""

        return system_prompt

    def _call_model(self, state: State):
        prompt_template = ChatPromptTemplate.from_messages(
            [
                (
                    "system",
                    state['system_prompt'],
                ),
                MessagesPlaceholder(variable_name="messages"),
            ]
        )

        trimmed_messages = self.trimmer.invoke(state["messages"])
        prompt = prompt_template.invoke(
            {"messages": trimmed_messages},

        )


        response = self.models_with_tools[state['model']].invoke(prompt)
        return {"messages": [response]}

    def _tool_node(self, state: dict):
        #print("inside tool node")
        result = []
        for tool_call in state["messages"][-1].tool_calls:
            model_tool = self.tools_by_name[tool_call["name"]]
            observation = model_tool.invoke(tool_call["args"])
            result.append(ToolMessage(content=observation, tool_call_id=tool_call["id"]))
        return {"messages": result}

    def _should_continue(self, state: MessagesState) -> Literal["tool_node", END]:
        #print("inside _should_continue")
        messages = state["messages"]
        last_message = messages[-1]

        if last_message.tool_calls:
            return "tool_node"

        return END

    def _compile_run_chat_app(self, workflow, state: State, config):
        with PostgresSaver.from_conn_string(self.postgres_conn_str) as checkpointer:
            compiled_app = workflow.compile(checkpointer=checkpointer)
            output = compiled_app.invoke(state, config=config) 

        return output

    def _create_media_message(self, file_path):
        file_ext =  file_path.split('.')[-1].lower()

        loader_map = {
            'pdf': self._load_pdf_content,
            'jpg': self._load_jpg_content,
            'jpeg': self._load_jpg_content,
            'png': self._load_jpg_content,
            'txt': self._load_txt_content,
