        }

        loader = loader_map.get(file_ext)
        if loader:
            media_contents = loader(file_path)
        else:
            raise ValueError(f'unsupported file extension: {file_ext}')

        file_title_prompt = {
            "type": "text", 
            "filename": f"{os.path.basename(file_path)}",
            "text": f"##Filename: {os.path.basename(file_path)}\n##File Content:",
        }

