        content = {
            "type": "image_url",  
            "image_url": {
                "url": f"data:application/jpeg;base64,{base64.b64encode(media_bytes).decode('utf-8')}"
            },
        }

        return [content]

    def _load_pdf_content(self, file_path):
        with open(file_path, "rb") as f:
            media_bytes = f.read()

        content = {
            "type": "image_url",
            "image_url": {
                "url": f"data:application/pdf;base64,{base64.b64encode(media_bytes).decode('utf-8')}"
            },
        }

        return [content]

    def _load_txt_content(self, file_path):
        loader = TextLoader(file_path, autodetect_encoding=True)
        data = loader.load()

        content = {
            "type": "text",  
            "text": data[0].page_content,
        }

        return [content]

    def _load_csv_content(self, file_path):
        loader = TextLoader(file_path, autodetect_encoding=True)
        data = loader.load()

        content = {
            "type": "text",  
            "text": data[0].page_content,
        }

        return [content]

    def _load_docx_content(self, file_path):
        loader = Docx2txtLoader(file_path)
        data = loader.load()

        content = {
            "type": "text",  
            "text": data[0].page_content,
        }

        return [content]

    def _load_xlxs_content(self, file_path):
        loader = UnstructuredExcelLoader(file_path, mode="elements")
        data = loader.load()

        contents = []
        for d in data:
            sheet_prompt = {
                "type": "text", 
                "text": f"\nPage Name:{d.metadata['page_name']}\nPage Content:",
            }

            content = {
                "type": "text",  
                "text": d.metadata['text_as_html'],
            }
            contents.append(sheet_prompt)
            contents.append(content)


        return contents


    def get_chat_history(self, thread_id):
        with PostgresSaver.from_conn_string(self.postgres_conn_str) as checkpointer:
            ret = checkpointer.get(config =  {"configurable": {"thread_id": thread_id}})

        if ret:
            messages = ret.get('channel_values', {}).get('messages', [])
        else:
            return []
        message_list = []

        for msg in messages:
            if type(msg) == HumanMessage:
                role = 'user'
            elif type(msg) == SystemMessage:
                role = 'system'
            elif type(msg) == AIMessage:
                role = 'assistant'
            elif type(msg) == ToolMessage:
                role = 'tool'

            content = msg.content
            if type(content) == list:
                message_list.append({'role': role, 'content': content[-1]['text']})
            elif type(content) == str and content:
                message_list.append({'role': role, 'content': content})

        return message_list

    def delete_thread(self, thread_id):
        with PostgresSaver.from_conn_string(self.postgres_conn_str) as checkpointer:
            checkpointer.delete_thread(thread_id)

