def fetch_news_batch(queries, start_date, end_date, interval=12,  max_workers=1):
    all_news = []
    unique_urls = set()

    with ThreadPoolExecutor(max_workers=max_workers) as executor:
        # Create a future for each query
        future_to_query = {executor.submit(fetch_google_news, query, start_date, end_date, interval): query for query in queries}

        # Process the results as they complete
        for future in future_to_query:
            query = future_to_query[future]
            try:
                news_items = future.result()
                for item in news_items:
                    if item.url not in unique_urls:
                        unique_urls.add(item.url)
                        all_news.append(item)
            except Exception as e:
                print(f"Error processing query '{query}': {e}")

    return all_news

