def parse_llm_json_output(llm_output: str):
    json_match = re.search(r'```json\s*(.*?)\s*```', llm_output, re.DOTALL)

    if json_match:
        json_string = json_match.group(1)
    else:
        # If no ```json ``` block is found, try to parse the entire output as JSON
        json_string = llm_output.strip()

    try:
        data = json.loads(json_string)
        return data
    except json.JSONDecodeError as e:
        print(f"Error decoding JSON after regex extraction: {e}")
        print("Problematic JSON string leading up to the error (snippet):")
        # Print a snippet around the error for debugging
        start = max(0, e.pos - 50)
        end = min(len(json_string), e.pos + 50)
        print(json_string[start:end])
        return {}

