models/ai_util.py::revert_text_from_brac.source_code:
def revert_text_from_brackets(modified_text, extracted_strings):
    def replacer(match):
        index = int(match.group(1))
        if 0 <= index < len(extracted_strings):
            return f"【{extracted_strings[index]}】"
        return match.group(0)  # Return original match if index is out of bounds

    original_text = re.sub(r"【(\d+)】", replacer, modified_text)
    return original_text

