def map_google_grounding_citations(response: AIMessage):
    grounding_metadata = response.response_metadata.get('grounding_metadata', {})
    content = response.content

    if grounding_metadata:
        grounding_chunks = grounding_metadata.get('grounding_chunks', [])
        grounding_supports =  grounding_metadata.get('grounding_supports', [])
        n_chunks = len(grounding_chunks)

        for support in grounding_supports:
            #text_chunk = support['segment']['text']
            text_chunk = support.get('segment', {}).get('text', '')
            grounding_chunk_indices = support.get('grounding_chunk_indices', [])

            if text_chunk and text_chunk in content:
                citation = ''
                for ind in grounding_chunk_indices:
                    if ind < n_chunks:
                        chunk_data = grounding_chunks[ind].get('web', {})
                        uri = chunk_data.get('uri', '')

                        if uri:
                            citation += f"【{uri}】"

                #add citation to the content at the end of text_chunk
                content = content.replace(text_chunk, text_chunk + citation)  

    return content

