    def post(self):
        report_id = self.args.get('report_id')
        thread_id = self.args.get('thread_id')
        user_query = self.args.get('user_query')
        enable_search = self.args.get('enable_search')
        model = self.args.get('model')
        attachments = self.args.get('attachments')
        role_id = self.args.get('role_id')

        if user_query is None:
            return jsonify(code=400, msg='user query is required')

        #check if session exists, if not, fetch company data, factsheet, etc
        #need a dataclass for chat session data
        if attachments:
            attachment_paths =  self._download_chat_attachments(attachments)
        else:
            attachment_paths = None

        chat_response = self.credit_chat.get_chat_response(user_query, report_id, model=model, thread_id=thread_id, enable_search=enable_search, attachments=attachment_paths, role_id=int(role_id))

        output = {"thread_id": chat_response.thread_id, "content": chat_response.response}
        return jsonify(code=200, msg='success', data=output)

    def delete(self):
