        report_id = self.args.get('report_id')
        aid = self.args.get('aid')

        if not report_id or not aid:
            return jsonify(code=403, msg='missing report_id or aid parameter.', data={})

        try:
            with get_db() as session:
                sql = """
                    SELECT is_deleted
                    FROM credit_attachments
                    WHERE report_id = :report_id
                    AND id = :aid
                    LIMIT 1
                """

                query = text(sql)
                params = {'report_id': report_id, 'aid': aid}
                row = session.execute(query, params).fetchone()
                if row and row[0] == 0:
                    update_query = text("""
                                    UPDATE credit_attachments SET is_deleted = 1
                                    WHERE report_id = :report_id AND id = :aid
                                """)
                    session.execute(update_query, {
                        'aid': aid,
                        'report_id': report_id
                    })
                    session.commit()

            return jsonify(code=200, msg='success', data={})

        except Exception as e:
            print(traceback.print_exc())
            return jsonify(code=500, msg=str(e), data={})

    def post(self):
        return self.get()

