        super(AttachmentsDownloadAPI, self).__init__()

    def get(self):
        report_id = self.args.get('report_id')
        aid = self.args.get('aid')
        auth = AzureAuthenticator()
        user_info = auth.get_user_info()

        if not report_id or not aid:
            return jsonify(code=403, msg='missing report_id or aid parameter.', data={})

        try:
            connection_string = os.getenv('CREDIT_AZURE_STORAGE_CONNECTION_STRING')

            with get_db() as session:
                sql = """
                    SELECT filename,mime_type,container_name,blob_name
                    FROM credit_attachments
                    WHERE report_id = :report_id
                    AND id = :aid
                    AND is_deleted = 0
                    LIMIT 1
                """

