class DTCReassessment(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.args = self.parser.parse_args()
        self.args = {k: v for k, v in self.args.items() if v is not None}
        super(DTCReassessment, self).__init__()

    def get(self):
        try:
            dtc_data = fetch_sheet_data()
            credit_memo_links = [item['Hyperlink'] for item in dtc_data]
            report_ids = set()
            for link in credit_memo_links:
                try:
                    parsed = urlparse(link)
                    query_params = parse_qs(parsed.query)
                    ids = query_params.get('report_id', [])
                    if ids:
                        report_ids.add(ids[0])
                except Exception:
                    continue

            report_ids = list(report_ids)
            if report_ids:
                with get_db() as session:
                    placeholders = ', '.join(f":id_{i}" for i in range(len(report_ids)))
                    query = text(f"""
                        SELECT cr.id, cr.parent_customer_id, crv.reviewer, crv.reviewer_email
                        FROM credit_report cr
                        JOIN credit_report_review crv ON cr.id = crv.report_id
                        WHERE cr.id IN ({placeholders})
                          AND cr.assessment_status = 2
                    """)
                    params = {f"id_{i}": rid for i, rid in enumerate(report_ids)}
                    result_proxy = session.execute(query, params)
                records = []
                for row in result_proxy:
                    records.append({
                        'report_id': row.id,
                        'parent_customer_id': row.parent_customer_id,
                        'triggered_from': 'ai_reassess',
                        'receiver': row.reviewer,
                        'receiver_email': row.reviewer_email
                    })
                if records:
                    insert_recommendation_workflow_batch(records)

        except Exception as e:
            print(traceback.print_exc())
        return jsonify(code=200, msg='success', data={})

