            conditions = ["parent_customer_code IS NOT NULL"]
            params = {}

            if q_list:
                filter_conds = []
                for idx, q in enumerate(q_list):
                    key_code = f'parent_code{idx}'
                    key_name = f'parent_name{idx}'
                    key_group = f'group_name{idx}'
                    key_customer = f'customer_name{idx}'
                    cond = f"""(
                        parent_customer_code = :{key_code}
                        OR parent_customer_name ILIKE :{key_name}
                        OR customer_group_name ILIKE :{key_group}
                        OR customer_name ILIKE :{key_customer}
                    )"""
                    filter_conds.append(cond)
                    params[key_code] = q
                    params[key_name] = f'%{q}%'
                    params[key_group] = f'%{q}%'
                    params[key_customer] = f'%{q}%'
                conditions.append("(" + " OR ".join(filter_conds) + ")")

            where_clause = " AND ".join(conditions)
            query = f"""
                SELECT
                    parent_customer_code,
                    parent_customer_name,
                    customer_group_name,
                    customer_name
                FROM public.credit_dashboard_production_daily_refreshed
                WHERE {where_clause}
            """

            with get_db() as session:
                proxy = session.execute(text(query), params)
                rows = proxy.mappings().all()

            data = []
            seen = set()
            for row in rows:
                key = (
                    row['parent_customer_code'],
                    row['parent_customer_name'],
                    row['customer_group_name'],
                    row['customer_name'],
                )
                if key not in seen:
                    seen.add(key)
                    data.append({
                        'parent_customer_code': row['parent_customer_code'],
                        'parent_customer_name': row['parent_customer_name'],
                        'customer_group_name': row['customer_group_name'],
                        'customer_name': row['customer_name'],
                    })

            return jsonify(code=200, msg='success', data={'customer_list': data})
        except Exception as e:
            return jsonify(code=500, msg=str(e), data={})

