class ExistingCustomerDetailAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('p_cust_codes', type=list, location='json', required=False)
        self.parser.add_argument('company_names', type=list, location='json', required=False)
        self.parser.add_argument('market_type', type=str, location='json', required=False)
        super(ExistingCustomerDetailAPI, self).__init__()

    def post(self):
        try:
            args = self.parser.parse_args()
            p_cust_codes = args.get('p_cust_codes')
            market_type = args.get('market_type')
            company_names = args.get('company_names')

            with get_db() as db_session:
                if market_type == 'potential':
                    if company_names is None or not company_names:
                        return jsonify(code=400, msg='company_names should be a non-empty list', data={})
                    placeholders = ', '.join(f":company_name_{i}" for i in range(len(company_names)))
                    query = text(f"""
                            SELECT ticker_code, company_name, id, current_risk_category, cm_page, source_type
                                                 FROM (
                                                    SELECT ticker_code, company_name AS company_name, xdata->'customer_background'->>'risk_category' as current_risk_category,
                                                            id, cm_page, 'company_name' AS source_type,
                                                            ROW_NUMBER() OVER (PARTITION BY company_name ORDER BY version DESC) AS rn
                                                    FROM credit_report
                                                    WHERE market_type = :market_type
                                                         AND assessment_status = 2
                                                         AND company_name IN ({placeholders})
                                                 ) sub
                                                 WHERE rn = 1
                    """)
                    params = {f"company_name_{i}": name for i, name in enumerate(company_names)}
                else:
                    if p_cust_codes is None or not p_cust_codes:
                        return jsonify(code=400, msg='p_cust_codes should be a non-empty list', data={})
                    placeholders = ', '.join(f":parent_code_{i}" for i in range(len(p_cust_codes)))
                    query = text(f"""
                                                 SELECT p_cust_code, company_name, id, current_risk_category, cm_page, source_type
                                                 FROM (
                                                    SELECT p_cust_code, company_name AS company_name, xdata->'customer_background'->>'current_risk_category' as current_risk_category,
                                                            id, cm_page, 'company_name' AS source_type,
                                                            ROW_NUMBER() OVER (PARTITION BY p_cust_code ORDER BY version DESC) AS rn
                                                    FROM credit_report
                                                    WHERE market_type = :market_type
                                                         AND assessment_status = 2
                                                         AND p_cust_code IN ({placeholders})
                                                 ) sub
                                                 WHERE rn = 1
                                            """)
                    params = {f"parent_code_{i}": parent_code for i, parent_code in enumerate(p_cust_codes)}
                params["market_type"] = market_type

                results = db_session.execute(query, params).fetchall()

                existing_customer = []
                potential_customer = []
                for rec in results:
                    cm_page_data = rec.cm_page if isinstance(rec.cm_page, dict) else {}
                    credit_limit_total = cm_page_data.get('credit_limit_total', {})
                    total_insurance_amount = 0
                    if credit_limit_total:
                        val = credit_limit_total.get('credit_limit_total_insurance_amount', '0')
                        try:
                            total_insurance_amount = float(val)
                        except Exception:
                            total_insurance_amount = 0
                    covered_by_insurer = 1 if total_insurance_amount > 0 else 0

                    credit_limits = cm_page_data.get('credit_limit', [])
                    streams = set()
                    if isinstance(credit_limits, list):
                        for cl in credit_limits:
                            stream_val = cl.get('stream')
                            if stream_val:
                                streams.add(stream_val)
                    active_og = ','.join(sorted(streams)) if streams else ''

                    if market_type == 'potential':
                        item = {
                            'report_id': rec.id,
                            'company_name': rec.company_name,
                            'ticker_code': getattr(rec, 'ticker_code', ''),
                            'risk_category': rec.current_risk_category,
                            'covered_by_insurer': covered_by_insurer,
                            'active_og': active_og
                        }
                        potential_customer.append(item)
                    else:
                        item = {
                            'report_id': rec.id,
                            'p_cust_code': rec.p_cust_code,
                            'risk_category': rec.current_risk_category,
                            'covered_by_insurer': covered_by_insurer,
                            'active_og': active_og
                        }
                        existing_customer.append(item)

            return jsonify(code=200, msg='success',
                           data={'existing_customers': existing_customer, 'potential_customer': potential_customer})
        except Exception as e:
            return jsonify(code=500, msg=str(e), data={})

