def build_level_map(hierarchy_nodes, level_map=None):
    if level_map is None:
        level_map = {}
    for node in hierarchy_nodes:
        level_map[node['entity_id']] = node.get('level')
        if node.get('children'):
            build_level_map(node['children'], level_map)
    return level_map

