class EntityHierarchyAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('entity_ids', type=list, location='json', required=False)
        super(EntityHierarchyAPI, self).__init__()

    def get(self):
        try:
            args = self.parser.parse_args()
            entity_ids = args.get('entity_ids')
            if entity_ids is None or not entity_ids:
                return jsonify(code=400, msg='entity_ids should be a non-empty list', data={})

            builder = EntityHierarchyService()
            hierarchy = builder.get_hierarchy_by_entity_ids(entity_ids)
            company_names = [node.get('name').upper() for node in hierarchy if node.get('name')]
            if not company_names:
                return jsonify(code=200, msg='success', data={'hierarchy': hierarchy})

            with get_db() as db_session:
                placeholders = ', '.join(f":name_{i}" for i in range(len(company_names)))
                query = text(f"""
                             SELECT company_name, id, current_risk_category, cm_page, p_cust_code, source_type
                             FROM (
                                SELECT UPPER(xdata->'customer_background'->>'parent_customer_group') AS company_name,
                                          xdata->'customer_background'->>'current_risk_category' as current_risk_category,
                             			    id, cm_page, p_cust_code, 'parent_group'AS source_type,
                                          ROW_NUMBER() OVER (PARTITION BY UPPER(xdata->'customer_background'->>'parent_customer_group') ORDER BY version DESC) AS rn
                                FROM credit_report
                                WHERE market_type = 'existing'
                                     AND assessment_status = 2
                                     AND UPPER(xdata->'customer_background'->>'parent_customer_group') IN ({placeholders})
                                UNION ALL
                                SELECT UPPER(company_name) AS company_name, xdata->'customer_background'->>'current_risk_category' as current_risk_category,
                                   			id, cm_page, p_cust_code, 'company_name' AS source_type,
                                          ROW_NUMBER() OVER (PARTITION BY UPPER(company_name) ORDER BY version DESC) AS rn
                                FROM credit_report
                                WHERE market_type = 'existing'
                                     AND assessment_status = 2
                                     AND UPPER(company_name) IN ({placeholders})
                             ) sub
                             WHERE rn = 1
                        """)
                params = {f"name_{i}": name for i, name in enumerate(company_names)}
                results = db_session.execute(query, params).fetchall()

                customer_groups = {}
                customer_names = {}
                for rec in results:
                    item = {
                        'report_id': rec.id,
                        'p_cust_code': rec.p_cust_code,
                        'risk_category': rec.current_risk_category,
                        'covered_by_insurer': 0,
                        'active_og': ''
                    }
                    cm_page_data = rec.cm_page if isinstance(rec.cm_page, dict) else {}
                    credit_limit_total = cm_page_data.get('credit_limit_total', {})
                    total_insurance_amount = 0
                    if credit_limit_total:
                        val = credit_limit_total.get('credit_limit_total_insurance_amount', '0')
                        try:
                            total_insurance_amount = float(val)
                        except Exception:
                            total_insurance_amount = 0
                    item['covered_by_insurer'] = 1 if total_insurance_amount > 0 else 0
                    credit_limits = cm_page_data.get('credit_limit', [])
                    streams = set()
                    if isinstance(credit_limits, list):
                        for cl in credit_limits:
                            stream_val = cl.get('stream')
                            if stream_val:
                                streams.add(stream_val)
                    item['active_og'] = ','.join(sorted(streams)) if streams else ''

                    if rec.source_type == 'parent_group':
                        customer_groups[rec.company_name] = item
                    else:
                        customer_names[rec.company_name] = item
            for node in hierarchy:
                node_name = node.get('name').upper() if node.get('name') else ''
                if node_name in customer_groups:
                    node['existing_customer'] = customer_groups[node_name]
                elif node_name in customer_names:
                    node['existing_customer'] = customer_names[node_name]

            return jsonify(code=200, msg='success', data={'hierarchy': hierarchy})
        except Exception as e:
            return jsonify(code=500, msg=str(e), data={})

    def post(self):
        return self.get()

