class ExcelUploadAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('assessment_transaction_id', type=str, location='values', required=True)
        self.parser.add_argument('task_status', type=str, location='values', required=True)
        self.args = self.parser.parse_args()
        arg_kv = {}
        for k, v in self.args.items():
            if v is not None:
                arg_kv[k] = v
        self.args = arg_kv
        super(ExcelUploadAPI, self).__init__()

    def post(self):
        report_id = self.args.get('assessment_transaction_id')
        task_status = self.args.get('task_status')
        rpa_key = request.headers.get('rpa-key')
        if rpa_key != RPA_API_SECRET:
            return jsonify(code=403, msg='Invalid or missing rpa-key header.', data={})

        if not report_id or task_status not in ['success', 'failure']:
            return jsonify(code=403, msg='missing assessment_transaction_id or task_status parameter.', data={})

        report_data = {}
        user_info = {}
        with get_db() as session:
            query = text("""
                        SELECT id, company_name, p_cust_code, market_type, version, listing_status, ticker_code, trigger_status
                        FROM credit_report
                        WHERE id = :report_id
                        ORDER BY version DESC
                        LIMIT 1
                    """)
            result = session.execute(query, {'report_id': report_id}).fetchone()
            if result:
                query = text("SELECT * FROM credit_report_review WHERE report_id = :report_id ")
                result_proxy = session.execute(query, {'report_id': report_id})
                ReportReview = namedtuple('ReportReview', result_proxy.keys())
                review_rows = [ReportReview(*row) for row in result_proxy.fetchall()]
                if review_rows:
                    review_res = review_rows[0]
                    user_info = {'user_name': review_res.reviewer, 'user_email': review_res.reviewer_email}

                    report_data = {
                        'report_id': result[0],
                        'company_name': result[1],
                        'p_cust_code': result[2],
                        'market_type': result[3],
                        'version': result[4],
                        'listing_status': result[5],
                        'ticker_code': result[6],
                        'trigger_status': result[7]
                    }
        if not report_data:
            return jsonify(code=403, msg=f'The current assessment_transaction_id: {report_id} does not exist.', data={})

        if task_status == 'failure':
            with get_db() as session:
                delete_query = text("DELETE FROM credit_report WHERE id = :report_id")
                session.execute(delete_query, {'report_id': report_id})
                session.commit()
            return jsonify(code=200, msg='success', data={})

        if 'file' not in request.files:
            return jsonify(code=403, msg='File does not exist.', data={})
        if 'pdf_file' in request.files and request.files['pdf_file'].filename == '':
            return jsonify(code=403, msg='PDF file name cannot be null.', data={})
        file = request.files['file']
        file_size = file.content_length
        if file.filename == '' or file_size is None:
            return jsonify(code=403, msg='No selected file.', data={})

        allowed_types = {'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                         'application/vnd.openxmlformats-officedocument.spreadsheetml.template'}
        filename = secure_filename(file.filename)
        mime_type, _ = mimetypes.guess_type(filename)
        if 'pdf_file' in request.files and request.files['pdf_file']:
            pdf_file_size = request.files['pdf_file'].content_length
            pdf_filename = secure_filename(request.files['pdf_file'].filename)
            pdf_mime_type, _ = mimetypes.guess_type(pdf_filename)
            if pdf_filename == '' or pdf_file_size is None:
                return jsonify(code=403, msg='Please upload a valid pdf filename and  file size cannot be empty.', data={})
            if pdf_mime_type != 'application/pdf':
                return jsonify(code=403,
                               msg='Invalid file format. Please upload a pdf_file in .pdf format.',
                               data={})

        if mime_type not in allowed_types:
            return jsonify(code=403, msg=f'Invalid file format. Please upload a file in .xlsx, .xltx, or .pdf format, current filename: {filename} and mime_type: {mime_type}',
                           data={})
        ExtractorObj = ExcelExtractor()
        if report_data['market_type'] == 'existing':
            report_data['company_name'], report_data['final_memo'], report_data['cm_page'], report_data['factsheet'], report_data['risk_rating'] = ExtractorObj.extract_report_data(file)
        else:
            parent_customer_name, report_data['final_memo'], report_data['cm_page'], report_data['factsheet'], report_data['risk_rating'] = ExtractorObj.extract_potential_data(file, report_data['listing_status'])
        updated = save_report_to_db(report_data)
        if not updated:
            return jsonify(code=403, msg='failed to upload excel.', data={})

        try:
            container_name = os.getenv('CREDIT_AZURE_STORAGE_CONTAINER_EXCEL')
            blob_name = f"{report_id}_{filename}"
            blob_url = upload_to_azure_blob(file, mime_type, container_name, blob_name)
            save_attachment_to_db(report_id, mime_type, filename, file_size, container_name, blob_name, 'RPA')
            parent_customer = report_data['company_name']
            if report_data['ticker_code'] and report_data['market_type'] == 'potential':
                parent_customer = report_data['ticker_code'] + '_' + parent_customer

            subsidiaries = [report_data['company_name']]
            if 'turnover_data' in report_data['cm_page']:
                for item in report_data['cm_page']['turnover_data']:
                    siubsidiary = item.get('customer_name')
                    if siubsidiary and siubsidiary != '(blank)':
                        subsidiaries.append(item.get('customer_name'))

            if subsidiaries:
                parent_customer_id, has_updated = SubsidiariesService().save(parent_customer, subsidiaries, 'excel')
                if parent_customer_id:
                    ReportService().save_parent_customer(parent_customer_id, report_data)
                    triggered_from = 'new_company'
                    if report_data['trigger_status'] == 3:
                        triggered_from = 'excel_reassess'
                    insert_recommendation_workflow(report_id, parent_customer_id, triggered_from, user_info)

            data = {
                'url': blob_url
            }
            if 'pdf_file' in request.files:
                blob_name = f"{report_id}_{pdf_filename}"
                pdf_blob_url = upload_to_azure_blob(request.files['pdf_file'], pdf_mime_type, container_name, blob_name)
                save_attachment_to_db(report_id, pdf_mime_type, pdf_filename, pdf_file_size, container_name, blob_name,
                                      'RPA')
                data['pdf_url'] = pdf_blob_url

        except Exception as e:
            print(traceback.print_exc())

        return jsonify(code=200, msg='success', data=data)

