class GoogleNewsConsumer(Resource):

    def batch_insert_news(self, news_list):
        if not news_list:
            return
        batch_size = 100
        batches = [news_list[i:i + batch_size] for i in range(0, len(news_list), batch_size)]
        shanghai_tz = timezone('Asia/Shanghai')
        now = datetime.now(shanghai_tz)
        try:
            with get_db() as session:
                for batch in batches:
                    keys = [(news['google_hash'], news.get('subsidiary_id'), news.get('parent_id')) for news in batch if news.get('subsidiary_id')]
                    if not keys:
                        continue

                    placeholders = ', '.join(f"(:hash{i}, :subsidiary_id{i}, :parent_id{i})" for i in range(len(keys)))
                    params_dict = {}
                    for i, (google_hash, subsidiary_id, parent_id) in enumerate(keys):
                        params_dict[f'hash{i}'] = google_hash
                        params_dict[f'subsidiary_id{i}'] = subsidiary_id
                        params_dict[f'parent_id{i}'] = parent_id

                    select_query = text(f"""
                        SELECT google_hash, subsidiary_id, parent_id
                        FROM public.credit_google_news
                        WHERE (google_hash, subsidiary_id, parent_id) IN ({placeholders})
                    """)
                    existing_records = session.execute(select_query, params_dict).fetchall()
                    existing_keys = set((row.google_hash, row.subsidiary_id, row.parent_id) for row in existing_records)
                    params = []
                    for news in batch:
                        google_hash = news['google_hash']
                        subsidiary_id = news.get('subsidiary_id')
                        parent_id = news.get('parent_id')
                        if not subsidiary_id:
                            continue
                        key = (google_hash, subsidiary_id, parent_id)
                        if key in existing_keys:
                            continue
                        params.append({
                            'title': news['google_title'],
                            'url': news['google_url'],
                            'published_date': news['google_published_date'],
                            'source': news['google_source'],
                            'hash': google_hash,
                            'created_at': now,
                            'updated_at': now,
                            'subsidiary_id': subsidiary_id,
                            'parent_id': parent_id,
                            'status': 'google_fetched'
                        })
                    if params:
                        insert_query = text("""
                            INSERT INTO public.credit_google_news (
                                google_title, google_url, google_published_date, 
                                google_source, google_hash, created_at, updated_at, 
                                subsidiary_id, status, parent_id
                            ) VALUES (:title, :url, :published_date, 
                                :source, :hash, :created_at, :updated_at, :subsidiary_id, :status, :parent_id)
                        """)
                        session.execute(insert_query, params)
                        session.commit()
        except Exception as e:
            print(e)

        return True

    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('sign', location='args', required=True)
        self.args = self.parser.parse_args()
        self.args = {k: v for k, v in self.args.items() if v is not None}
        super(GoogleNewsConsumer, self).__init__()

    def get(self):

        def handle_msg(msg, client):
            try:
                data = json.loads(msg.content)
                if data:
                    news = process_google_news(data)
                    if news:
                        self.batch_insert_news(news)
                    today = now_dt.strftime("%Y-%m-%d")
                    with get_db() as session :
                        update_query = text("""
                            UPDATE public.credit_subsidiary_keywords
                            SET last_sync_date = :last_sync_date
                            WHERE id = :id
                        """)
                        session.execute(update_query, {'last_sync_date': today, 'id': data ['id']})
                        session.commit()
            except Exception as e:
                print(traceback.print_exc(e))

            client.delete_message(msg)

        try:
            sign = self.args.get('sign')
            if gen_sign(self.args) != sign:
                return jsonify(code=401, msg='Invalid token, please check.', data={})
            shanghai_tz = timezone('Asia/Shanghai')
            now_dt = datetime.now(shanghai_tz)
            workers = 2

            connection_string = os.getenv('CREDIT_AZURE_STORAGE_CONNECTION_STRING')
            queue_name = os.getenv('CREDIT_NEWS_QUEUE')
            reassess_queue_name = os.getenv('CREDIT_NEWS_REASSESS_QUEUE')
            queue_client = QueueClient.from_connection_string(connection_string, queue_name)
            reassess_queue_client = QueueClient.from_connection_string(connection_string, reassess_queue_name)

            reassess_messages = list(reassess_queue_client.receive_messages(messages_per_page=workers, visibility_timeout=10,
                                                       logging_enable=False))
            if reassess_messages:
                with concurrent.futures.ThreadPoolExecutor(max_workers=workers) as executor:
                    futures = [executor.submit(handle_msg, msg, reassess_queue_client) for msg in reassess_messages[:workers]]
                    for future in concurrent.futures.as_completed(futures, timeout=10):
                        try:
                            future.result()
                        except concurrent.futures.TimeoutError:
                            print("Processing timeout")
                return jsonify(code=200, msg="Reassess queue processed successfully", data={})

            messages = queue_client.receive_messages(messages_per_page=workers, visibility_timeout=10, logging_enable=False)
            messages_list = []
            for i, msg in enumerate(messages):
                if i >= workers:
                    break
                messages_list.append(msg)
            with concurrent.futures.ThreadPoolExecutor(max_workers=workers) as executor:
                futures = [executor.submit(handle_msg, msg, queue_client) for msg in messages_list]
                for future in concurrent.futures.as_completed(futures, timeout=10):
                    try:
                        future.result()
                    except concurrent.futures.TimeoutError:
                        print("Processing timeout")

            return jsonify(code=200, msg="success", data={})

        except Exception as e:
            print(traceback.print_exc(e))

        return jsonify(code=500, msg=str(e), data={})

    def post(self):
        return self.get()

