    def get(self):
        try:
            sign = self.args['sign']
            if gen_sign(self.args) != sign:
                return jsonify(code=401, msg='Invalid token, please check.', data={})

            utc_tz = pytz.UTC
            now = datetime.now(utc_tz)
            start_time = now - timedelta(hours=14)
            start_time_str = start_time.strftime("%Y-%m-%d %H:%M:%S.000")

            with get_db() as session:
                query = text("""
                    SELECT DISTINCT ON (parent_id) cpc.customer_name, cgn.parent_id 
                        FROM credit_google_news cgn 
                        JOIN credit_parent_customers cpc ON cgn.parent_id = cpc.id 
                        WHERE cgn.status = 'firecrawl_fetched'
                          AND cgn.crawl_status not in ('irrelevant_title','old_news')
                          AND cgn.parent_id > 0
                          AND cgn.google_published_date < :start_time
                    ORDER BY cgn.parent_id, cgn.google_published_date DESC limit 4
                """)
                result = session.execute(query, {'start_time': start_time_str}).fetchall()

            connection_string = os.getenv('CREDIT_AZURE_STORAGE_CONNECTION_STRING')
            queue_name = os.getenv('CREDIT_EVENT_QUEUE')
            queue_client = QueueClient.from_connection_string(connection_string, queue_name)
            for row in result:
                msg = {'customer_name': row[0], 'parent_id': row[1]}
                message_content = json.dumps(msg)
                queue_client.send_message(message_content)

            return jsonify(code=200, msg="success", data={})

        except Exception as e:
            print(traceback.print_exc())
            return jsonify(code=500, msg=str(e), data={})

