def parse_crawl_published_date(metadata):
    formats = [
        '%Y-%m-%dT%H:%M:%S%z',
        '%b %dth %Y',
        '%b %d %Y'
    ]

    for key in [
        "article:published_time",
        "og:article:published_time",
        "og:updated_time",
        "crawl_published_date",
        "last_updated_date"
    ]:
        date_str = metadata.get(key)
        if isinstance(date_str, list):
            date_str = date_str[0] if date_str else None

        if date_str:
            date_str = re.sub(r'(\d+)(st|nd|rd|th)', r'\1', date_str)
            for fmt in formats:
                try:
                    parsed_date = datetime.strptime(date_str, fmt)
                    if parsed_date.tzinfo is None and 'Z' in date_str:
                        parsed_date = parsed_date.replace(tzinfo=pytz.utc)
                    elif parsed_date.tzinfo is None:
                        parsed_date = pytz.utc.localize(parsed_date)
                    return parsed_date.strftime('%Y-%m-%d %H:%M:%S')
                except ValueError:
                    continue
    return None

