class FirecrawlNews(Resource):

    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('sign', location='args', required=True)
        self.args = self.parser.parse_args()
        self.args = {k: v for k, v in self.args.items() if v is not None}
        super(FirecrawlNews, self).__init__()

    def get(self):
        try:
            sign = self.args.get('sign')
            if gen_sign(self.args) != sign:
                return jsonify(code=401, msg='Invalid token, please check.', data={})

            news_rows = None
            update_queries = []
            company_name = ''
            shanghai_tz = timezone('Asia/Shanghai')
            now = datetime.now(shanghai_tz)
            with get_db() as session:
                query = text("""
                    (SELECT cgn.parent_id, cpc.customer_name FROM public.credit_recommendation_workflow crw JOIN credit_google_news cgn ON crw.parent_id = cgn.parent_id AND cgn.status = 'google_fetched' JOIN credit_parent_customers cpc ON cgn.parent_id = cpc.id WHERE crw.status IN ('pending', 'crawling') ORDER BY crw.created_at ASC LIMIT 1) 
                    UNION ALL 
                    (SELECT cgn.parent_id, cpc.customer_name FROM credit_google_news cgn JOIN credit_parent_customers cpc ON cgn.parent_id = cpc.id WHERE cgn.status = 'google_fetched' LIMIT 1)
                    LIMIT 1
                """)
                result = session.execute(query).fetchone()
                if result:
                    parent_id = result[0]
                    company_name = result[1]
                    query = text("select cgn.id as news_id,cgn.google_source as source,cgn.crawl_content as content,cgn.google_title as title,cgn.google_url as url,cgn.google_published_date as google_publish_date from credit_google_news cgn join credit_parent_customers cpc on cgn.parent_id = cpc.id where cgn.status = 'google_fetched' and cgn.parent_id  = :parent_id order by cgn.google_published_date desc limit 30")
                    result_proxy = session.execute(query, {'parent_id': parent_id})
                    GoogleNews = namedtuple('GoogleNews', result_proxy.keys())
                    news_rows = [GoogleNews(*row) for row in result_proxy.fetchall()]

            if company_name and news_rows:
                news_objects = []
                for row in news_rows:
                    if row.google_publish_date:
                        adjusted_date = row.google_publish_date + timedelta(hours=8)
                        formatted_google_publish_date = adjusted_date.strftime('%Y-%m-%d')
                    else:
                        formatted_google_publish_date = None

                    if not formatted_google_publish_date:
                        continue
                    news = News(
                        title=row.title,
                        url=row.url,
                        published_date=formatted_google_publish_date,
                        content=row.content,
                        google_publish_date=formatted_google_publish_date,
                        news_id=row.news_id,
                        source_origin=row.source
                    )
                    news_objects.append(news)
                credit_news_ai = CreditNewsAI(prompt_directory='data/prompt')
                processed_news = credit_news_ai.process_news(company_name, news_objects)
                if processed_news:
                    for row in news_rows:
                        news_id = row.news_id
                        processed_item = next((item for item in processed_news if item.news_id == news_id), None)

                        if processed_item:
                            if isinstance(processed_item.metadata, str):
                                try:
                                    processed_item.metadata = json.loads(processed_item.metadata)
                                except json.JSONDecodeError:
                                    processed_item.metadata = {}
                            elif isinstance(processed_item.metadata, list):
                                processed_item.metadata = processed_item.metadata[0] if processed_item.metadata else {}

                            origin_url = processed_item.metadata.get("og:url")
                            crawl_published_date = parse_crawl_published_date(processed_item.metadata)
                            status_flag = None
                            content = ''
                            summary = ''
                            if hasattr(processed_item, 'status_flag') and processed_item.status_flag is not None:
                                status_flag = processed_item.status_flag
                            if hasattr(processed_item, 'content') and processed_item.content is not None:
                                content = processed_item.content
                            if hasattr(processed_item, 'summary') and processed_item.summary is not None:
                                summary = processed_item.summary

                            update_queries.append({
                                "news_id": news_id,
                                "origin_url": origin_url,
                                "crawl_published_date": crawl_published_date,
                                "content": content,
                                "summary": summary,
                                "crawl_status": status_flag,
                                "updated_at": now
                            })
                        else:
                            update_queries.append({
                                "news_id": news_id,
                            })

                with get_db() as session:
                    for update in update_queries:
                        if 'origin_url' in update:
                            update_query = text("""
                                                UPDATE public.credit_google_news 
                                                SET origin_url = :origin_url,
                                                    crawl_published_date = :crawl_published_date,
                                                    crawl_content = :content,
                                                    summary = :summary,
                                                    status = 'firecrawl_fetched',
                                                    crawl_status = :crawl_status,
                                                    updated_at = :updated_at
                                                WHERE id = :news_id
                                            """)
                            session.execute(update_query, update)
                        else:
                            update_query = text("""
                                                UPDATE public.credit_google_news 
                                                SET status = 'firecrawl_fetched',
                                                    updated_at = :updated_at
                                                WHERE id = :news_id
                                            """)
                            session.execute(update_query, {"news_id": update['news_id'], "updated_at": now})

                    if update_queries:
                        session.commit()


            return jsonify(code=200, msg="success", data={})

        except Exception as e:
            print(traceback.print_exc(e))
            return jsonify(code=500, msg=str(e), data={})

    def post(self):
        return self.get()

