class GoogleNews(Resource):

    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('sign', location='args', required=True)
        self.args = self.parser.parse_args()
        self.args = {k: v for k, v in self.args.items() if v is not None}
        super(GoogleNews, self).__init__()

    def get(self):
        try:
            sign = self.args.get('sign')
            if gen_sign(self.args) != sign:
                return jsonify(code=401, msg='Invalid token, please check.', data={})
            shanghai_tz = timezone('Asia/Shanghai')
            now_dt = datetime.now(shanghai_tz)
            keywords = []
            with get_db() as session:
                query = text("SELECT * FROM public.credit_subsidiary_keywords order by last_sync_date desc")
                result_proxy = session.execute(query)
                Keywords = namedtuple('Keywords', result_proxy.keys())
                keyword_rows = [Keywords(*row) for row in result_proxy.fetchall()]

            for item in keyword_rows:
                if not item.last_sync_date or not isinstance(item.last_sync_date, str):
                    continue

                try:
                    dt = datetime.fromisoformat(
                        item.last_sync_date if len(item.last_sync_date) > 7 else item.last_sync_date + "-01")
                    dt = dt.replace(tzinfo=shanghai_tz)
                except ValueError:
                    continue

                if now_dt >= dt and now_dt - dt <= timedelta(days=31):
                    keywords.append({
                        'id': item.id,
                        'parent_customer_id': item.parent_customer_id,
                        'keyword': item.keyword
                    })

            if keywords:
                connection_string = os.getenv('CREDIT_AZURE_STORAGE_CONNECTION_STRING')
                queue_name = os.getenv('CREDIT_NEWS_QUEUE')
                queue_client = QueueClient.from_connection_string(connection_string, queue_name)
                for msg in keywords:
                    message_content = json.dumps(msg)
                    queue_client.send_message(message_content)

            return jsonify(code=200, msg="success", data={})

        except Exception as e:
            print(traceback.print_exc(e))
            return jsonify(code=500, msg=str(e), data={})

    def post(self):
        return self.get()

