def get_next_month(current_month):
    try:
        first_day = datetime.strptime(current_month, "%Y-%m")
    except ValueError:
        try:
            first_day = datetime.strptime(current_month, "%Y-%m-%d")
            first_day = first_day.replace(day=1)
        except ValueError as e:
            pass

    next_month = first_day + timedelta(days=31)
    return next_month.replace(day=1).strftime("%Y-%m")

