class AlertListAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('sign', location='args', required=True)
        self.parser.add_argument('debug', type=int, location='values', required=False)
        self.args = self.parser.parse_args()
        self.args = {k: v for k, v in self.args.items() if v is not None}
        super(AlertListAPI, self).__init__()

    def get(self):
        debug = self.args.get('debug')
        sign = self.args.get('sign')
        if gen_sign(self.args) != sign:
            return jsonify(code=401, msg='Invalid token, please check.', data={})

        utc_tz = pytz.UTC
        now = datetime.now(utc_tz)
        news_rows = None
        data = []

        if 23 <= now.hour < 24:
            hours = 14
        elif 0 <= now.hour < 23:
            hours = 5

        if debug:
            hours = 124

        start_time = now - timedelta(hours=hours)
        start_time_str = start_time.strftime("%Y-%m-%d %H:00:00.000+00:00")
        end_time_str = (now + timedelta(hours=1)).strftime("%Y-%m-%d %H:00:00.000+00:00")
        with get_db() as session:
            query = text("SELECT event_data,news_data FROM public.credit_news_event_history where created_at >= :start_time and created_at < :end_time order by created_at desc limit 1")
            res = session.execute(query, {
                'start_time': start_time_str,
                'end_time': end_time_str
            }).fetchone()
            if res:
                event_data = res[0]
                news_data = res[1]
                news_dict = {str(news['news_id']): int(news['news_rank']) for news in news_data if news.get('news_id')}
                events_dict = {str(event['event_id']): int(event['rank']) for event in event_data if event.get('event_id') and event['rank'] != ''}
                query = text("""
                    SELECT cgn.id news_id,cpc.customer_name,cne.event,cgn.google_title,cgn.google_url,cgn.google_published_date,cgn.crawl_published_date,
                        cgn.google_source,cgn.event_id,cr.market_type,cgn.subsidiary_id,cgn.parent_id,csk.id,csk.parent_customer_id,cr.version
                    FROM credit_google_news cgn
                    JOIN credit_subsidiary_keywords csk ON cgn.subsidiary_id = csk.id
                    JOIN credit_news_event cne ON cgn.event_id = cne.id
                    JOIN credit_parent_customers cpc ON cpc.id = cgn.parent_id
                    JOIN (
                        SELECT parent_customer_id, MAX(version) AS version, market_type
                        FROM credit_report
                        GROUP BY parent_customer_id, market_type
                    ) cr ON cr.parent_customer_id = cpc.id
                    WHERE cgn.id IN :news_ids
                """)
                result_proxy = session.execute(query.bindparams(
                    bindparam("news_ids", expanding=True)
                ), {
                    'news_ids': list(news_dict.keys())
                })
                News = namedtuple('News', result_proxy.keys())
                news_rows = [News(*row) for row in result_proxy.fetchall()]

        server_now = datetime.now().astimezone()
        is_utc = (server_now.utcoffset() == timedelta(0))
        if news_rows:
            items = []
            for news in news_rows:
                alert = check_alert(news.google_title.lower())
                if alert and news.event:
                    news_rank = news_dict[str(news.news_id)] if str(news.news_id) in news_dict else 100
                    event_rank = events_dict[str(news.event_id)] if str(news.event_id) in events_dict else 100
                    customer_name = news.customer_name
                    if int(news_rank) == 100:
                        continue

                    if news.crawl_published_date:
                        crawl_date = news.crawl_published_date.date()
                        google_date = news.google_published_date.date()
                        day_diff = abs((google_date - crawl_date).days)
                        if day_diff > 1:
                            print(f"{news.google_title}, {crawl_date}, {google_date}")
                            continue

                    if is_utc:
                        adjusted_date = news.google_published_date + timedelta(hours=8)
                    else:
                        adjusted_date = news.google_published_date

                    items.append({
                        'title': news.google_title,
                        'event': news.event,
                        'event_rank': int(event_rank),
                        'url': news.google_url,
                        'format_date': adjusted_date.strftime("%d %b %Y %H:%M:%S HKT"),
                        'source_origin': news.google_source,
                        'customer_name': customer_name.split('_')[-1],
                        'market_type': news.market_type,
                        'alert_keyword': alert,
                        'news_rank': news_rank
                    })

            customer_events = {}
            for item in items:
                cust = item['customer_name']
                evt = item['event']
                customer_events.setdefault(cust, {}).setdefault(evt, []).append(item)

            for cust, events in customer_events.items():
                seen_titles = set()
                sorted_event_keys = sorted(
                    events.keys(),
                    key=lambda evt: min(item['event_rank'] for item in events[evt])
                )[:5]
                for evt in sorted_event_keys:
                    records = events[evt]
                    deduped_records = []
                    for record in sorted(records, key=lambda x: x['news_rank']):
                        title = record['title'].split(" - ")[0].strip()
                        if title not in seen_titles:
                            deduped_records.append(record)
                            seen_titles.add(title)
                        if len(deduped_records) == 3:
                            break
                    data.extend(deduped_records)

        return jsonify(code=200, msg='success', data={'items': data})

    def post(self):
        return self.get()

