class PotentialAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('ticker_code', type=str, location='values', required=False)
        self.parser.add_argument('company_name', type=str, location='values', required=False)
        self.parser.add_argument('listing_status', type=str, location='values', required=True)
        super(PotentialAPI, self).__init__()

    def post(self):
        args = self.parser.parse_args()
        ticker_code = args.get('ticker_code').upper() if args.get('ticker_code') else ''
        company_name = args.get('company_name')
        listing_status = args.get('listing_status')
        auth = AzureAuthenticator()
        user_info = auth.get_user_info()
        return self.handle_listing(listing_status, ticker_code, company_name, user_info)

    def handle_listing(self, listing_status, ticker_code, company_name, user_info):
        current_time = int(datetime.now().timestamp())
        market_type = 'potential'

        if listing_status == 'listed':
            if not ticker_code:
                return jsonify(code=403, msg='Missing ticker_code parameter.', data={})
            if not company_name:
                company_name = ''
            return self.process_listed(ticker_code, current_time, company_name, user_info, market_type)

        elif listing_status == 'non-listed':
            if not company_name:
                return jsonify(code=403, msg='Missing company_name parameter.', data={})
            return self.process_non_listed(company_name, current_time, user_info, market_type)

    def process_listed(self, ticker_code, current_time, company_name, user_info, market_type):
        sql = """
            SELECT id, assessment_status FROM credit_report 
            WHERE ticker_code = :ticker_code 
            AND market_type = :market_type 
            AND listing_status = 'listed'
        """
        params = {'ticker_code': ticker_code, 'market_type': market_type}

        try:
            with get_db() as session:
                rows = session.execute(text(sql), params).fetchall()
                if self.check_existing_reports(rows):
                    return jsonify(code=500, msg='The company already exists, please Re-Assess the operation.', data={})
                if self.check_in_progress_reports(rows):
                    return jsonify(code=500,
                                   msg=f'The current ticker_code: {ticker_code} is still in progress, please refresh the page later to view the list.',
                                   data={})

                self.remove_failed_records(session, ticker_code, market_type)

                report_id = self.insert_report(session, ticker_code, company_name, current_time, market_type,'listed')
                review_id = self.insert_review(session, report_id, user_info, current_time)

            if not report_id or not review_id:
                return jsonify(code=500, msg='Failed to create company, please try again.', data={})

            self.start_job(ticker_code, report_id, user_info, market_type)
        except Exception as e:
            print(f"An error occurred while starting the job: {e}")
            return jsonify(code=500, msg='Failed to start rpa job.', data={})
        return jsonify(code=200, msg='Success', data={})

    def process_non_listed(self, company_name, current_time, user_info, market_type):
        sql = """
            SELECT id, assessment_status FROM credit_report 
            WHERE listing_status = 'non-listed' 
            AND market_type = :market_type 
            AND company_name = :company_name
        """
        params = {'company_name': company_name, 'market_type': market_type}

        try:
            with get_db() as session:
                rows = session.execute(text(sql), params).fetchall()
                if self.check_existing_reports(rows):
                    return jsonify(code=500,
                                   msg='The company already exists, can be located by searching for company name.',
                                   data={})
                if self.check_in_progress_reports(rows):
                    return jsonify(code=500,
                                   msg=f'The company is still in progress, please refresh the page later to view the list.',
                                   data={})

                report_id = self.insert_report(session, '', company_name, current_time, market_type, 'non-listed')
                review_id = self.insert_review(session, report_id, user_info, current_time)

            parent_customer_id, has_updated = SubsidiariesService().save(company_name, [company_name], 'excel')
            if parent_customer_id:
                report_data = {
                    'company_name': company_name,
                    'market_type': market_type,
                    'p_cust_code': '',
                    'ticker_code': ''
                }
                ReportService().save_parent_customer(parent_customer_id, report_data)
                insert_recommendation_workflow(report_id, parent_customer_id, 'new_company', user_info)
        except Exception as e:
            print(traceback.format_exc())
            return jsonify(code=500, msg='Failed to create company, please try again.', data={})

        return jsonify(code=200, msg='success', data={})

    def check_existing_reports(self, rows):
        for row in rows:
            if row.assessment_status == 2:
                return True
        return False

    def check_in_progress_reports(self, rows):
        for row in rows:
            if row.assessment_status in [1,4]:
                return True
        return False

    def remove_failed_records(self, session, ticker_code, market_type):
        session.execute(
            text("DELETE FROM credit_report WHERE ticker_code = :ticker_code AND assessment_status = 3 AND market_type = :market_type"),
            {'ticker_code': ticker_code, 'market_type': market_type}
        )
        session.commit()

    def insert_report(self, session, ticker_code, company_name, current_time, market_type, listing_status=''):
        insert_sql = """
            INSERT INTO credit_report (p_cust_code, ctime, utime, trigger_status, version, assessment_status, xdata, risk_rating, company_name, market_type, ticker_code, listing_status)
            VALUES (:p_cust_code, :ctime, :utime, :trigger_status, :version, :assessment_status, :xdata, :risk_rating, :company_name, :market_type, :ticker_code, :listing_status) RETURNING id
        """
        xdata = {"requests": [], "key_risks": [], "recommendations": [], "customer_background": {"rating": "", "market_cap": "", "risk_alert": "", "ticker_code": "", "customer_name": "", "industry_code": "", "risk_category": "", "product_sourced": "", "lf_customer_since": "", "bankruptcy_history": "", "next_credit_review": "", "bussiness_activities": "", "current_risk_category": "", "parent_customer_group": "", "main_business_location": ""}, "recommendations_title": ""}
        xdata['customer_background']['customer_name'] = company_name
        insert_params = {
            'p_cust_code': '',
            'ctime': current_time,
            'utime': current_time,
            'trigger_status': 1,
            'version': 1,
            'assessment_status': 1,
            'xdata': json.dumps(xdata) if listing_status == 'non-listed' else '{}',
            'risk_rating': json.dumps(risk_rating_default),
            'company_name': company_name,
            'market_type': market_type,
            'ticker_code': ticker_code if listing_status == 'listed' else '',
            'listing_status': listing_status
        }
        res = session.execute(text(insert_sql), insert_params)
        report_id = res.scalar()
        session.commit()
        return report_id

    def insert_review(self, session, report_id, user_info, current_time):
        review_sql = """
            INSERT INTO credit_report_review (report_id, review_status, reviewer, reviewer_email, review_time) 
            VALUES (:report_id, :review_status, :reviewer, :reviewer_email, :review_time) RETURNING review_time
        """
        review_params = {
            'report_id': report_id,
            'review_status': 1,
            'reviewer': user_info['user_name'],
            'reviewer_email': user_info['user_email'],
            'review_time': current_time
        }
        res = session.execute(text(review_sql), review_params)
        review_id = res.scalar()
        session.commit()
        return review_id

    def start_job(self, ticker_code, report_id, user_info, market_type):
        req_data = {
            'in_Company': '',
            'in_RequesterName': user_info['user_name'],
            'assessment_transaction_id': str(report_id),
            'requestor_email_address': user_info['user_email'],
            'market_type': market_type,
            'in_Ticker': ticker_code
        }
        connection_string = os.getenv('CREDIT_AZURE_STORAGE_CONNECTION_STRING')
        queue_name = os.getenv('CREDIT_UIPATH_QUEUE')
        queue_client = QueueClient.from_connection_string(connection_string, queue_name)
        message_content = json.dumps(req_data)
        queue_client.send_message(message_content)

