class PotentialAssessAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('entity_ids', type=str, location='values', required=True)
        self.args = self.parser.parse_args()
        self.logger = async_logger
        arg_kv = {}
        for k, v in self.args.items():
            if v is not None:
                arg_kv[k] = v
        self.args = arg_kv
        super(PotentialAssessAPI, self).__init__()

    def post(self):
        entity_ids = self.args.get('entity_ids')
        market_type = 'potential'
        if not entity_ids:
            return jsonify(code=403, msg='missing entity_id parameter.', data={})
        entity_ids_list = [int(eid.strip()) for eid in str(entity_ids).split(',') if eid.strip().isdigit()]
        try:
            auth = AzureAuthenticator()
            user_info = auth.get_user_info()
            current_time = int(datetime.now().timestamp())
            with get_db() as session:
                query = text("""
                    SELECT * FROM (
                        SELECT id,assessment_status,xdata,trigger_status,company_name,parent_customer_id,ticker_code,
                               entity_id,version,ROW_NUMBER() OVER(PARTITION BY entity_id ORDER BY version DESC) as rn
                        FROM credit_report
                        WHERE entity_id = ANY (:entity_ids)) t
                    WHERE rn = 1;
                """)
                reports = session.execute(query, {'entity_ids': entity_ids_list}).fetchall()
                report_dict = {}
                for report in reports:
                    report_dict[report.entity_id] = {
                        'version': int(report.version),
                        'assessment_status': int(report.assessment_status),
                        'company_name': report.company_name,
                        'parent_customer_id': report.parent_customer_id,
                        'ticker_code': report.ticker_code,
                        'entity_id': report.entity_id if report.entity_id else 0
                    }

                in_progress_codes = []
                for entity_id in entity_ids_list:
                    if entity_id in report_dict:
                        if int(report_dict[entity_id]['assessment_status']) == 1:
                            in_progress_codes.append(report_dict[entity_id]['ticker_code'])
                            continue

                if in_progress_codes:
                    return jsonify(
                        code=500,
                        msg=f'Tickers/CIQ IDs: {"|".join(in_progress_codes)} are still in progress. Please wait to receive an email notification upon completion.',
                        data={}
                    )

                for entity_id in entity_ids_list:
                    if entity_id in report_dict:
                        query = text(
                            "INSERT INTO credit_report (p_cust_code, company_name, assessment_time, ctime, utime, version, trigger_status, assessment_status, xdata, market_type, ticker_code, listing_status, parent_customer_id, entity_id) VALUES (:p_cust_code, :company_name, :assessment_time, :ctime, :utime, :version, :trigger_status, :assessment_status, :xdata, :market_type, :ticker_code, :listing_status, :parent_customer_id, :entity_id) RETURNING id")
                        params = {'p_cust_code': '', 'company_name': report_dict[entity_id]['company_name'],
                                  'assessment_time': 0, 'ctime': current_time, 'utime': current_time,
                                  'version': report_dict[entity_id]['version'] + 1, 'trigger_status': 3,
                                  'assessment_status': 1, 'xdata': '{}', 'market_type': market_type,
                                  'ticker_code': report_dict[entity_id]['ticker_code'],
                                  'listing_status': 'listed',
                                  'parent_customer_id': report_dict[entity_id]['parent_customer_id'],
                                  'entity_id': entity_id}
                        res = session.execute(query, params)
                        report_id = res.scalar()
                        session.commit()
                        if report_id:
                            query = text("""
                                         INSERT INTO credit_report_review (report_id, review_status, reviewer, reviewer_email, review_time)
                                         VALUES (:report_id, :review_status, :reviewer, :reviewer_email,
                                                 :review_time) RETURNING review_time
                                         """)
                            params = {'report_id': report_id, 'review_status': 1, 'reviewer': user_info['user_name'],
                                      'reviewer_email': user_info['user_email'], 'review_time': current_time}
                            res = session.execute(query, params)
                            review_id = res.scalar()
                            session.commit()
                        if report_id and review_id:
                            req_data = {
                                'in_Company': '',
                                'in_RequesterName': user_info['user_name'],
                                'assessment_transaction_id': str(report_id),
                                'requestor_email_address': user_info['user_email'],
                                'market_type': market_type,
                                'in_Ticker': report_dict[entity_id]['ticker_code']
                            }
                            connection_string = os.getenv('CREDIT_AZURE_STORAGE_CONNECTION_STRING')
                            queue_name = os.getenv('CREDIT_UIPATH_QUEUE')
                            queue_client = QueueClient.from_connection_string(connection_string, queue_name)
                            message_content = json.dumps(req_data)
                            queue_client.send_message(message_content)

            log_otherinfo = json.dumps(self.args, ensure_ascii=False)
            self.logger.async_log(user_info, log_otherinfo, log_action_party=f"User_{user_info.get('user_id', '')}",
                                  function_group="Assessment", function_name="Re-assess")
            return jsonify(code=200, msg='success', data={})
        except Exception as e:
            print(traceback.print_exc())
            return jsonify(code=500, msg=str(e), data={})

