def get_max_level(hierarchy_nodes):
    max_level = 0
    for node in hierarchy_nodes:
        level = node.get('level', 0)
        if node.get('children'):
            child_max = get_max_level(node['children'])
            level = max(level, child_max)
        if level > max_level:
            max_level = level
    return max_level

