def build_relation_type_map(hierarchy_nodes, max_level=None, relation_type_map=None):
    if relation_type_map is None:
        relation_type_map = {}
    if max_level is None:
        max_level = get_max_level(hierarchy_nodes)
    for node in hierarchy_nodes:
        if node.get('level') == max_level:
            relation_type_map[node['entity_id']] = 'children'
        else:
            relation_type_map[node['entity_id']] = 'parent'
        if node.get('children'):
            build_relation_type_map(node['children'], max_level, relation_type_map)
    return relation_type_map

