def map_report_detail_to_hierarchy(hierarchy_nodes, entity_report_map):
    for node in hierarchy_nodes:
        report_detail = entity_report_map.get(node['entity_id'], {})
        node['report_id'] = report_detail.get('report_id', 0)
        node['company_profile'] = report_detail.get('company_profile', {})
        ctime = report_detail.get('ctime')

        if ctime:
            create_time_date = datetime.fromtimestamp(ctime)
            initial_assess_end_date = (create_time_date + relativedelta(months=1, day=1)) - relativedelta(days=1)
            node['last_review_date'] = initial_assess_end_date.strftime('%Y-%m-%d')
        else:
            node['last_review_date'] = ''

        if node.get('children'):
            map_report_detail_to_hierarchy(node['children'], entity_report_map)

