class PotentialUploadAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('ticker_code', type=str, location='values', required=False)
        self.parser.add_argument('report_id', type=str, location='values', required=False)
        self.parser.add_argument('listing_status', type=str, location='values', required=False)
        self.args = self.parser.parse_args()
        self.logger = async_logger
        arg_kv = {}
        for k, v in self.args.items():
            if v is not None:
                arg_kv[k] = v
        self.args = arg_kv
        super(PotentialUploadAPI, self).__init__()

    def post(self):
        ticker_code = self.args.get('ticker_code')
        report_id = self.args.get('report_id')
        listing_status = self.args.get('listing_status', 'listed')

        if 'file' not in request.files:
            return jsonify(code=403, msg='File does not exist.', data={})

        file = request.files['file']
        file_size = file.content_length
        if file.filename == '' or file_size is None:
            return jsonify(code=403, msg='No selected file.', data={})

        if listing_status == 'non-listed':
            if not report_id:
                return jsonify(code=403, msg='missing report_id parameter.', data={})
            sql = "SELECT * FROM credit_report WHERE id = :report_id and assessment_status = 2 and listing_status = 'non-listed'"
            params = {'report_id': report_id}
        else:
            if not ticker_code:
                return jsonify(code=403, msg='missing ticker_code parameter.', data={})
            sql = "SELECT * FROM credit_report WHERE ticker_code = :ticker_code ORDER BY version DESC LIMIT 1"
            params = {'ticker_code': ticker_code}

        auth = AzureAuthenticator()
        user_info = auth.get_user_info()
        filename = secure_filename(file.filename)
        mime_type, _ = mimetypes.guess_type(filename)
        allowed_types = {'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                         'application/vnd.openxmlformats-officedocument.spreadsheetml.template',
                         'application/pdf'}
        if mime_type not in allowed_types:
            return jsonify(code=403, msg='Invalid file format. Please upload a file in .xlsx, .xltx format.',
                           data={})

        report_data = {}
        try:
            with get_db() as session:
                result_proxy = session.execute(text(sql), params)
                Report = namedtuple('Report', result_proxy.keys())
                reports = [Report(*row) for row in result_proxy.fetchall()]
                if not reports:
                    return jsonify(code=403, msg='This report does not exist.', data={})
                result = reports[0]

                if result:
                    if result.listing_status == 'non-listed':
                        sql = "SELECT * FROM credit_report WHERE company_name = :company_name and listing_status = 'non-listed' ORDER BY version DESC LIMIT 1"
                        result_proxy = session.execute(text(sql), {'company_name': result.company_name})
                        Report = namedtuple('Report', result_proxy.keys())
                        results = [Report(*row) for row in result_proxy.fetchall()]
                        if results:
                            result = results[0]
        except Exception as e:
            print(traceback.print_exc())

        ExtractorObj = ExcelExtractor()
        if listing_status == 'listed':
            report_data['company_name'], report_data['final_memo'], report_data['cm_page'], report_data['factsheet'], report_data['risk_rating'] = ExtractorObj.extract_report_data(file)
        else:
            report_data['company_name'], report_data['final_memo'], report_data['cm_page'], report_data['factsheet'], report_data['risk_rating'] = ExtractorObj.extract_potential_data(file)
        if result.listing_status == 'non-listed' and result.company_name != report_data.get('final_memo', {}).get('customer_background', {}).get('customer_name'):
            return jsonify(code=403,
                           msg='The uploaded excel should be consistent with the current report customer name.',
                           data={})
        if result.listing_status == 'listed' and result.company_name != report_data['company_name']:
            return jsonify(code=403,
                           msg='The uploaded excel should be consistent with the current report customer group.',
                           data={})

        report_id, review_id = create_new_version(result, report_data, result.version, user_info)
        if not report_id or not review_id:
            return jsonify(code=500, msg='failed to upload report.', data={})
        blob_name = f"{report_id}_{filename}"
        container_name = os.getenv('CREDIT_AZURE_STORAGE_CONTAINER_EXCEL')
        upload_to_azure_blob(file, mime_type, container_name, blob_name)
        save_attachment_to_db(report_id, mime_type, filename, file_size, container_name, blob_name, user_info['user_name'])
        parent_customer = report_data['company_name']
        if ticker_code:
            parent_customer = ticker_code + '_' + parent_customer

        subsidiaries = []
        if 'turnover_data' in report_data['cm_page']:
            for item in report_data['cm_page']['turnover_data']:
                siubsidiary = item.get('customer_name')
                if siubsidiary and siubsidiary != '(blank)':
                    subsidiaries.append(item.get('customer_name'))
        if not subsidiaries:
            subsidiaries = [parent_customer]

        if subsidiaries:
            parent_customer_id, has_updated = SubsidiariesService().save(parent_customer, subsidiaries, 'excel')
            if parent_customer_id:
                report_data['market_type'] = 'potential'
                report_data['p_cust_code'] = ''
                report_data['ticker_code'] = ticker_code
                ReportService().save_parent_customer(parent_customer_id, report_data)

        connection_string = os.getenv('CREDIT_AZURE_STORAGE_CONNECTION_STRING')
        queue_name = os.getenv('CREDIT_JOB_QUEUE', 'aidrafting')
        queue_client = QueueClient.from_connection_string(connection_string, queue_name)
        message_content = json.dumps({"report_id": report_id})
        queue_client.send_message(message_content)

        log_otherinfo = json.dumps(self.args, ensure_ascii=False)
        self.logger.async_log(user_info, log_otherinfo, log_action_party=f"User_{user_info.get('user_id', '')}",
                              function_group="Assessment", function_name="Excel Edit AND Upload")

        return jsonify(code=200, msg='success', data={})

