class BatchAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('data', type=list, location='json', required=True)
        self.args = self.parser.parse_args()
        self.logger = async_logger
        super(BatchAPI, self).__init__()

    def check_existing_reports(self, rows):
        for row in rows:
            if row.assessment_status == 2:
                return True
        return False

    def check_in_progress_reports(self, rows):
        for row in rows:
            if row.assessment_status in [1, 4]:
                return True
        return False

    def remove_failed_records(self, session, entity_id, market_type):
        session.execute(
            text(
                "DELETE FROM credit_report WHERE entity_id = :entity_id AND assessment_status = 3 AND market_type = :market_type"),
            {'entity_id': entity_id, 'market_type': market_type}
        )
        session.commit()

    def get_next_version(self, rows):
        max_version = 0
        for row in rows:
            if row.version and row.version > max_version:
                max_version = row.version
        return max_version + 1

    def insert_report(self, session, ticker_code, company_name, entity_id, current_time, max_version, market_type, listing_status=''):
        insert_sql = """
            INSERT INTO credit_report (p_cust_code, ctime, utime, trigger_status, version, assessment_status, xdata, risk_rating, company_name, market_type, ticker_code, listing_status, entity_id)
            VALUES (:p_cust_code, :ctime, :utime, :trigger_status, :version, :assessment_status, :xdata, :risk_rating, :company_name, :market_type, :ticker_code, :listing_status, :entity_id) RETURNING id
        """
        xdata = {"requests": [], "key_risks": [], "recommendations": [],
                 "customer_background": {"rating": "", "market_cap": "", "risk_alert": "", "ticker_code": "",
                                         "customer_name": "", "industry_code": "", "risk_category": "",
                                         "product_sourced": "", "lf_customer_since": "", "bankruptcy_history": "",
                                         "next_credit_review": "", "bussiness_activities": "",
                                         "current_risk_category": "", "parent_customer_group": "",
                                         "main_business_location": ""}, "recommendations_title": ""}
        xdata['customer_background']['customer_name'] = company_name
        insert_params = {
            'p_cust_code': '',
            'ctime': current_time,
            'utime': current_time,
            'trigger_status': 1,
            'version': max_version,
            'assessment_status': 1,
            'xdata': json.dumps(xdata) if listing_status == 'non-listed' else '{}',
            'risk_rating': json.dumps(risk_rating_default),
            'company_name': company_name,
            'market_type': market_type,
            'ticker_code': ticker_code if listing_status == 'listed' else '',
            'listing_status': listing_status,
            'entity_id': entity_id
        }
        res = session.execute(text(insert_sql), insert_params)
        report_id = res.scalar()
        session.commit()
        return report_id

    def insert_review(self, session, report_id, user_info, current_time):
        review_sql = """
            INSERT INTO credit_report_review (report_id, review_status, reviewer, reviewer_email, review_time) 
            VALUES (:report_id, :review_status, :reviewer, :reviewer_email, :review_time) RETURNING review_time
        """
        review_params = {
            'report_id': report_id,
            'review_status': 1,
            'reviewer': user_info['user_name'],
            'reviewer_email': user_info['user_email'],
            'review_time': current_time
        }
        res = session.execute(text(review_sql), review_params)
        review_id = res.scalar()
        session.commit()
        return review_id

    def process_item(self, item, user_info, current_time):
        listing_status = item.get('listing_status')
        company_name = item.get('company_name', '')
        ticker_code = item.get('ticker_code', '').upper() if item.get('ticker_code') else ''
        entity_id = item.get('entity_id', 0)

        if listing_status == 'listed':
            if not ticker_code:
                return {
                    'item': item,
                    'code': 403,
                    'msg': 'Missing ticker_code parameter.',
                    'data': {}
                }
            if not entity_id:
                return {
                    'item': item,
                    'code': 403,
                    'msg': 'Missing entity_id parameter.',
                    'data': {}
                }
        elif listing_status == 'non-listed':
            if not company_name:
                return {
                    'item': item,
                    'code': 403,
                    'msg': 'Missing company_name parameter.',
                    'data': {}
                }
        else:
            return {
                'item': item,
                'code': 403,
                'msg': f'Invalid listing_status: {listing_status}.',
                'data': {}
            }

        result = self.handle_listing(listing_status, ticker_code, company_name, entity_id, user_info, current_time)

        return {
            'item': item,
            'code': result["code"],
            'msg': result["msg"],
            'data': result.get("data", {})
        }

    def post(self):
        items = self.args.get('data')

        auth = AzureAuthenticator()
        user_info = auth.get_user_info()
        batch_results = []
        current_time = int(datetime.now().timestamp())

        with ThreadPoolExecutor(max_workers=2) as executor:
            future_to_item = {
                executor.submit(self.process_item, item, user_info, current_time): item for item in items
            }
            for future in as_completed(future_to_item):
                item = future_to_item[future]
                try:
                    result = future.result()
                except Exception as exc:
                    result = {
                        'item': item,
                        'code': 503,
                        'msg': f'An error occurred during processing: {exc}',
                        'data': {}
                    }
                batch_results.append(result)

        successes = [r for r in batch_results if r['code'] == 200]
        reassess = [r for r in batch_results if r['code'] == 500]
        errors = [r for r in batch_results if r['code'] not in [200, 500]]
        if errors or reassess:
            data = {
                'success': [r['item'] for r in successes],
                'errors': [{'item': r['item'], 'code': r['code'], 'msg': r['msg']} for r in errors],
                'reassess': [r['item'] for r in reassess]
            }
            return jsonify(code=500, msg='Batch processing completed with errors', data=data)

        log_otherinfo = json.dumps(items, ensure_ascii=False)
        self.logger.async_log(user_info, log_otherinfo, log_action_party=f"User_{user_info.get('user_id', '')}", function_group="Assessment", function_name="New Company")
        return jsonify(code=200, msg='Batch processing complete', data={})

    def handle_listing(self, listing_status, ticker_code, company_name, entity_id, user_info, current_time):
        market_type = 'potential'

        if listing_status == 'listed':
            return self.process_listed(ticker_code, current_time, company_name, entity_id, user_info, market_type)
        elif listing_status == 'non-listed':
            return self.process_non_listed(company_name, current_time, user_info, market_type)

    def process_listed(self, ticker_code, current_time, company_name, entity_id, user_info, market_type):
        sql = """
            SELECT id, version, assessment_status FROM credit_report
            where entity_id = :entity_id
            AND market_type = :market_type
        """
        params = {'market_type': market_type, 'entity_id': entity_id}

        try:
            with get_db() as session:
                rows = session.execute(text(sql), params).fetchall()
                if self.check_in_progress_reports(rows):
                    return {"code": 501, "msg": f'The current entity_id: {entity_id} is still in progress, please refresh the page later to view the list.', "data": {}}
                self.remove_failed_records(session, entity_id, market_type)

                max_version = self.get_next_version(rows)
                report_id = self.insert_report(session, ticker_code, company_name, entity_id, current_time, max_version, market_type, 'listed')
                review_id = self.insert_review(session, report_id, user_info, current_time)

            if not report_id or not review_id:
                return {"code": 503, "msg": 'Failed to create company, please try again.', "data": {}}

            self.start_job(ticker_code, report_id, user_info, market_type)
        except Exception as e:
            print(f"An error occurred while starting the job: {e}")
            return {"code": 503, "msg": 'Failed to create rpa job. Please contact support.', "data": {}}

        return {"code": 200, "msg": 'Success', "data": {}}

    def process_non_listed(self, company_name, current_time, user_info, market_type):
        sql = """
            SELECT id, assessment_status FROM credit_report
            WHERE listing_status = 'non-listed'
            AND market_type = :market_type
            AND company_name = :company_name
        """
        params = {'company_name': company_name, 'market_type': market_type}

        try:
            with get_db() as session:
                rows = session.execute(text(sql), params).fetchall()
                '''
                if self.check_existing_reports(rows):
                    return {"code": 500,
                            "msg": 'The company already exists, can be located by searching for company name.',
                            "data": {}}
                '''
                if self.check_in_progress_reports(rows):
                    return {"code": 501, "msg": 'The company is still in progress, please refresh the page later to view the list.', "data": {}}

                max_version = self.get_next_version(rows)
                report_id = self.insert_report(session, '', company_name, 0, current_time, max_version, market_type, 'non-listed')
                review_id = self.insert_review(session, report_id, user_info, current_time)

                if not report_id or not review_id:
                    return {"code": 503, "msg": 'Failed to create company, please try again.', "data": {}}

            parent_customer_id, has_updated = SubsidiariesService().save(company_name, [company_name], 'excel')
            if parent_customer_id:
                report_data = {
                    'company_name': company_name,
                    'market_type': market_type,
                    'p_cust_code': '',
                    'ticker_code': ''
                }
                ReportService().save_parent_customer(parent_customer_id, report_data)
                insert_recommendation_workflow(report_id, parent_customer_id, 'new_company', user_info)

        except Exception as e:
            print(traceback.format_exc())
            return {"code": 503, "msg": 'Failed to create company, please try again.', "data": {}}

        return {"code": 200, "msg": 'Success', "data": {}}

    def start_job(self, ticker_code, report_id, user_info, market_type):
        req_data = {
            'in_Company': '',
            'in_RequesterName': user_info['user_name'],
            'assessment_transaction_id': str(report_id),
            'requestor_email_address': user_info['user_email'],
            'market_type': market_type,
            'in_Ticker': ticker_code
        }
        connection_string = os.getenv('CREDIT_AZURE_STORAGE_CONNECTION_STRING')
        queue_name = os.getenv('CREDIT_UIPATH_QUEUE')
        queue_client = QueueClient.from_connection_string(connection_string, queue_name)
        message_content = json.dumps(req_data)
        queue_client.send_message(message_content)

