class ReportBatchDelAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('report_ids', type=list, location='json', required=True)
        self.args = self.parser.parse_args()
        self.logger = async_logger
        super(ReportBatchDelAPI, self).__init__()

    def post(self):
        report_ids = self.args.get('report_ids')
        auth = AzureAuthenticator()
        user_info = auth.get_user_info()
        if not report_ids:
            return jsonify(code=403, msg='missing report_ids parameter.', data={})
        if not isinstance(report_ids, list):
            return jsonify(code=400, msg='report_ids must be a list.', data={})
        try:
            del_report_ids = []
            reports = None
            with get_db() as session:
                query = text("""
                    SELECT * FROM credit_report
                    WHERE id in :report_ids and assessment_status = 2
                """).bindparams(bindparam("report_ids", expanding=True))
                result_proxy = session.execute(query, {'report_ids': report_ids})
                Report = namedtuple('Report', result_proxy.keys())
                reports = [Report(*row) for row in result_proxy.fetchall()]

            p_cust_codes = []
            ticker_codes = []
            non_list_companys = []
            non_list_report_ids = []
            for report in reports:
                if report.p_cust_code:
                    p_cust_codes.append(report.p_cust_code)
                elif report.market_type == 'potential' and report.ticker_code:
                    ticker_codes.append(report.ticker_code)
                else:
                    non_list_companys.append(report.company_name)

            if non_list_companys:
                with get_db() as session:
                    query = text("""
                        SELECT id FROM credit_report
                        WHERE company_name in :company_name and market_type = 'potential' and listing_status = 'non-listed'
                    """).bindparams(bindparam("company_name", expanding=True))
                    result_proxy = session.execute(query, {'company_name': non_list_companys})
                    non_list_report_ids = [row[0] for row in result_proxy.fetchall()]

            base_query = "SELECT id FROM credit_report WHERE 1=1"
            conditions = []
            params = {}
            if non_list_report_ids:
                conditions.append("id IN :report_ids")
                params['report_ids'] = non_list_report_ids

            if p_cust_codes:
                conditions.append("p_cust_code IN :p_cust_code")
                params['p_cust_code'] = p_cust_codes

            if ticker_codes:
                conditions.append("ticker_code IN :ticker_code")
                params['ticker_code'] = ticker_codes

            if conditions:
                base_query += " AND " + " OR ".join(conditions)
                with get_db() as session:
                    query = text(base_query).bindparams(
                        *(bindparam(key, expanding=True) for key in params.keys())
                    )
                    result_proxy = session.execute(query, params)
                    del_report_ids = [row[0] for row in result_proxy.fetchall()]

            if del_report_ids:
                with get_db() as session:
                    stmt = text("DELETE FROM credit_report WHERE id IN :report_ids").bindparams(
                        bindparam("report_ids", expanding=True)
                    )
                    session.execute(stmt, {'report_ids': del_report_ids})
                    session.commit()
            log_otherinfo = json.dumps(self.args, ensure_ascii=False)
            self.logger.async_log(user_info, log_otherinfo, log_action_party=f"User_{user_info.get('user_id', '')}",
                                  function_group="Customer", function_name="Delete Company")
            return jsonify(code=200, msg='success', data={})
        except Exception as e:
            print(traceback.print_exc(e))
            return jsonify(code=500, msg=str(e), data={})

