class ReportSaveAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('report_id', type=int, location='values', required=True)
        self.parser.add_argument('final_memo', type=str, location='values', required=False)
        self.parser.add_argument('cm_page', type=str, location='values', required=False)
        self.parser.add_argument('factsheet', type=str, location='values', required=False)
        self.parser.add_argument('risk_rating', type=str, location='values', required=False)
        self.parser.add_argument('company_profile', type=str, location='values', required=False)
        self.args = self.parser.parse_args()
        self.logger = async_logger
        arg_kv = {}
        for k, v in self.args.items():
            if v is not None:
                arg_kv[k] = v
        self.args = arg_kv
        super(ReportSaveAPI, self).__init__()

    def post(self):
        report_id = self.args.get('report_id')
        final_memo_json = self.args.get('final_memo')
        cm_page_json = self.args.get('cm_page')
        factsheet_json = self.args.get('factsheet')
        risk_rating_json = self.args.get('risk_rating')
        company_profile_json = self.args.get('company_profile')
        if not report_id:
            return jsonify(code=403, msg='missing report_id parameter.', data={})
        try:
            with get_db() as session:
                query = text("SELECT * FROM credit_report WHERE id = :report_id and assessment_status = 2 limit 1")
                result_proxy = session.execute(query, {'report_id': report_id})
                Report = namedtuple('Report', result_proxy.keys())
                reports = [Report(*row) for row in result_proxy.fetchall()]
                if not reports:
                    return jsonify(code=403, msg='This report does not exist.', data={})
                result = reports[0]
                if result.market_type == 'existing':
                    order_field = 'p_cust_code'
                    order_value = result.p_cust_code
                elif result.market_type == 'potential' and result.listing_status == 'listed':
                    order_field = 'entity_id'
                    order_value = result.entity_id
                elif result.market_type == 'potential' and result.listing_status == 'non-listed':
                    order_field = 'company_name'
                    order_value = result.company_name
                query = text(f"SELECT version FROM public.credit_report where {order_field} = :order_value order by version desc")
                max_version_report = session.execute(query, {'order_value': order_value}).fetchone()
                if not max_version_report:
                    return jsonify(code=403, msg='This report does not exist.', data={})
                max_version = max_version_report[0]
                data = {}
                if final_memo_json and validate_json(final_memo_json):
                    data['final_memo'] = final_memo_json
                    final_memo = json.loads(final_memo_json)
                else:
                    data['final_memo'] = json.dumps(result.xdata) if result.xdata else '{}'
                    final_memo = json.loads(data['final_memo'])

                if cm_page_json and validate_json(cm_page_json):
                    data['cm_page'] = cm_page_json
                else:
                    data['cm_page'] = json.dumps(result.cm_page) if result.cm_page else '{}'

                if factsheet_json and validate_json(factsheet_json):
                    data['factsheet'] = factsheet_json
                    factsheet = json.loads(factsheet_json)
                else:
                    data['factsheet'] = json.dumps(result.factsheet) if result.factsheet else '{}'
                    factsheet = json.loads(data['factsheet'])

                if risk_rating_json and validate_json(risk_rating_json):
                    data['risk_rating'] = risk_rating_json
                    risk_rating = json.loads(risk_rating_json)
                else:
                    data['risk_rating'] = json.dumps(result.risk_rating) if result.risk_rating else '{}'
                    risk_rating = json.loads(data['risk_rating'])

                if company_profile_json and validate_json(company_profile_json):
                    data['company_profile'] = company_profile_json
                    company_profile = json.loads(company_profile_json)
                else:
                    data['company_profile'] = json.dumps(result.company_profile) if result.company_profile else '{}'
                    company_profile = json.loads(data['company_profile'])

                report_id = create_new_version(result, data, max_version)

                if result.market_type == 'potential':
                    dtc_queue_name = os.getenv('CREDIT_DTC_QUEUE', 'dtc')
                    connection_string = os.getenv('CREDIT_AZURE_STORAGE_CONNECTION_STRING')
                    dtc_queue_client = QueueClient.from_connection_string(connection_string, dtc_queue_name)
                    dtc_queue_client.send_message(json.dumps({"report_id": report_id}))

                auth = AzureAuthenticator()
                user_info = auth.get_user_info()
                log_otherinfo = json.dumps(self.args, ensure_ascii=False)
                self.logger.async_log(user_info, log_otherinfo, log_action_party=f"User_{user_info.get('user_id', '')}", function_group="Assessment", function_name="Manual Edit")

            return jsonify(code=200, msg='success', data={'report_id': report_id})
        except Exception as e:
            print(traceback.print_exc(e))
            return jsonify(code=500, msg=str(e), data={})

