def get_review_dates(initial_time, next_credit_review):
    try:
        create_time_date = datetime.fromtimestamp(initial_time)
        initial_assess_end_date = (create_time_date + relativedelta(months=1, day=1)) - relativedelta(days=1)
        last_review_date = initial_assess_end_date.strftime('%Y-%m-%d')
    except ValueError:
        last_review_date = datetime.now().strftime('%Y-%m-%d')

    if next_credit_review:
        try:
            date_obj = parse_date(next_credit_review)
            next_review_date_obj = (date_obj + relativedelta(months=1, day=1)) - relativedelta(days=1)
            next_review_date = next_review_date_obj.strftime("%Y-%m-%d")
        except ValueError:
            next_review_date = datetime.now().strftime('%Y-%m-%d')
    else:
        next_review_date_obj = initial_assess_end_date + relativedelta(months=12)
        next_review_date = next_review_date_obj.strftime('%Y-%m-%d')

    return last_review_date, next_review_date

