        try:
            parent_customer_code = self.args.get('parent_customer_code')
            location_type = self.args.get('location_type', 'offshore')
            max_version = 0
            report_id = 0
            review_id = 0
            market_type = 'existing'

            if not parent_customer_code:
                return jsonify(code=403, msg='missing parent_customer_code parameter.', data={})

            if parent_customer_code.isalpha():
                parent_customer_code = parent_customer_code.upper()
            auth = AzureAuthenticator()
            user_info = auth.get_user_info()
            report_ids = []
            with get_db() as db_session:
                query = text(
                    "SELECT id, assessment_status,location_type,version FROM credit_report WHERE p_cust_code = :p_cust_code and market_type = :market_type")
                rows = db_session.execute(query,
                                          {'p_cust_code': parent_customer_code, 'market_type': market_type}).fetchall()
                is_exists = False
                is_in_progress = False
                has_failed_record = False
                for row in rows:
                    report_ids.append(row.id)
                    if row.assessment_status == 2:
                        if row.version > max_version:
                            max_version = row.version
                        if row.location_type == location_type:
                            is_exists = True
                    if row.assessment_status in [1, 4]:
                        is_in_progress = True
                    if row.assessment_status == 3:
                        has_failed_record = True

                if is_exists:
                    return jsonify(code=500,
                                   msg=f'The company with {parent_customer_code} parent customer code already exists, please Re-Assess the operation.',
                                   data={})
                if is_in_progress:
                    return jsonify(code=500,
                                   msg=f'The current parent_customer_code: {parent_customer_code} is still in progress, please refresh the page later to view the list.',
                                   data={})

                if has_failed_record:
                    db_session.execute(
                        text(
                            "DELETE FROM credit_report WHERE p_cust_code = :p_cust_code AND assessment_status = 3 and market_type = :market_type"),
                        {'p_cust_code': parent_customer_code, 'market_type': market_type})
                    if report_ids:
                        placeholders = ', '.join(f":id_{i}" for i in range(len(report_ids)))
                        query = text(f"DELETE FROM credit_report_review WHERE report_id IN ({placeholders})")
                        params = {f"id_{i}": rid for i, rid in enumerate(report_ids)}
                        db_session.execute(query, params)
                    db_session.commit()

                current_time = int(datetime.now().timestamp())
                query = text(
                    "INSERT INTO credit_report (p_cust_code, ctime, utime, trigger_status, version, assessment_status, xdata, market_type, ticker_code, listing_status, location_type) VALUES (:p_cust_code, :ctime, :utime, :trigger_status, :version, :assessment_status, :xdata, :market_type, :ticker_code, :listing_status, :location_type) RETURNING id ")
                params = {'p_cust_code': parent_customer_code, 'ctime': current_time, 'utime': current_time,
                          'trigger_status': 1, 'version': max_version + 1, 'assessment_status': 1, 'xdata': '{}',
                          'market_type': market_type, 'ticker_code': '', 'listing_status': 'listed',
                          'location_type': location_type}
                res = db_session.execute(query, params)
                report_id = res.scalar()
                db_session.commit()
                if report_id:
                    query = text("""
                                 INSERT INTO credit_report_review (report_id, review_status, reviewer, reviewer_email, review_time)
                                 VALUES (:report_id, :review_status, :reviewer, :reviewer_email,
                                         :review_time) RETURNING review_time
                                 """)
                    params = {'report_id': report_id, 'review_status': 1, 'reviewer': user_info['user_name'],
                              'reviewer_email': user_info['user_email'], 'review_time': current_time}
                    res = db_session.execute(query, params)
                    review_id = res.scalar()
                    db_session.commit()

            if report_id and review_id:
                req_data = {
                    'in_Company': parent_customer_code,
                    'in_RequesterName': user_info['user_name'],
                    'assessment_transaction_id': str(report_id),
                    'requestor_email_address': user_info['user_email'],
                    'market_type': market_type,
                    'location_type': location_type
                }
                connection_string = os.getenv('CREDIT_AZURE_STORAGE_CONNECTION_STRING')
                queue_name = os.getenv('CREDIT_UIPATH_QUEUE')
                queue_client = QueueClient.from_connection_string(connection_string, queue_name)
                message_content = json.dumps(req_data)
                queue_client.send_message(message_content)
                log_otherinfo = json.dumps(self.args, ensure_ascii=False)
                self.logger.async_log(user_info, log_otherinfo, log_action_party=f"User_{user_info.get('user_id', '')}",
                                      function_group="Assessment", function_name="New Company")
                return jsonify(code=200, msg='success', data={})
            else:
                return jsonify(code=500, msg='failed to create report', data={})
        except Exception as e:
            print(traceback.print_exc())
            return jsonify(code=500, msg='failed to create report', data={})

