class ReportAssessAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('p_cust_code', type=str, location='values', required=True)
        self.parser.add_argument('location_type', type=str, location='values', required=False)
        self.parser.add_argument('is_workflow', type=int, location='values', required=False)
        self.args = self.parser.parse_args()
        self.logger = async_logger
        arg_kv = {}
        for k, v in self.args.items():
            if v is not None:
                arg_kv[k] = v
        self.args = arg_kv
        super(ReportAssessAPI, self).__init__()

    def post(self):
        parent_customer_codes = self.args.get('p_cust_code')
        location_type = self.args.get('location_type')
        is_workflow = self.args.get('is_workflow', 0)
        market_type = "existing"
        if not parent_customer_codes:
            return jsonify(code=403, msg='missing parent_customer_code parameter.', data={})
        parent_customer_codes_list = parent_customer_codes.split(',')
        user_info = {}
        try:
            if not is_workflow:
                auth = AzureAuthenticator()
                user_info = auth.get_user_info()
                if not user_info or not user_info['user_name']:
                    return jsonify(code=401, msg='Your session has expired. Please refresh the page.', data={})

            current_time = int(datetime.now().timestamp())
            with get_db() as session:
                query = text("""
                    SELECT id, assessment_status, xdata, trigger_status, company_name, parent_customer_id, p_cust_code, entity_id, version, location_type, reviewer, reviewer_email
                    FROM (
                        SELECT id, assessment_status, xdata, trigger_status, company_name, parent_customer_id, p_cust_code, entity_id, version, location_type, crr.reviewer_email, crr.reviewer,
                            ROW_NUMBER() OVER(PARTITION BY p_cust_code ORDER BY version DESC) as rn
                        FROM credit_report cr join credit_report_review crr on cr.id = crr.report_id
                        WHERE cr.p_cust_code = ANY(:parent_customer_codes)
                    ) t
                    WHERE rn = 1
                """)

                reports = session.execute(query, {'parent_customer_codes': parent_customer_codes_list}).fetchall()
                report_dict = {}
                for report in reports:
                    report_dict[report.p_cust_code] = {
                        'version': int(report.version),
                        'assessment_status': int(report.assessment_status),
                        'company_name': report.company_name,
                        'parent_customer_id': report.parent_customer_id,
                        'entity_id': report.entity_id if report.entity_id else 0,
                        'location_type': location_type if location_type in ['offshore','onshore'] else report.location_type,
                        'reviewer': report.reviewer,
                        'reviewer_email': report.reviewer_email
                    }

                in_progress_codes = []
                for p_cust_code in parent_customer_codes_list:
                    if p_cust_code in report_dict:
                        if int(report_dict[p_cust_code]['assessment_status']) == 1:
                            in_progress_codes.append(p_cust_code)

                if not is_workflow and in_progress_codes:
                    return jsonify(
                        code=500,
                        msg=f'The current parent_customer_codes: {"|".join(in_progress_codes)} are still in progress. Please wait to receive an email notification upon completion.',
                        data={}
                    )

                for p_cust_code in parent_customer_codes_list:
                    if p_cust_code in report_dict:
                        reviewer = report_dict[p_cust_code]['reviewer'] if is_workflow else user_info['user_name']
                        reviewer_email = report_dict[p_cust_code]['reviewer_email'] if is_workflow else user_info['user_email']
                        query = text(
                            "INSERT INTO credit_report (p_cust_code, company_name, assessment_time, ctime, utime, version, trigger_status, assessment_status, xdata, market_type, ticker_code, listing_status, parent_customer_id, entity_id, location_type) VALUES (:p_cust_code, :company_name, :assessment_time, :ctime, :utime, :version, :trigger_status, :assessment_status, :xdata, :market_type, :ticker_code, :listing_status, :parent_customer_id, :entity_id, :location_type) RETURNING id")
                        params = {'p_cust_code': p_cust_code, 'company_name': '', 'assessment_time': 0, 'ctime': current_time, 'utime': current_time,
                                  'version': report_dict[p_cust_code]['version'] + 1, 'trigger_status': 3, 'assessment_status': 1, 'xdata': '{}', 'market_type': market_type, 'ticker_code': '', 'listing_status': 'listed',
                                  'parent_customer_id': report_dict[p_cust_code]['parent_customer_id'], 'entity_id': report_dict[p_cust_code]['entity_id'], 'location_type': report_dict[p_cust_code]['location_type']}
                        res = session.execute(query, params)
                        report_id = res.scalar()
                        session.commit()
                        if report_id:
                            query = text("""
                                        INSERT INTO credit_report_review (report_id, review_status, reviewer, reviewer_email, review_time) 
                                        VALUES (:report_id, :review_status, :reviewer, :reviewer_email, :review_time) RETURNING review_time
                                    """)
                            params = {'report_id': report_id, 'review_status': 1, 'reviewer': reviewer,
                                      'reviewer_email': reviewer_email, 'review_time': current_time}
                            res = session.execute(query, params)
                            review_id = res.scalar()
                            session.commit()
                        if report_id and review_id:
                            req_data = {
                                'in_Company': p_cust_code,
                                'in_RequesterName': reviewer,
                                'assessment_transaction_id': str(report_id),
                                'requestor_email_address': reviewer_email,
                                'market_type': market_type,
                                'location_type': report_dict[p_cust_code]['location_type']
                            }
                            connection_string = os.getenv('CREDIT_AZURE_STORAGE_CONNECTION_STRING')
                            queue_name = os.getenv('CREDIT_UIPATH_QUEUE')
                            queue_client = QueueClient.from_connection_string(connection_string, queue_name)
                            message_content = json.dumps(req_data)
                            queue_client.send_message(message_content)
            if not is_workflow:
                log_otherinfo = json.dumps(self.args, ensure_ascii=False)
                self.logger.async_log(user_info, log_otherinfo, log_action_party=f"User_{user_info.get('user_id', '')}", function_group="Assessment", function_name="Re-assess")
            return jsonify(code=200, msg='success', data={})
        except Exception as e:
            print(traceback.print_exc(e))
            return jsonify(code=500, msg=str(e), data={})

