def get_credit_limit_info(row):
    credit_limit_data = row.xdata.get('credit_limit')
    if not credit_limit_data:
        return ('-', '-', 'No Data', '-')

    total = credit_limit_data.get('total', {})
    current_credit = total.get('current_credit_limit', '-')
    propose_credit = total.get('propose_credit', '-')

    if row.review_status == 2:
        review_time_str = '-'
        if row.review_time:
            review_time_str = datetime.utcfromtimestamp(row.review_time).strftime('%d %B %Y, %H:%M')
        return (propose_credit, '-', 'Approved', review_time_str)

    return (current_credit, propose_credit, 'Draft', '-')

