class ReportGetDetailAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('p_cust_code', type=str, location='values', required=True)
        self.parser.add_argument('report_id', type=int, location='values', required=True)
        self.args = self.parser.parse_args()
        arg_kv = {}
        for k, v in self.args.items():
            if v is not None:
                arg_kv[k] = v
        self.args = arg_kv
        super(ReportGetDetailAPI, self).__init__()

    def get(self):
        trigger_from_mapping = {
            1: 'Auto RPA',
            2: 'Excel Edit & Upload',
            3: 'Ad-hoc Request',
            4: 'Manual Edit'
        }
        p_cust_code = self.args.get('p_cust_code')
        report_id = self.args.get('report_id')
        if not p_cust_code or not report_id:
            return jsonify(code=403, msg='missing parent_customer_code and report_id parameter.', data={})

        attachments_instance = AttachmentsService()
        with get_db() as session:
            query = text("""
                        SELECT 
                            cr.id,cr.version,cr.xdata,cr.cm_page,cr.factsheet,cr.risk_rating,cr.company_name,cr.p_cust_code,cr.assessment_time,cr.assessment_status,
                            cr.trigger_status,cr.company_profile,cr.parent_customer_id,cr.entity_id,cr.location_type,crr.reviewer,crr.review_status,crr.review_time
                        FROM credit_report cr
                        JOIN credit_report_review crr
                        ON cr.id = crr.report_id
                        WHERE cr.p_cust_code = :p_cust_code and cr.assessment_status = 2
                    """)
            result_proxy = session.execute(query, {'p_cust_code': p_cust_code, 'report_id': report_id})
            Report = namedtuple('Report', result_proxy.keys())
            reports = [Report(*row) for row in result_proxy.fetchall()]
            report_ids = [row.id for row in reports]
            latest_report = {}
            assess_history_data = []
            attachment_report_ids = []
            has_approved_cm = 0
            parent_customer = ''
            parent_customer_id = 0
            if report_ids:
                pdf_attachments = attachments_instance.get_pdf_list(report_ids, container='credit-excel')
                attachment_report_ids = [item['report_id'] for item in pdf_attachments]

            for row in reports:
                credit_limit_info = get_credit_limit_info(row)
                assess_history = {
                    'report_id': row.id,
                    'version': row.version,
                    'assessment_date': datetime.fromtimestamp(row.assessment_time).strftime(
                        '%d %B %Y') if row.assessment_time else '-',
                    'assessment_status': 'Done' if row.assessment_status == 2 else 'Running',
                    'trigger_status': trigger_from_mapping.get(row.trigger_status, 'Auto RPA'),
                    'overall_risk_rating': row.xdata.get('customer_background', {}).get('current_risk_category', '-'),
                    'current_credit_limit': credit_limit_info[0],
                    'propose_credit_limit': credit_limit_info[1],
                    'reviewer': row.reviewer,
                    'review_status': credit_limit_info[2],
                    'last_approval_date': credit_limit_info[3],
                    'approver': row.xdata.get('credit_head', {}).get('name', ''),
                    'is_pdf_available': 1 if row.id in attachment_report_ids else 0,
                    'location_type': row.location_type
                }
                assess_history_data.append(assess_history)
                if not latest_report and row.xdata and report_id == int(row.id):
                    has_approved_cm = 1
                    parent_customer = row.company_name
                    parent_customer_id = row.parent_customer_id
                    latest_report['final_memo'] = row.xdata
                    customer_bg = row.xdata.get('customer_background', {})
                    risk_alert = customer_bg.get('risk_alert', '')
                    risk_category = customer_bg.get('risk_category', '')
                    if risk_alert == 'witch' and '(Watchlist)' not in risk_category:
                        latest_report['final_memo']['customer_background']['risk_category'] = risk_category + '(Watchlist)'

                    latest_report.update({
                        'reviewer': row.reviewer,
                        'version': row.version,
                        'entity_id': row.entity_id if row.entity_id else 0,
                        'last_review_date': datetime.utcfromtimestamp(row.review_time).strftime('%d %B %Y, %H:%M'),
                    })
                    if row.cm_page:
                        latest_report.update({
                            'cm_page': row.cm_page
                        })
                    if row.factsheet:
                        has_financial = has_financial_scores(row.risk_rating)
                        factsheet = replace_value_error_copy(row.factsheet)
                        row.factsheet.update({'has_financial': has_financial})
                        latest_report.update({
                            'factsheet': factsheet
                        })
                    if row.risk_rating:
                        risk_rating = replace_value_error_copy(row.risk_rating)
                        latest_report.update({
                            'risk_rating': risk_rating
                        })
                    if row.company_profile:
                        latest_report.update({
                            'company_profile': row.company_profile
                        })

        attachment_data = attachments_instance.get_list(report_id)

        if assess_history_data:
            assess_history_data.sort(key=lambda x: x['version'])

        data = copy.copy(latest_report)
        data['has_approved_cm'] = has_approved_cm
        data['assess_history'] = assess_history_data
        data['attachment'] = attachment_data if attachment_data else []
        data['subsidaries'] = SubsidiariesService().get_subsidiaries(parent_customer)
        data['subsidiaries'] = SubsidiariesService().get_subsidiaries_by_parent_id(parent_customer_id)
        if reports:
            return jsonify(code=200, msg='success', data=data)
        else:
            return jsonify(code=403, msg='Report not found', data={})

