class ReportDownloadAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('report_id', type=int, location='values', required=True)
        self.parser.add_argument('file_type', type=str, location='values', required=False)
        self.args = self.parser.parse_args()
        self.logger = async_logger
        arg_kv = {}
        for k, v in self.args.items():
            if v is not None:
                arg_kv[k] = v
        self.args = arg_kv
        super(ReportDownloadAPI, self).__init__()

    def get(self):
        report_id = self.args.get('report_id')
        file_type = self.args.get('file_type')
        auth = AzureAuthenticator()
        user_info = auth.get_user_info()

        if not report_id:
            return jsonify(code=403, msg='missing report_id parameter.', data={})
        if not file_type or file_type not in ['pdf', 'xlsx']:
            return jsonify(code=403, msg='Invalid or missing file_type parameter. It should be either "pdf" or "xlsx".', data={})

        try:
            connection_string = os.getenv('CREDIT_AZURE_STORAGE_CONNECTION_STRING')
            if file_type == 'pdf':
                mime_types = ['application/pdf']
            else:
                mime_types = ['application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                              'application/vnd.openxmlformats-officedocument.spreadsheetml.template']
            container = os.getenv('CREDIT_AZURE_STORAGE_CONTAINER_EXCEL')

            with get_db() as session:
                attachment_sql = """
                    SELECT blob_name,mime_type,filename
                    FROM credit_attachments
                    WHERE report_id = :report_id 
                    AND mime_type = ANY(:mime_types)
                    ORDER BY uploaded_time DESC
                    LIMIT 1
                """

                query = text(attachment_sql)
                params = {'report_id': report_id, 'mime_types': mime_types}
                row = session.execute(query, params).fetchone()
                if row:
                    blob_name = row[0]
                    mime_type = row[1]
                    filename = row[2]

            if not blob_name:
                return jsonify(code=404, msg='Resource does not exist.', data={})

            stream = download_blob_to_stream(connection_string, container, blob_name)

            log_otherinfo = json.dumps(self.args, ensure_ascii=False)
            self.logger.async_log(user_info, log_otherinfo, log_action_party=f"User_{user_info.get('user_id', '')}", function_group="Excel", function_name="Download")
            return send_file(stream, as_attachment=True, download_name=filename, mimetype=mime_type)
        except Exception as e:
            print(traceback.print_exc())
            return jsonify(code=500, msg=str(e), data={})

