class ReportUploadAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('p_cust_code', type=str, location='values', required=True)
        self.args = self.parser.parse_args()
        self.logger = async_logger
        arg_kv = {}
        for k, v in self.args.items():
            if v is not None:
                arg_kv[k] = v
        self.args = arg_kv
        super(ReportUploadAPI, self).__init__()

    def post(self):
        parent_customer_code = self.args.get('p_cust_code')
        if not parent_customer_code:
            return jsonify(code=403, msg='missing p_cust_code parameter.', data={})
        if 'file' not in request.files:
            return jsonify(code=403, msg='File does not exist.', data={})
        file = request.files['file']
        file_size = file.content_length
        if file.filename == '' or file_size is None:
            return jsonify(code=403, msg='No selected file.', data={})

        auth = AzureAuthenticator()
        user_info = auth.get_user_info()
        filename = secure_filename(file.filename)
        mime_type, _ = mimetypes.guess_type(filename)
        allowed_types = {'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                         'application/vnd.openxmlformats-officedocument.spreadsheetml.template'}
        if mime_type not in allowed_types:
            return jsonify(code=403, msg='Invalid file format. Please upload a file in .xlsx, .xltx',
                           data={})

        report_data = {}
        with get_db() as session:
            query = text("SELECT * FROM credit_report WHERE p_cust_code = :parent_customer_code ORDER BY version DESC limit 1")
            result_proxy = session.execute(query, {'parent_customer_code': parent_customer_code})
            Report = namedtuple('Report', result_proxy.keys())
            reports = [Report(*row) for row in result_proxy.fetchall()]
            if not reports:
                return jsonify(code=403, msg='This report does not exist.', data={})
            result = reports[0]

        ExtractorObj = ExcelExtractor()
        report_data['company_name'], report_data['final_memo'], report_data['cm_page'], report_data['factsheet'], report_data['risk_rating'] = ExtractorObj.extract_report_data(file)
        if parent_customer_code != report_data.get('cm_page', {}).get('credit_memorandum', {}).get('parent_code'):
            return jsonify(code=403,
                           msg='The uploaded excel should be consistent with the current report Parent Customer Group.',
                           data={})
        report_id = create_new_version(result, report_data, result.version, user_info)
        if not report_id:
            return jsonify(code=500, msg='failed to upload report.', data={})
        blob_name = f"{report_id}_{filename}"
        container_name = os.getenv('CREDIT_AZURE_STORAGE_CONTAINER_EXCEL')
        upload_to_azure_blob(file, mime_type, container_name, blob_name)
        save_attachment_to_db(report_id, mime_type, filename, file_size, container_name, blob_name, user_info['user_name'])
        parent_customer = report_data['company_name']

        subsidiaries = []
        if 'turnover_data' in report_data['cm_page']:
            for item in report_data['cm_page']['turnover_data']:
                siubsidiary = item.get('customer_name')
                if siubsidiary and siubsidiary != '(blank)':
                    subsidiaries.append(item.get('customer_name'))

        if not subsidiaries:
            subsidiaries = [parent_customer]

        if subsidiaries:
            parent_customer_id, has_updated = SubsidiariesService().save(parent_customer, subsidiaries, 'excel')
            if parent_customer_id:
                report_data['market_type'] = 'existing'
                report_data['p_cust_code'] = parent_customer_code
                report_data['ticker_code'] = ''
                ReportService().save_parent_customer(parent_customer_id, report_data)

        log_otherinfo = json.dumps(self.args, ensure_ascii=False)
        self.logger.async_log(user_info, log_otherinfo, log_action_party=f"User_{user_info.get('user_id', '')}",
                              function_group="Assessment", function_name="Excel Edit AND Upload")

        return jsonify(code=200, msg='success', data={})

