class SubsidiariesAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('report_id', type=int, location='json', required=True)
        self.parser.add_argument('manual_subsidaries', type=list, location='json', required=True)
        self.args = self.parser.parse_args()
        self.logger = async_logger
        arg_kv = {}
        for k, v in self.args.items():
            if v is not None:
                arg_kv[k] = v
        self.args = arg_kv
        super(SubsidiariesAPI, self).__init__()

    def _insert_recommendation_workflow(self, session, report_id, parent_customer_id, user_info):
        insert_query = text("""
            INSERT INTO credit_recommendation_workflow(report_id, triggered_from, status, parent_id, receiver, receiver_email)
            VALUES (:report_id, :triggered_from, :status, :parent_id, :receiver, :receiver_email)
        """)
        session.execute(insert_query, {
            'report_id': report_id,
            'triggered_from': 'edit_subsidiaries',
            'status': 'pending',
            'parent_id': parent_customer_id,
            'receiver': user_info['user_name'],
            'receiver_email': user_info['user_email'],
        })
        session.commit()

    def post(self):
        report_id = self.args.get('report_id')
        subsidiaries = list(set(self.args.get('manual_subsidaries') or []))
        auth = AzureAuthenticator()
        if not report_id:
            return jsonify(code=403, msg='missing report_id or manual_subsidiaries parameter.', data={})

        user_info = auth.get_user_info()
        try:
            with get_db() as session:
                query = text("SELECT company_name,market_type,ticker_code,p_cust_code,parent_customer_id FROM credit_report WHERE id = :report_id and assessment_status = 2")
                report = session.execute(query, {'report_id': report_id}).fetchone()
                if not report:
                    return jsonify(code=403, msg='This report does not exist.', data={})
                parent_customer = report[0]
                market_type = report[1]
                ticker_code = report[2]
                p_cust_code = report[3]
                if ticker_code and market_type == 'potential':
                    parent_customer = ticker_code + '_' + parent_customer
                parent_customer_id, has_updated = SubsidiariesService().save(parent_customer, subsidiaries, 'manual')
                if parent_customer_id:
                    report_data = {
                        'company_name': report[0],
                        'market_type': market_type,
                        'p_cust_code': p_cust_code,
                        'ticker_code': ticker_code
                    }
                    ReportService().save_parent_customer(parent_customer_id, report_data)
                if has_updated:
                    self._insert_recommendation_workflow(session, report_id, parent_customer_id, user_info)

                log_otherinfo = json.dumps(self.args, ensure_ascii=False)
                self.logger.async_log(user_info, log_otherinfo, log_action_party=f"User_{user_info.get('user_id', '')}", function_group="Subsidiaries", function_name="Edit Subsidiary")
            return jsonify(code=200, msg='success', data={'s_id': parent_customer_id})
        except Exception as e:
            print(traceback.print_exc(e))
            return jsonify(code=500, msg=str(e), data={})

