class SupportingDocumentsAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('report_id', type=str, location='values', required=False)
        self.args = self.parser.parse_args()
        arg_kv = {}
        for k, v in self.args.items():
            if v is not None:
                arg_kv[k] = v
        self.args = arg_kv
        super(SupportingDocumentsAPI, self).__init__()

    def post(self):
        report_id = self.args.get('report_id')
        if 'file' not in request.files:
            return jsonify(code=403, msg='File does not exist.', data={})
        file = request.files['file']
        file_size = file.content_length
        if file.filename == '':
            return jsonify(code=403, msg='No selected file.', data={})
        if file_size == 0:
            file.seek(0)
            content = file.read()
            file_size = len(content)
        if not file_size:
            return jsonify(code=403, msg='File size cannot be empty.', data={})
        auth = AzureAuthenticator()
        user_info = auth.get_user_info()
        full_filename = secure_filename(file.filename)
        filename, file_extension = os.path.splitext(full_filename)
        mime_type, _ = mimetypes.guess_type(full_filename)
        allowed_types = {'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                         'application/pdf'}
        if mime_type not in allowed_types:
            return jsonify(code=403, msg='Invalid file format. Please upload a file in .xlsx and .pdf format.',
                           data={})

        with get_db() as session:
            sql = """
                    SELECT id FROM credit_report
                    WHERE id = :report_id and assessment_status = 2 LIMIT 1           
            """
            query = text(sql)
            params = {'report_id': report_id}
            result = session.execute(query, params).fetchone()
            if not result:
                return jsonify(code=403, msg='This report does not exist.', data={})

        now = datetime.now()
        blob_name = f"{report_id}_{filename}_" + now.strftime('%Y%m%d%H%M%S') + file_extension
        container_name = 'supporting-documents'
        upload_to_azure_blob(file, mime_type, container_name, blob_name)
        aid = save_attachment_to_db(report_id, mime_type, full_filename, file_size, container_name, blob_name, user_info['user_name'])
        today_date = datetime.now().strftime('%d %B %Y')
        data = {
            'aid': aid,
            'filename': full_filename,
            'file_size': str(round(file_size / (1024 * 1024), 1)) + 'MB',
            'uploaded_by': user_info['user_name'],
            'date': today_date
        }
        return jsonify(code=200, msg='success', data=data)

