def get_ticker_list(q=''):
    items = []
    try:
        url = f"https://query2.finance.yahoo.com/v1/finance/search?q={q}&lang=en-US&region=US&quotesCount=10&listsCount=2&enableFuzzyQuery=false&quotesQueryId=tss_match_phrase_query&multiQuoteQueryId=multi_quote_single_token_query&newsQueryId=news_cie_vespa&enableCb=true&enableNavLinks=true&enableEnhancedTrivialQuery=true&enableResearchReports=true&enableCulturalAssets=true&enableLogoUrl=true&recommendCount=10"
        headers = {
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/116.0.5845.110 Safari/537.36'
        }
        response = requests.get(url, headers=headers)
        if response.status_code == 200:
            data = response.json()
            for quote in data['quotes']:
                if 'symbol' in quote and 'shortname' in quote:
                    items.append({
                        'ticker_code': quote['symbol'],
                        'company_name': quote['shortname']
                    })
        else:
            print(f"Request failed, status code: {response.status_code}")
    except Exception as e:
        print(e)
    return items

