class UserAccessAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('role_debug', location='args', required=False)
        self.args = self.parser.parse_args()
        self.args = {k: v for k, v in self.args.items() if v is not None}
        super(UserAccessAPI, self).__init__()

    def get(self):
        role_debug = self.args.get('role_debug')
        role_id = session.get("role_id", 0)
        role = session.get('role', 'guest')
        user_id = session.get('user_id')
        permissions_cache = session.get('permissions')
        permissions = {
            'allowed_pages': [],
            'actions_map': {}
        }

        if not role_id or not permissions_cache or not role:
            if role_id:
                with get_db() as db_session:
                    query = text("SELECT role_name FROM public.credit_roles WHERE id = :role_id")
                    role_record = db_session.execute(query, {'role_id': role_id}).fetchone()
                    if not role_record:
                        return False
                    role = role_record[0]
                    allowed_pages, actions_map = get_allowed_pages_and_actions_for_role(role_id)
                    permissions = {
                        'allowed_pages': allowed_pages,
                        'actions_map': actions_map
                    }
                    session['permissions'] = permissions
                    session['role'] = role

        else:
            permissions = permissions_cache

        if role_debug:
            role = role_debug
            with get_db() as db_session:
                query = text("SELECT id FROM public.credit_roles WHERE role_name = :role_name")
                role_record = db_session.execute(query, {'role_name': role}).fetchone()
                if role_record:
                    role_id = role_record[0]
                    allowed_pages, actions_map = get_allowed_pages_and_actions_for_role(role_id)
                    permissions = {
                        'allowed_pages': allowed_pages,
                        'actions_map': actions_map
                    }

        if user_id:
            user_filters = session.get('user_filters')
            if user_filters is None:
                with get_db() as db_session:
                    filters_query = text(
                        "SELECT filter_name, filters FROM public.credit_filters WHERE user_id = :user_id")
                    filters_result = db_session.execute(filters_query, {'user_id': user_id}).fetchall()
                    user_filters = [{'name': row[0], 'params': row[1]} for row in filters_result if row[1] != {}]
                    session['user_filters'] = user_filters
        else:
            user_filters = []

        return jsonify(code=200, msg='Success', data={
            'role': role,
            'permissions': permissions,
            'filters': user_filters,
            'app_env': os.getenv('APP_ENV', 'uat')
        })

