class WorkflowApiChecker(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.parser.add_argument('sign', location='args', required=True)
        self.args = self.parser.parse_args()
        self.args = {k: v for k, v in self.args.items() if v is not None}
        super(WorkflowApiChecker, self).__init__()

    def get(self):
        try:
            sign = self.args.get('sign')
            if gen_sign(self.args) != sign:
                return jsonify(code=401, msg='Invalid token, please check.', data={})
            today = datetime.datetime.now(ZoneInfo("Asia/Shanghai")).date()
            utc_tz = pytz.UTC
            utc_now = datetime.datetime.now(utc_tz)
            start_time = utc_now - datetime.timedelta(hours=24)
            start_time_str = start_time.strftime("%Y-%m-%d %H:%M:%S.000")

            with get_db() as session:
                query = text("SELECT * FROM public.credit_recommendation_workflow where status in ('pending', 'crawling') ORDER BY created_at ASC")
                result_proxy = session.execute(query)
                WorkflowObj = namedtuple('Workflow', result_proxy.keys())
                workflow_rows = [WorkflowObj(*row) for row in result_proxy.fetchall()]
                if not workflow_rows:
                    return jsonify(code=200, msg='success', data={})

            workflows_to_update = []
            messages_to_enqueue = []

            for workflow in workflow_rows:
                triggered_from = workflow.triggered_from
                status = workflow.status
                workflow_id = workflow.id
                report_id = workflow.report_id
                parent_id = workflow.parent_id

                workflow_status = None
                if triggered_from in ['new_company', 'edit_subsidiaries', 'excel_reassess']:
                    crawl_complete = False
                    keywords_rows = []
                    with get_db() as session:
                        query = text("SELECT * FROM credit_subsidiary_keywords where parent_customer_id = :parent_id")
                        result_proxy = session.execute(query, {'parent_id': parent_id})
                        KeywordsObj = namedtuple('Keywords', result_proxy.keys())
                        keywords_rows = [KeywordsObj(*row) for row in result_proxy.fetchall()]

                    valid = True
                    if keywords_rows:
                        subsidiary_ids = [item.id for item in keywords_rows]
                        for item in keywords_rows:
                            try:
                                last_sync_date = datetime.datetime.strptime(item.last_sync_date, '%Y-%m-%d').date()
                            except Exception as e:
                                valid = False
                                break
                            if last_sync_date != today or item.last_sync_year != today.year + 1:
                                valid = False
                                break

                        if valid:
                            with get_db() as session:
                                placeholders = ', '.join(f":id_{i}" for i in range(len(subsidiary_ids)))
                                query = text(f"""
                                    select * from credit_google_news
                                    where status = 'google_fetched'
                                    and subsidiary_id in ({placeholders})
                                    and google_published_date < :google_published_date_str
                                    limit 1
                                """)
                                params = {f"id_{i}": sid for i, sid in enumerate(subsidiary_ids)}
                                params['google_published_date_str'] = start_time_str

                                result_proxy = session.execute(query, params)
                                NewsObj = namedtuple('News', result_proxy.keys())
                                news_rows = [NewsObj(*row) for row in result_proxy.fetchall()]
                                if news_rows:
                                    valid = False

                    if valid:
                        crawl_complete = True

                    if crawl_complete:
                        workflow_status = 'drafting'
                    elif status != 'crawling':
                        workflow_status = 'crawling'

                elif triggered_from in ['ai_reassess']:
                    workflow_status = 'drafting'

                if workflow_status and workflow_status != status:
                    workflows_to_update.append((workflow_status, workflow_id))
                if workflow_status == 'drafting':
                    messages_to_enqueue.append(report_id)

            if workflows_to_update:
                with get_db() as session:
                    for workflow_status, workflow_id in workflows_to_update:
                        update_query = text(
                            "UPDATE credit_recommendation_workflow SET status = :workflow_status, updated_at = CURRENT_TIMESTAMP WHERE id = :id")
                        session.execute(update_query, {'workflow_status': workflow_status, 'id': workflow_id})
                    session.commit()

            if messages_to_enqueue:
                connection_string = os.getenv('CREDIT_AZURE_STORAGE_CONNECTION_STRING')
                queue_name = os.getenv('CREDIT_JOB_QUEUE', 'aidrafting')
                queue_client = QueueClient.from_connection_string(connection_string, queue_name)
                for report_id in messages_to_enqueue:
                    message_content = json.dumps({"report_id": report_id})
                    queue_client.send_message(message_content)

            return jsonify(code=200, msg='success', data={})
        except Exception as e:
            print(traceback.print_exc(e))
            return jsonify(code=500, msg=str(e), data={})

