class WorkflowReassessAPI(Resource):
    def __init__(self):
        self.parser = reqparse.RequestParser(bundle_errors=True)
        self.args = self.parser.parse_args()
        self.args = {k: v for k, v in self.args.items() if v is not None}
        super(WorkflowReassessAPI, self).__init__()

    def get(self):
        today = datetime.today()

        tomorrow = today.replace(day=today.day) + timedelta(days=1)
        if tomorrow.month == today.month:
            return jsonify(code=201, msg='success', data={})

        current_year_short = today.year % 100
        next_review_date = today.strftime('%b-') + str(current_year_short)

        with get_db() as session:
            sql = text(f"""
                SELECT p_cust_code FROM (
                    SELECT *,
                    ROW_NUMBER() OVER (PARTITION BY p_cust_code ORDER BY version DESC) as rn
                    FROM public.credit_report
                    WHERE assessment_status = 2
                    AND market_type = 'existing'
                    AND xdata->'customer_background'->>'next_credit_review' = :next_review_date
                ) t
                WHERE t.rn = 1 limit 2
            """)
            result = session.execute(sql, {'next_review_date': next_review_date})
            p_cust_codes = [row.p_cust_code for row in result]
            if p_cust_codes:
                try:
                    host = os.environ.get("CUSTOM_HOST")
                    url = f"{host}/api/reassess"
                    data = {
                        'p_cust_code': ",".join(p_cust_codes),
                        'location_type': 'onshore',
                        'is_workflow': 1
                    }
                    requests.post(url, data=data)
                except Exception as e:
                    print(traceback.print_exc())

        return jsonify(code=200, msg='success', data=p_cust_codes)

