def calculate_generated_score(risk_rating):

    def sum_factor_weightings(field, data):
        total = 0
        if isinstance(data, dict):
            for key, value in data.items():
                if key == field and isinstance(value, (int, float)):
                    total += value
                elif isinstance(value, dict):
                    total += sum_factor_weightings(field, value)
                elif isinstance(value, list):
                    for item in value:
                        total += sum_factor_weightings(field, item)
        return total

    total_weight = sum_factor_weightings("weight", risk_rating)
    total_factor_weighting = sum_factor_weightings("factor_weighting", risk_rating)

    if total_factor_weighting >= 76:
        gen_score = "A"
    elif total_factor_weighting >= 51:
        gen_score = "B"
    elif total_factor_weighting >= 31:
        gen_score = "C"
    else:
        gen_score = "D"

    return gen_score, round_half_up(total_factor_weighting), round_half_up(total_weight)

