def update_credit_report(created_report_id, final_memo = None, risk_rating = None, company_profile = None):
    try:
        current_time = int(datetime.now().timestamp())
        with get_db() as session:
            query = "UPDATE credit_report SET assessment_status = 2, assessment_time = :assessment_time"
            params = {
                'report_id': created_report_id,
                'assessment_time': current_time
