class DTCManager:
    def __init__(self, company_name, final_memo, company_profile, risk_rating, factsheet, credit_memo_link):
        self.company_name = company_name
        self.final_memo = final_memo or {}
        if not isinstance(self.final_memo, dict):
            self.final_memo = {}

        self.company_profile = company_profile or {}
        if not isinstance(self.company_profile, dict):
            self.company_profile = {}

        self.risk_rating = risk_rating or {}
        if not isinstance(self.risk_rating, dict):
            self.risk_rating = {}

        self.factsheet = factsheet or {}
        if not isinstance(self.factsheet, dict):
            self.factsheet = {}

        self.credit_memo_link = credit_memo_link
        self.dtc_api_key = os.getenv("DTC_API_KEY")
        dtc_sheet_ids_str = os.getenv("DTC_SHEET_ID", "68a3fadfcd986789cebdb499")
        self.dtc_sheet_ids = [s.strip() for s in dtc_sheet_ids_str.split(",") if s.strip()]
        dtc_view_ids_str = os.getenv("DTC_VIEW_ID", "68a3f98bcd986789cebdb496")
        self.dtc_view_ids = [v.strip() for v in dtc_view_ids_str.split(",") if v.strip()]

        max_len = max(len(self.dtc_sheet_ids), len(self.dtc_view_ids))
        if len(self.dtc_sheet_ids) < max_len:
            self.dtc_sheet_ids += [self.dtc_sheet_ids[-1]] * (max_len - len(self.dtc_sheet_ids))
        if len(self.dtc_view_ids) < max_len:
            self.dtc_view_ids += [self.dtc_view_ids[-1]] * (max_len - len(self.dtc_view_ids))

        self.headers = {
            "Content-Type": "application/json",
            "x-api-key": self.dtc_api_key
        }

    def fmt_date_str(self, date_str, out_format="%d-%b-%Y"):
        if not date_str:
            return ''
        try:
            dt = datetime.strptime(date_str, "%b-%y")
            year = dt.year
            if year < 100:
                year += 2000
            dt = dt.replace(year=year)
        except ValueError:
            try:
                dt = datetime.strptime(date_str, "%Y-%m-%d")
            except ValueError:
                try:
                    dt = datetime.strptime(date_str, "%Y-%m-%dT%H:%M:%S.%fZ")
                except Exception:
                    return ''
        return dt.strftime(out_format)

    def get_dtc_url(self, sheet_id, view_id):
        return f"https://dtc-api.lfapps.net/api/v1/sheets/{sheet_id}/views/{view_id}"

    def fetch_sheet_data(self, sheet_id=None, view_id=None):
        if sheet_id is None or view_id is None:
            sheet_id = self.dtc_sheet_ids[0]
            view_id = self.dtc_view_ids[0]
        dtc_url = self.get_dtc_url(sheet_id, view_id)
        try:
            response = requests.get(dtc_url, headers=self.headers, timeout=60)
            if response.status_code == 200:
                return response.json().get("sheetData", [])
            else:
                print(f"Failed to fetch DTC sheet data (sheet: {sheet_id} view: {view_id}): {response.status_code} {response.text}")
                return []
        except Exception as e:
            print(f"Exception while fetching DTC sheet data (sheet: {sheet_id} view: {view_id}): {e}")
            return []

    def prepare_entry(self, sheet_data=None):
        if sheet_data is None:
            sheet_data = self.fetch_sheet_data()
        matched_row = None
        used_indices = set()
        for row in sheet_data:
            if row.get("Company Name") == self.company_name:
                matched_row = row
            try:
                idx = int(row.get("rowIndex", 1))
                used_indices.add(idx)
            except Exception:
                continue

        max_index = max(used_indices) if used_indices else 0
        next_index = None
        for i in range(1, max_index):
            if i not in used_indices:
                next_index = i
                break
        if next_index is None:
            next_index = max_index + 1

        row_index = matched_row.get("rowIndex", next_index) if matched_row else next_index
        now_str = datetime.utcnow().strftime("%d-%b-%Y")
        risk_category_raw = self.final_memo.get("customer_background", {}).get("risk_category", "")
        risk_category = re.sub(r"\s*\(WATCHLIST\)", "", risk_category_raw).strip()
        credit_comments_title = self.final_memo.get("recommendations_title", "")
        recommendations = self.final_memo.get("recommendations", [])
        credit_comments = "\n".join([rec for rec in recommendations if rec])
        main_business_location = self.final_memo.get("customer_background", {}).get("main_business_location", "")
        if not main_business_location or main_business_location == "(Invalid Identifier)":
            head_office = self.company_profile.get('head_office', '')
            if head_office:
                main_business_location = head_office
        if credit_comments:
            credit_comments = re.sub(r'【.*?】', '', credit_comments).strip()
        if main_business_location:
            main_business_location = re.sub(r'【.*?】', '', main_business_location).strip()

        risk_alert_raw = self.final_memo.get("customer_background", {}).get("risk_alert", "")
        risk_alert_map = {
            "low": "Low",
            "mid-high": "Mid to High",
            "witch": "WATCHLIST",
            "high": "High"
        }
        risk_alert = risk_alert_map.get(risk_alert_raw, "Low")
        next_credit_review_date_raw = self.final_memo.get("customer_background", {}).get("next_credit_review")
        if next_credit_review_date_raw:
            next_credit_review_date = self.fmt_date_str(next_credit_review_date_raw)
        else:
            next_credit_review_date = datetime.now().strftime("%d-%b-%Y")

        financial_scores = self.risk_rating.get("financial_scores", {})
        revenue_value = financial_scores.get("revenue_size", {}).get("value", 0)
        try:
            revenue_size = float(revenue_value)
        except (ValueError, TypeError):
            revenue_size = 0

        annual_periods = self.factsheet.get('annual', {}).get('period', [])
        ebt = 0
        net_profit = 0

        if annual_periods:
            last_annual_key = annual_periods[-1]
            annual_data = self.factsheet.get('annual', {}).get('data', {})
            ebt = convert_to_float(annual_data.get(last_annual_key, {}).get('EBT', 0))
            net_profit = convert_to_float(annual_data.get(last_annual_key, {}).get('Profit/(Loss) After tax', 0))

        final_memo_ratings_str = self.final_memo.get("customer_background", {}).get("rating", "")
        sp_rating = ""
        dtc_moody = ""

        if final_memo_ratings_str:
            parts = final_memo_ratings_str.split(";")
            for part in parts:
                part = part.strip()
                if "(Invalid Identifier)" in part:
                    sp_rating, dtc_moody = "", ""
                    break
                if part.startswith("Moody's:"):
                    dtc_moody = part.replace("Moody's:", "").strip()
                    dtc_moody = re.sub(r'【.*?】', '', dtc_moody).strip()
                elif part.startswith("S&P:"):
                    sp_rating = part.replace("S&P:", "").strip()
                    sp_rating = re.sub(r'【.*?】', '', sp_rating).strip()

        sp_rating = sp_rating if sp_rating else ""

        data = {
            "rowIndex": row_index,
            "Date of Assessment": now_str,
            "Company Name": self.company_name,
            "S&P Rating": sp_rating,
            "Head Office Country": main_business_location,
            "Financial Date": next_credit_review_date,
            "Revenue in USD mil": revenue_size,
            "EBT before One-Off in USD mil": ebt,
            "Net Profit in USD mil": net_profit,
            "Risk Level": risk_alert,
            "LF Risk Category": risk_category,
            "Credit Comments/Remarks": credit_comments_title,
            "Prospect Credit Scan":credit_comments,
            "Hyperlink": self.credit_memo_link
        }
        if dtc_moody:
            data['Moody’s rating'] = dtc_moody

        return data

    def update_sheet(self):
        for sheet_id, view_id in zip(self.dtc_sheet_ids, self.dtc_view_ids):
            dtc_url = self.get_dtc_url(sheet_id, view_id)
            try:
                sheet_data = self.fetch_sheet_data(sheet_id, view_id)
                entry = self.prepare_entry(sheet_data=sheet_data)
                patch_data = {"sheetData": [entry]}
                patch_response = requests.patch(dtc_url, json=patch_data, headers=self.headers, timeout=60)
                if patch_response.status_code not in [200, 204]:
                    print(f"Failed to update DTC sheet data (sheet: {sheet_id} view: {view_id}): {patch_response.status_code} {patch_response.text}")
                    print(sheet_data)
            except Exception as e:
                print(f"Exception while updating DTC sheet data (sheet: {sheet_id} view: {view_id}): {e}")

