class EntityHierarchyService:
    def get_all_related_entities(self, ids):
        with get_db() as session:
            rows = session.execute(
                text("SELECT entity_id, parent_company_id FROM credit_entity_hierarchy")).fetchall()

        parent_to_children = {}
        child_to_parent = {}

        for entity_id, parent_id in rows:
            if parent_id is not None:
                parent_to_children.setdefault(parent_id, set()).add(entity_id)
            child_to_parent[entity_id] = parent_id

        all_ids = set(ids)
        queue = list(ids)

        while queue:
            current_id = queue.pop()

            parent_id = child_to_parent.get(current_id)
            if parent_id and parent_id not in all_ids:
                all_ids.add(parent_id)
                queue.append(parent_id)

            for child_id in parent_to_children.get(current_id, []):
                if child_id not in all_ids:
                    all_ids.add(child_id)
                    queue.append(child_id)

        return list(all_ids)

    def get_hierarchy_by_entity_ids(self, entity_ids):
        if entity_ids is None or not entity_ids:
            return []

        all_entity_ids = self.get_all_related_entities(entity_ids)
        query = """
            SELECT 
                e.entity_id,
                e.entity_name,
                e.ticker,
                e.ciq_id,
                h.parent_company_id
            FROM credit_entities e
            LEFT JOIN credit_entity_hierarchy h ON e.entity_id = h.entity_id
            WHERE e.entity_id = ANY(:entity_ids)
        """

        with get_db() as session:
            proxy = session.execute(text(query), {'entity_ids': all_entity_ids})
            rows = proxy.mappings().all()

        entities = {}
        children_map = {}
        child_to_parent = {}

        for row in rows:
            entity_id = row['entity_id']
            entities[entity_id] = {
                'entity_id': entity_id,
                'name': row['entity_name'],
                'ticker': row['ticker'],
                'ciq_id': row['ciq_id'],
                'children': [],
                'level': None
            }
            parent_id = row['parent_company_id']
            child_to_parent[entity_id] = parent_id

            if parent_id is not None:
                children_map.setdefault(parent_id, set()).add(entity_id)

        for key in children_map:
            children_map[key] = list(children_map[key])

        def find_root(entity_id):
            current = entity_id
            visited = set()
            while True:
                if current in visited:
                    break
                visited.add(current)
                parent = child_to_parent.get(current)
                if parent is None or parent not in entities:
                    break
                current = parent
            return current

        roots = set(find_root(eid) for eid in entity_ids if eid in entities)

        valid_nodes = set()

        def mark_path_to_entity(root, target, path):
            if root == target:
                valid_nodes.update(path + [root])
                return True
            for child in children_map.get(root, []):
                if child in path:
                    continue
                if mark_path_to_entity(child, target, path + [root]):
                    valid_nodes.add(root)
                    return True
            return False

        for eid in entity_ids:
            for root in roots:
                if mark_path_to_entity(root, eid, []):
                    break

        def add_descendants(node):
            valid_nodes.add(node)
            for child in children_map.get(node, []):
                add_descendants(child)

        for node in list(valid_nodes):
            add_descendants(node)

        def build_tree(entity_id, level=1, visited=None):
            if visited is None:
                visited = set()
            if entity_id in visited:
                return None
            if entity_id not in valid_nodes:
                return None
            visited.add(entity_id)

            node = entities[entity_id]
            node['level'] = level
            children_nodes = []
            for child_id in children_map.get(entity_id, []):
                child_node = build_tree(child_id, level + 1, visited)
                if child_node is not None:
                    children_nodes.append(child_node)
            node['children'] = children_nodes
            return node

        hierarchy = []
        visited_global = set()
        for root_id in roots:
            node = build_tree(root_id, 1, visited_global)
            if node is not None:
                hierarchy.append(node)

        return hierarchy

