def determine_risk_category(rgb):
    if isinstance(rgb, str) and len(rgb) >= 8:
        rgb = rgb[2:]
    else:
        print("Invalid RGB format:", rgb)
        return ""
    r = int(rgb[0:2], 16)
    g = int(rgb[2:4], 16)
    b = int(rgb[4:6], 16)

    if r < 128 and g >= 128 and b < 128:
        return "low"
    elif r >= 128 and g >= 128 and b < 128:
        if g > r:
            return "low"
        elif r == 255 and g == 192 and b == 0:
            return "mid-high"
        else:
            return "witch"
    elif r >= 128 and g < 128 and b < 128:
            return "high"
    return ""

