                if key is None or key in missed_keys:
                    continue
                # key = key.strip().lower().replace(" ", "_").replace("/", "_").replace("&", "and") + ('_' if not (key.startswith("(") or key.endswith(")")) else '')
                values = []
                for index in value_columns_indices:
                    value = '' if row[index] is None else row[index]
                    if isinstance(value, (int, float)):
                        if index in [6, 14]:
                            value = f"{round(value * 100):.0f}%"
                        elif ('%' in key or key in percentage_format_keys):
                            value = f"{value * 100:.1f}%".format(value)
                        elif key in round_format_keys:
                            value = f"{round(value):.0f}"
                        else:
                            value = f"({abs(value):.1f})" if value < 0 else f"{value:.1f}"

                    if value == '0.0':
                        value = '-'

                    values.append(value)
                content[key] = values

            parts = sheet['B6'].value.split(":")
            financial_summary_source = parts[1] if len(parts) > 1 else ''
            data = {
                'parent_customer': sheet['D4'].value,
                'financial_summary_source': financial_summary_source,
                'annual': {'period': extract_factsheet_header(sheet, min_col=4, max_col=6), 'data': {}, 'headers': sheet['D5'].value},
                'semiannual': {'period': extract_factsheet_header(sheet, min_col=13, max_col=14), 'data': {}, 'headers': sheet['I5'].value},
            }

            for idx, date in enumerate(data['annual']['period']):
                data['annual']['data'][date] = {key: content[key][idx] for key in content}
            for idx, date in enumerate(data['semiannual']['period']):
                data['semiannual']['data'][date] = {key: content[key][idx + 4] for key in content}
            data['annual']['data']['annual_yoy'] = {key: content[key][3] for key in content}
            data['semiannual']['data']['semiannual_yoy'] = {key: content[key][6] for key in content}

        return data
    except Exception as e:
        print(traceback.print_exc())
        return None

