class ReportService:

    def save_parent_customer(self, parent_customer_id, report_data):
        has_updated = False
        try:
            if not report_data['company_name'] or not report_data['market_type']:
                return parent_customer_id
            base_query = "UPDATE credit_report SET parent_customer_id = {parent_customer_id} WHERE assessment_status in (1,2,4) ".format(
                    parent_customer_id=str(parent_customer_id))
            conditions = []
            params = {}
            if report_data['market_type'] == 'existing' and report_data['p_cust_code']:
                conditions.append("p_cust_code = :p_cust_code")
                params['p_cust_code'] = report_data['p_cust_code']
            elif report_data['market_type'] == 'potential':
                if report_data['ticker_code']:
                    conditions.append("ticker_code = :ticker_code")
                    params['ticker_code'] = report_data['ticker_code']
                else:
                    conditions.append("listing_status = :listing_status")
                    params['listing_status'] = 'non-listed'

            if conditions:
                has_updated = True
                conditions.append("company_name = :company_name")
                params['company_name'] = report_data['company_name']
                conditions.append("market_type = :market_type")
                params['market_type'] = report_data['market_type']
                base_query += " AND " + " AND ".join(conditions)
                with get_db() as session:
                    query = text(base_query)
                    session.execute(query, params)
                    session.commit()

        except Exception:
            print(traceback.print_exc())

        return has_updated

