class SubsidiariesService:

    def save(self, parent_customer, subsidiaries, source):
        has_updated = False
        try:
            with get_db() as session:
                query = text(
                    "SELECT id FROM credit_parent_customers WHERE customer_name = :customer_name")
                parent_customers_res = session.execute(query, {'customer_name': parent_customer}).fetchone()
                if parent_customers_res:
                    parent_customer_id = int(parent_customers_res[0])
                else:
                    has_updated = True
                    insert_sql = text("""
                        INSERT INTO credit_parent_customers (customer_name, created_at) 
                        VALUES (:customer_name, :created_at) RETURNING id
                    """)
                    res = session.execute(insert_sql, {
                        'customer_name': parent_customer,
                        'created_at': datetime.now()
                    })
                    parent_customer_id = res.scalar()

                keywords_query = text("""
                    SELECT id, parent_customer_id, keyword, source 
                    FROM credit_subsidiary_keywords
                    WHERE parent_customer_id = :parent_customer_id AND source = :source
                """)
                result_proxy = session.execute(keywords_query, {'parent_customer_id': parent_customer_id, 'source': source})
                Keywords = namedtuple('Keywords', result_proxy.keys())
                keywords_rows = [Keywords(*row) for row in result_proxy.fetchall()]
                current_keywords = {row.keyword for row in keywords_rows}

                if not subsidiaries:
                    has_updated = True
                    delete_query = text("""
                        DELETE FROM credit_subsidiary_keywords 
                        WHERE parent_customer_id = :parent_customer_id 
                            AND source = :source
                    """)
                    session.execute(delete_query, {
                        'parent_customer_id': parent_customer_id,
                        'source': source
                    })
                else:
                    incoming_keywords = set(subsidiaries)
                    missing_keywords = incoming_keywords - current_keywords
                    extra_keywords = current_keywords - incoming_keywords
                    connection_string = os.getenv('CREDIT_AZURE_STORAGE_CONNECTION_STRING')
                    queue_name = os.getenv('CREDIT_NEWS_REASSESS_QUEUE')
                    queue_client = QueueClient.from_connection_string(connection_string, queue_name)

                    if missing_keywords:
                        has_updated = True
                        news_keywords = []
                        insert_keyword = text("""
                            INSERT INTO credit_subsidiary_keywords (parent_customer_id, keyword, source, created_at, last_sync_date, last_sync_year)
                            VALUES (:parent_customer_id, :keyword, :source, :created_at, :last_sync_date, :last_sync_year) RETURNING id
                        """)
                        for kw in missing_keywords:
                            res = session.execute(insert_keyword, {
                                'parent_customer_id': parent_customer_id,
                                'keyword': kw,
                                'source': source,
                                'created_at': datetime.now(),
                                'last_sync_date': '',
                                'last_sync_year': 0
                            })
                            news_keywords.append({
                                'id': res.scalar(),
                                'parent_customer_id': parent_customer_id,
                                'keyword': kw
                            })
                        if news_keywords:
                            for msg in news_keywords:
                                message_content = json.dumps(msg)
                                queue_client.send_message(message_content)

                    if extra_keywords:
                        has_updated = True
                        delete_query = text("""
                            DELETE FROM credit_subsidiary_keywords 
                            WHERE parent_customer_id = :parent_customer_id 
                                AND keyword IN :keywords 
                                AND source = :source
                        """).bindparams(bindparam("keywords", expanding=True))

                        session.execute(delete_query, {
                            'parent_customer_id': parent_customer_id,
                            'keywords': list(extra_keywords),
                            'source': source
                        })

                if has_updated:
                    session.commit()

        except Exception as e:
            parent_customer_id = 0
            print(traceback.print_exc(e))

        return parent_customer_id, has_updated

    def get_subsidiaries(self, parent_customer):
        data = {"subsidaries": [], "manual_subsidaries": []}
        if not parent_customer:
            return data
        try:
            with get_db() as session:
                query = text(
                    "SELECT id,customer_name FROM credit_parent_customers WHERE customer_name = :parent_customer")
                res = session.execute(query, {'parent_customer': parent_customer}).fetchone()
                if res:
                    parent_customer_id = res[0]
                    query = text(
                        "SELECT keyword,source FROM credit_subsidiary_keywords WHERE parent_customer_id = :parent_customer_id")
                    result = session.execute(query, {'parent_customer_id': parent_customer_id})
                    for row in result.fetchall():
                        keyword, source = row
                        if source == "excel":
                            data["subsidaries"].append(keyword)
                        elif source == "manual":
                            data["manual_subsidaries"].append(keyword)
        except Exception as e:
            print(traceback.print_exc(e))

        return data

    def get_subsidiaries_by_parent_id(self, parent_id):
        data = []
        if not parent_id:
            return data

        try:
            with get_db() as session:
                query = text(
                    "SELECT id,customer_name FROM credit_parent_customers WHERE id = :parent_id")
                res = session.execute(query, {'parent_id': parent_id}).fetchone()
                if res:
                    parent_customer_id = res[0]
                    query = text(
                        "SELECT keyword,source,created_at FROM credit_subsidiary_keywords WHERE parent_customer_id = :parent_customer_id")
                    result = session.execute(query, {'parent_customer_id': parent_id})
                    for row in result.fetchall():
                        keyword, source, created_at = row
                        data.append({
                            'keyword': keyword,
                            'source': source,
                            'created_at': created_at
                        })

        except Exception as e:
            print(traceback.print_exc(e))

        return data

