class AccessManager:

    def check_role_access(self):
        azure_auth = AzureAuthenticator()
        path = request.path

        if any(path.startswith(p) for p in NO_LOGIN_REQUIRED_PATHS):
            return None

        if not azure_auth.is_login():
            if request.path.startswith('/api/'):
                return jsonify(code=401, msg='Your session has expired. Please refresh the page.', data={})
            else:
                return redirect('/.auth/login/aad?post_login_redirect_url=/')

        if not azure_auth.is_whitelisted():
            return jsonify(code=403, msg='Permission denied', data={})

        if path in ['/', '/logout']:
            return None

        role = session.get("role", "guest")
        role_id = session.get("role_id")

        if role in ['admin', 'credit']:
            return None

        allowed_routes = session.get('allowed_routes')
        if allowed_routes is None:
            allowed_routes = get_allowed_routes_for_role(role_id)
            session['allowed_routes'] = allowed_routes

        if not allowed_routes or not any(path.startswith(p) for p in allowed_routes):
            return jsonify(code=403, msg='Permission denied', data={})

        return None

