def upload_to_azure_blob(file, mime_type, container_name, blob_name):
    try:
        connection_string = os.getenv('CREDIT_AZURE_STORAGE_CONNECTION_STRING')

        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        container_client = blob_service_client.get_container_client(container_name)
        try:
            container_client.get_container_properties()
        except Exception as e:
            if hasattr(e, 'message') and 'ContainerNotFound' in e.message:
                container_client.create_container()

        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)
        if isinstance(file, str) and os.path.isfile(file):
            with open(file, "rb") as data:
                blob_client.upload_blob(data, content_settings=ContentSettings(content_type=mime_type), overwrite=True)
        elif hasattr(file, 'read'):
            file.seek(0)
            blob_client.upload_blob(file, content_settings=ContentSettings(content_type=mime_type), overwrite=True)
        else:
            print("Invalid file type provided. Must be a file path or file object.")
            return None
    except Exception as e:
        print(f"Error uploading to Azure Blob: {str(e)}")
        return None

    return blob_client.url

