def get_db(retries=3, delay=1):
    attempt = 0

    while attempt < retries:
        db = None
        try:
            db = SessionLocal()
            yield db
        except OperationalError as e:
            attempt += 1
            print(f"OperationalError occurred: {str(e)}. Retrying {attempt}/{retries}...")
            if db:
                db.close()
            sleep(delay)
            if attempt >= retries:
                print("Max retries reached. Could not establish database connection.")
                break
        except Exception as e:
            print(f"An error occurred while connecting to the database: {str(e)}")
            if db:
                db.close()
            break
        else:
            if db:
                db.close()
            break

