def has_financial_scores(risk_rating, factsheet=None):
    invalid_values = {'-', '#VALUE!', '0', '0.0', 'NA', None}
    financial_scores = risk_rating.get('financial_scores', {}) if isinstance(risk_rating, dict) else {}
    values = [
        financial_scores.get('revenue_size', {}).get('value'),
        financial_scores.get('gross_debt', {}).get('value'),
        financial_scores.get('net_profit', {}).get('value'),
        financial_scores.get('total_networth', {}).get('value'),
    ]
    return 0 if all(str(v) in invalid_values for v in values) else 1

