def is_factsheet_outdated(factsheet):
    if factsheet and isinstance(factsheet, dict):
        period_dates = factsheet.get('annual', {}).get('period', [])
        if period_dates:
            try:
                current_year = datetime.now().year
                for date_str in period_dates:
                    date_obj = datetime.strptime(date_str, "%d-%b-%y")
                    year = date_obj.year if date_obj.year > 1900 else date_obj.year + 2000
                    if year >= current_year - 5:
                        return False
                return True
            except Exception:
                return False
    return False

