class UiPathHelper:

    def __init__(self):
        self.access_token = self.get_uipath_token()

    def get_uipath_token(self):
        url = 'https://cloud.uipath.com/identity_/connect/token'
        headers = {'Content-Type': 'application/x-www-form-urlencoded'}
        data = {
            'grant_type': 'client_credentials',
            'client_id': os.getenv('UIPATH_APPID'),
            'client_secret': os.getenv('UIPATH_APP_SECRET'),
            'scope': 'OR.Administration OR.Execution OR.Folders OR.Jobs OR.Machines OR.Robots OR.Users'
        }
        try:
            response = requests.post(url, headers=headers, timeout=10, data=data)
            response.raise_for_status()
            response_json = response.json()
            access_token = response_json.get('access_token', None)
            return access_token
        except Exception as e:
            traceback.print_exc()
            return None

    def get_robot_id(self):
        robot_name = os.getenv('UIPATH_ROBOT_NAME')
        url = f"https://cloud.uipath.com/lifungonetech/CreditAI_Tenant/orchestrator_/odata/Users?$filter=Name eq '{robot_name}'"
        headers = {
            'Authorization': 'Bearer ' + self.access_token
        }

        response = requests.get(url, timeout=10, headers=headers)
        response_json = response.json()
        value_list = response_json.get('value', [])
        if value_list:
            unattended_robot = value_list[0].get('UnattendedRobot', {})
            robot_id = unattended_robot.get('RobotId', None)
        else:
            robot_id = None
        return robot_id

    def get_machine_id(self):
        machine_name = os.getenv('UIPATH_MACHINE_NAME')
        machine_name = machine_name.lower()
        url = f"https://cloud.uipath.com/lifungonetech/CreditAI_Tenant/orchestrator_/odata/Machines?%24filter=name%20eq%20%27{machine_name}%27"
        headers = {
            'Authorization': 'Bearer ' + self.access_token
        }

        response = requests.get(url, timeout=10, headers=headers)
        response_json = response.json()
        value_list = response_json.get('value', [])
        if value_list:
            machine_id = value_list[0].get('Id', None)
        else:
            machine_id = None
        return machine_id

    def get_machine_session_id(self, machine_id):
        machine_name = os.getenv('UIPATH_MACHINE_NAME')
        url = f"https://cloud.uipath.com/lifungonetech/CreditAI_Tenant/orchestrator_/odata/sessions/UiPath.Server.Configuration.OData.GetMachineSessions(key={machine_id})?%24filter=HostMachineName%20eq%20%27{machine_name}%27".format(machine_id=machine_id, machine_name=machine_name)
        headers = {
            'Authorization': 'Bearer ' + self.access_token
        }
        response = requests.get(url, timeout=10, headers=headers)
        response_json = response.json()
        value_list = response_json.get('value', [])
        if value_list:
            machine_id = value_list[0].get('Id', None)
        else:
            machine_id = None
        return machine_id

    def get_release_id(self, market_type, location_type):
        if market_type == 'potential':
            url = 'https://cloud.uipath.com/lifungonetech/CreditAI_Tenant/orchestrator_/odata/Releases?%24filter=Name%20eq%20%27LF_PotentialExposureComputation%27'
        else:
            if location_type == 'onshore':
                url = 'https://cloud.uipath.com/lifungonetech/CreditAI_Tenant/orchestrator_/odata/Releases?%24filter=Name%20eq%20%27LF_ExposureComputation_OnShore%27'
            else:
                url = 'https://cloud.uipath.com/lifungonetech/CreditAI_Tenant/orchestrator_/odata/Releases?%24filter=Name%20eq%20%27LF_ExposureComputation%27'
        headers = {
            'Authorization': 'Bearer ' + self.access_token,
            'X-UIPATH-OrganizationUnitId': os.getenv('UIPATH_OrganizationUnitId')
        }
        response = requests.get(url, timeout=10, headers=headers)
        response_json = response.json()
        value_list = response_json.get('value', [])
        if value_list:
            release_id = value_list[0].get('Key', None)
        else:
            release_id = None
        return release_id

    def get_robot_info(self, market_type, location_type):
        futures = []
        results = {}
        machine_session_id = 0
        with ThreadPoolExecutor(max_workers=3) as executor:
            futures.append(('robot_id', executor.submit(self.get_robot_id)))
            futures.append(('machine_id', executor.submit(self.get_machine_id)))
            futures.append(('release_id', executor.submit(lambda: self.get_release_id(market_type, location_type))))

        for identifier, future in futures:
            try:
                result = future.result()
                results[identifier] = result
            except Exception as e:
                print(traceback.print_exc())
                results[identifier] = None
        if results['machine_id']:
            machine_session_id = self.get_machine_session_id(results['machine_id'])

        return results['robot_id'], results['release_id'], machine_session_id

    def start_jobs(self, req_data):
        if not self.access_token:
            print("[start_jobs] No access token available.")
            return False
        if 'location_type' not in req_data:
            req_data['location_type'] = 'offshore'

        robot_id, release_id, machine_session_id = self.get_robot_info(req_data['market_type'], req_data['location_type'])
        if not robot_id or not release_id or not machine_session_id or not req_data:
            print(f"[start_jobs] Missing robot info: robot_id={robot_id}, release_id={release_id}, machine_session_id={machine_session_id}")
            return False

        start_info = {
            "ReleaseKey": None,
            "RobotIds": [],
            "MachineSessionIds": [],
            "JobsCount": 1,
            "JobPriority": "Normal",
            "Strategy": "ModernJobsCount",
            "InputArguments": json.dumps(req_data)
        }

        start_info["RobotIds"].append(robot_id)
        start_info["MachineSessionIds"].append(machine_session_id)
        start_info["ReleaseKey"] = release_id
        url = "https://cloud.uipath.com/lifungonetech/CreditAI_Tenant/orchestrator_/odata/Jobs/UiPath.Server.Configuration.OData.StartJobs"
        headers = {
            'X-UIPATH-OrganizationUnitId': os.getenv('UIPATH_OrganizationUnitId'),
            'Authorization': 'Bearer {token}'.format(token=self.access_token),
            'Content-Type': 'application/json'
        }
        data = {
            "startInfo": start_info
        }
        try:
            response = requests.post(url, timeout=10, headers=headers, data=json.dumps(data))
            response.raise_for_status()
        except requests.exceptions.RequestException as e:
            print(f"[start_jobs] Request failed: {e}")
            return False
        return True
